-- Row 1: EFP1
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Nelson Mandela University', 'Magda Minguzzi', 'magda.minguzzi@mandela.ac.za', 'Investigation on First Nation built environment and dwellings in the Eastern Cape, South Africa',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Bavianskloof Valley', 'South Africa',
    NULL, NULL,
    'With this ongoing community-led project, the working group (First Indigenous Peoples-Nelson Mandela University staff and students) is documenting, studying, and moving awareness of the First Indigenous Peoples of South Africa’s settlements and dwellings (self-built with local materials) located in a remote area of the Eastern Cape, and never studied before. A unique example of a regenerative approach to the built environment where the Indigenous building knowledge, typology, technique and materials (Indigenous Knowledge System) have been handed down from generation to generation, from pre-colonial times till the present, orally, despite the long history of repression and segregation, the Indigenous Peoples went through since the arrival of the settler colonialists. The working group was formed in 2015, under the umbrella of the Nelson Mandela University School of Architecture, and led by Dr Magda Minguzzi. Since then, their focus is on community engagement projects, based on practice research, that involve teaching, learning and research.', 'In the current environmental-socio-economic crisis that we are facing, globally, these First Nations dwellings under study and the IKS applied to represent a unique example of equal opportunity to housing, which empowers people (self-building), improves their living conditions and creates food security lifestyle. It is urgent to open a global to re-activate our forgotten indigenous knowledge, rooted in a regenerative approach to the built environment and resources. Trailer of a documentary: https://vimeo.com/812088198?activityReferer=1', 'This community engagement project (Nelson Mandela University-First Nations of South Africa) promotes inclusivity, social cohesion and equity. The village under study is a remarkable example of equal opportunity to housing (the land is owned by the community), which empowers people (self-building), uses a sustainable model (materials used are self-collected in the area) improves people''s living conditions and creates food security lifestyle (each house has a vegetable garden). It’s an example that can be used in other similar climate contexts to alleviate poverty and promote a regenerative approach to the environment.',
    TRUE,
    'EFP1', 'Dr Magda Minguzzi (NMU), Gaob/Chief Margaret Coetzee, in collaboration with Arch Lucy Vosloo (NMU)', NULL, NULL
);

