-- Row 5: LDP3
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'EMARA Architecture and Urbanism', 'Shiekh Intekhab Alam', 'emaraarchitects@gmail.com', 'ASHRAY REC Foundation Old Age Home',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'LEH', 'INDIA',
    NULL, NULL,
    'A community village for the elderly with Shelter Services – Modular, comprehensive & elder-friendly, also envisaged as a Wellness, Geriatric health care center, and day-care center, designed keeping in mind the vulnerability of the cold desert region as well the comfort of the people, especially during winters.', 'The special feature of the project is its use of indigenous technique of construction, the project takes help from local craftsmanship and wisdom not only at the building level but also at the Masterplan level, the site as a resultant is a secure habitat for old age people, the building designed by ‘rammed earth’ mixed with concrete balancing strength with insulation keeping in mind the low temperature & harsh winters of the cold desert region. Solarised walls, especially for bathrooms (“Tombe” walls), which have specially insulated & south facing walls for sunshine which prevents the freezing of water from the tank to the pipe outlet. The landscape allows for a certain kind of local feel to the built environment.', 'Old age home at shey, Ladakh is envisaged as a small village for old age people who either have been abandoned by their own family or have no one to take care, the land for the site was donated by the local politician after the 2014 flash flood in Ladakh. Sustainability here is not a choice but a way of life, the learnings from traditional wisdom and local craftsmen has helped make the project an all year habitable space. The temperature at site varies from +30 Degree to -30 Degree, the design hence is a affordable, low maintenance, energy efficient model for the entire region. It promotes well being for elderly but also provides wisdom to the young.',
    TRUE,
    'LDP3', 'Shiekh Intekhab Alam (Architect), Nazir Din (Engineer), Amrita Kaur Slatch', NULL, NULL
);

