    external_code, authors, size_sqm, year_completed
) VALUES (
    'UNISINOS - Universidade do Vale do Rio dos Sinos', 'Ana Carolina Borile', 'anacarolina_borile@outlook.com', 'Agroecological Pavilion - Urban agriculture as an agent of socio-environmental transformation',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Porto Alegre/ Brazil', 'Unknown',
    NULL, NULL,
    'The agroecological pavilion can be a solution to various problems in cities: it mitigates malnutrition, saves natural resources, generates employment and income, promotes health, and reduces the impact on soil.', 'In a context of scarcity of natural resources, climate change, and a society heavily hit by food insecurity, broadening access and supply of food with less environmental impact and seeking to reduce waste should be priorities. The pavilion combines the uses of conscious and sustainable urban agricultural production, the commercialization of low-cost food, and uses aimed at education and professionalization in an equipment line on the premises of sustainable architecture, open to the community.', 'Urban agriculture emerges as a possible solution that answers interrelated issues in urban systems, such as waste management, health, land use, reducing distances between production and consumption, the use of loose spaces in the city, combating food insecurity, and the generation of occupational activity with consequent income generation. In addition, it is able to directly intervene in the adaptation of cities to climate change and sanitary crises, such as the current COVID-19 pandemic.',
    TRUE,
    'IFF15', 'Ana Carolina Borile', NULL, NULL
);

-- Row 8: IFF4
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
