    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'até arquitetura', 'Henrique Rodrigues Freires de Lima', 'contato.atearquitetura@gmail.com', 'An Urban Farm: Architecture and Scarcity',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo', 'Brasil',
    NULL, NULL,
    'The project is made up of a network of semi-autonomous units in a steel structure, focused on work, education, research, commerce and culture. The set was designed to be replicated in a scalable way.', '"An Urban Farm: Architecture and Scarcity" portrays a problem that had already been resolved and which has abruptly reappeared in the periphery of Brasil: hunger. From the perspective of a marginalized region of São Paulo, hunger is treated as a form of scarcity, social insecurity and a portrait of a period marked by a pandemic that intensified latent inequalities in the global south. In this way, the work proposes multipurpose structures in an unused floodplain area aimed at Jardim Piratininga.', '"An Urban Farm: Architecture and Scarcity" seeks to strengthen the local community, support economic growth and ensure effective social assistance, in the form of a self-sustainable, inclusive and replicable management model. In addition, it seeks to provide the necessary tools to face hunger and poverty in the peripheries of Brasil through the community''s own means of production, aimed at the community and the city as a whole.',
    TRUE,
    'IFF4', 'Henrique Rodrigues Freires de Lima', NULL, NULL
);

