) VALUES (
    'Department of Visual Studies, University of Karachi', 'Kanzul Fatima', 'wajiha.siddiqui@uok.edu.pk', 'Sustainable Growth for Fishermen Communities: Architecture for Environment',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Karachi', 'Pakistan',
    NULL, NULL,
    'The project aims to create sustainable and uplifting solutions for the fishing community by enabling architecture to exist in harmony with nature. It seeks to understand design methods that can achieve this goal.', 'A design program is divided into three parts, including work units for fishermen, a mangrove nursery for researchers, and connecting bridges and ramps for exploration. The design features convertible walls and roofs that allow for adaptable space and the potential to form clusters. The architecture is versatile and can be disassembled and relocated to other sites to restore ecosystems. After 40-50 years, the design anticipates the bridge becoming a natural pathway for eco-tourism.', 'The materials and design strategies used in a project highlight project''s sustainable qualities. The materials were carefully chosen to include bamboo, waste boat wood, plastic, and water drums, all of which contribute to sustainable development and recycling waste. The use of these materials reflects a conscious effort to create an environmentally friendly and socially responsible project.',
    TRUE,
    'IFF44', 'Kanzul Fatima and Wajiha Siddiqui', NULL, NULL
);

