-- Row 11: LDP25
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Localworks', 'Angela Nkurunziza', 'angela@localworks.ug', 'AWF Primary Schools in Karamoja',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Karamoja', 'Uganda',
    NULL, NULL,
    'Two primary schools on an area of 2000 sqm located in immediate adjacency to Kidepo Valley National Park in Karamoja/ North-eastern Uganda. One school built in the park buffer zone and another in a farming village nearby, both with the ambition to multiply their influence among each of their 750 school children, their immediate families, and their surrounding communities.

In total, 21 buildings across 2 schools, each with 9 classrooms reinforce the vision of AWF to integrate stunning landscapes within the schools, create beautiful that are friendly to the environment on which they are placed and elevate the perceptions of indigenous materials.', 'Due to the remoteness of the sites and the associated high transport costs, building materials were carefully selected to be sourced locally and built with local labour wherever possible. The Kidepo area has beautiful local stone which was utilised for near-carbon-neutral foundations and plinth walls. The stones were gathered by the locals within a 3km radius of the site and arranged in semi-dry-stack formations creating a water-mitigating substructure. Walling utilises fair-faced, manually compressed stabilized soil blocks (CEBs) formed on site, a material that presents a much more ecological alternative to the commonly used “village brick” which is a main cause of deforestation in Uganda. 
The steel roof trusses were designed using very thin steel profiles, of the size more commonly used for windows and doors; the idea was to optimise the design so much that the entire primary roof structure of two schools would fit into a single truck. The idea was not only to minimise transport costs but also to reduce the weight of each truss to such an extent that they can be hoisted in place by muscle power. Sliding and top-hung steel louvre panels form windows and doors, multicoloured as inspired by the local jewelry design, provide a sturdy, maintenance-efficient response to shading and security requirements.', 'Special care was given to the landscape design which was seen as the key to fostering a better relationship between people and nature. Existing trees and shrubs were protected to an extraordinary extent, local species added and innovative forms of appropriate agriculture introduced in the form of demonstration farms and gardens. While the school in Geremech was designed in the image of a ‘savannah school’, the Sarachom school reflects its location within an agricultural zone in the structure of a demonstration garden.
In total, 21 buildings across two schools, each with nine classrooms reinforce the vision of AWF to integrate stunning landscapes within the school that are friendly to the environment on which they are placed and elevate preexisting perceptions of indigenous materials. Each building is completely dependent on passive ventilation to achieve indoor thermal comfort. A combination of thermal mass and building orientation used to minimise direct ingress of sun has proven to be an effective passive strategy to avoid overheating without deploying high-tech energy intensive equipment. Appropriate technologies include a semi-centralised rainwater harvesting, solar power, fuel-efficient wood stoves and ''aquaprivy'' toilets.',
    TRUE,
    'LDP25', 'Allan Semakula, Arthur Baleeta, Charles Ssegirinya, Deborah Tusiime, Edson Agume, Emma Mugisha, Felix Holland, Jeroen Van Roie, Juliana Achi, Philip Matovu, Robert Mugisha, Sandra Mudondo, Valerie Rubombora', NULL, NULL
);

-- Row 12: LDP52
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'China Architecture Design&Research Group', 'Kang Kai', '329579671@qq.com', 'The main exhibition hall of Tianfu Agricultural Expo Park',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Chengdu，China', 'Unknown',
    NULL, NULL,
    'The Tianfu Agricultural Expo Park project is located in Xingyi Town, Xinjin County and Sanjiang Town, Chongzhou City, close to Chengxinpu Expressway and Chengdu Second Ring Expressway, with good landscape and traffic conditions. The main exhibition hall is located in the agriculture exhibition area, north of Chengxin Pu Expressway and west of the Yangma River, with a land area of about 135,000 square meters. It includes the functions of agricultural exhibition hall, conference center, Tianfu Agricultural Civilization Museum, cultural and creative incubation, characteristic commercial neighborhood, outdoor exhibition space and other functions, with a total construction area of about 132,000 square meters. The project uses five arched scaffolding to interpenetrate with the surrounding pastoral landscape, and adopts prefabricated steel and wood structure scaffolding combined with colorful ETFE enclosure system to create a semi-outdoor non-energy consumption space, embodies the concept of green development and environmentally friendly design.', 'Ecological energy-saving. 
The plan adopts a finger-shaped penetration layout pattern, which is mutually infiltrated with the pastoral landscape. At the same time, in order to reflect the characteristics of the agricultural expo exhibition and take into account the basic needs of wind and rain shelter, it mainly adopts the form of an outdoor exhibition venue with a roof. Through appropriate passive green building technology, the organization of air flow is guided to create a comfortable semi-outdoor activity space. The exhibition part has achieved the goal of near-zero energy consumption, truly realizing the green ecological concept that is in line with the agricultural expo. The design of the building opening effectively organizes the air flow to form a ventilation corridor, so that the indoor temperature can be kept in a more comfortable state for a long time. The microclimate environment of human activities has been greatly improved. In addition, fog spraying additional measures are used at a close range to regulate the micro-environment.
Wooden frame. 
The architectural form is a large-span structure, combined with the fact that the project is located in farmland, abandoning the reinforced concrete structure form that causes greater damage to farmland during construction and is not renewable. Laminated wood structure is a negative carbon material that can be carbon-fixed. It can better reflect ecological and agricultural characteristics and is all factory-processed. On-site assembly reduces construction errors and ensures completion quality. At the same time, wooden structures originate from nature, with simple colors and in line with agricultural expo characteristics.
Colorful film. 
ETFE film material is light in weight, good in light transmission, easy to color, and can be matched with colorful fields through colorful textures to better reflect agricultural expo concepts.
Implanted nature.
 In order to introduce landscape into the arch shed and create an outdoor pastoral feeling indoors, at the boundary, while the building extends into the field, it also extends the external landscape environment into the arch shed to blur and weaken the boundary between architecture and nature and increase opportunities for all-weather contact with nature.', 'The SDGs are 17 global development goals formulated by the United Nations. These goals will last from 2016 to 2030. The main purpose of these goals is to eliminate poverty, protect the earth and ensure human well-being worldwide. There are extensive interrelationships between the SDGs, and the achievement of one goal may have positive promotion or negative effects on other goals.
In the 17 global development goals formulated by the United Nations, SDGs2 and SDGs4 have been fully reflected and responded to in the Tianfu Agricultural Expo Park project. The green, open, energy-saving and environmentally friendly architectural landscape design concept provides a solid foundation for the development of sustainable agriculture and provides effective technical models for the construction of agricultural-related infrastructure. The farmland is fertile and vast, and the colorful film arch shed of the main exhibition hall blends with the bright yellow of rapeseed flowers, the oil green of rice seedlings, the golden orange of wheat ears and the deep brown of fertile soil to present seasonal changes. On the west side of the five arch sheds is a demonstration field for scientific agriculture. Farmers spontaneously integrate farmland together, optimize field ridges lines, plant new varieties of crops, and introduce intelligent irrigation equipment to achieve full-cycle automatic monitoring, batching and planting. High-quality agricultural development provides technical support and feasible solutions for eliminating hunger worldwide and achieving food security.
At the same time, the main exhibition hall of Tianfu Agricultural Expo Park also undertakes important responsibilities for education and scientific research. High-end agricultural research projects and science popularization education exhibitions for students and citizens are all rooted in the park. The construction of the main exhibition hall has become an important platform for citizens to understand modern agriculture and demonstrate sustainable agricultural development. It has great social significance in improving relevant education levels.',
    TRUE,
    'LDP52', 'Cui Kai, Kang Kai', 130000.0, NULL
);

-- Row 13: IFF12
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Univeridad del Bio-Bio, Concepción, Chile', 'Beatriz Piderit', 'mpiderit@ubiobio.cl', 'Future Edu Space(FES) Prototype',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Concepción, Region del Bio-Bio', 'Chile',
    NULL, NULL,
    'The Future Edu Space (FES) classroom has been envisaged to promote and inspire the creation of creative, sustainable, and comfortable educational spaces. It has been designed to transform learning experiences, considering many Chilean schools in the Bio-Bío region have deficient infrastructure that critically affects the student community. 

FES used an interdisciplinary approach, linking areas as diverse as architecture, design, education, and engineering. Public and private entities contributed to specific solutions, with the region’s key actors involved In a highly participative process. Teachers, principals, and school boards took part, giving their vision for future classrooms. Psychologists, educators, and specialists in pedagogical innovation provided guidelines about how the space had to foster 21st-century skills. The resulting space acts as a mediator between teaching practices and student learning, with the potential to develop creative and innovative skills while stimulating active participation, interaction, and communication. 

This prototype has a demonstrational role for the region’s architecture and design offices, wood companies, and builders about schools and technology transfer. It is a result of the project, “Future Edu Space: Generation of Technological Capacities to Build State-of-the-art Sustainable Educational Space from the Biobío Region”, an initiative financed by the Bio-Bío Regional Government’s Innovation for Competitivity Fund (FIC-R).', 'The Future Edu Space (FES) prototype is an educational space that combines flexibility, adaptability, and variety in its use. Its design was developed based on interdisciplinary and collaborative work involving actors from education, design, architecture, construction, and wood industrialization. The BIM method was used throughout the design process, combined with virtual reality tools.

To break with the traditional classroom layout, it has been designed using a square neutral-style floor plan, which allows using the classroom in different senses and creating multiple educational scenarios. It has a total surface area of 100m2, with a central area of 70m2 for 35 students.

Its structure comprises two active sidewalls to support the pedagogical activities. One holds furniture for individual learning activities, and the other, which can also store furniture, has a large interactive board. It also has an acoustic wall that folds inward to extend activities to an adjoining space. The final wall is glazed, connecting with the outside to take pedagogical activities further still.
Passive strategies are included to generate appropriate environmental conditions: temperature (thermal envelope), air quality (crossed ventilation), acoustics (foldable acoustic doors and partition), and daylight (lucarnes and view windows).

It considers the design of flexible furniture to provide an easily adjusted multipurpose learning space. For example, changing from a presentation space to one for participation or group work.

FES is designed with a wooden prefabricated system, to foster wood-based architecture in the education area. The geometry is obtained from a construction technology capacity and modulation process. A 1.2m x 3m CLT (Cross Laminated Timber) module, which is easy to transport and meets the requirements of the architectural space, is used for the sidewalls using the manufacturing skills of local wood companies.

The educational space’s structure comprises CLT frames that form part of the active sidewalls, with GLT (Glued Laminated Timber) beams for the ceiling’s caisson structure. CLT wall braces are placed between the frames. The walls do not have an indoor coating, leaving the same CLT pine wall. The outdoor covering is a thermally modified tongue and groove.

The FES prototype is conceived as a unitary system that can be repeated and joined together to generate new options. Three variants are proposed: EDU SPACE FRONT, EDU SPACE NEXT, and EDU SPACE UP. These are organized by two main elements: the essential indoor space module, and an independent ring surrounding it, forming an intermediate space. The prototype and its variants inspire projecting and building new ways of developing school architecture.', 'This initiative is aligned with the following goals: 
GOAL 3 GOOD HEALTH AND WELL-BEING: “Ensure healthy lives and promote well-being for all at all ages”. 
The FES prototype considers a biophilic design since its incorporation in educational spaces has been emphasized in recent studies, especially after the pandemic, to promote children’s health and well-being. For this reason, it integrates a visual connection with the outside through glazed walls to see the sky and nature. It fosters sensorial stimuli, using a wooden covering with its warmth, texture, and insulation capacities. Thanks to the lucarnes, it generates dynamic lighting that stimulates the Circadian cycle, which is key for the student’s well-being and behavior. All these elements allow restoring the positive experience of nature in built spaces, to attain better psychological and social well-being for our children.

GOAL  4 QUALITY EDUCATION: ”Ensure inclusive and equitable quality education and promote lifelong learning opportunities for all”.
This prototype looks to provide a solution to the specific issues Chilean school infrastructure has. Many public schools are in disrepair, directly impacting the country’s most vulnerable students who are their main users. FES contributes to improving classroom quality, providing a level playing field for learning environments, and eliminating gaps between different socioeconomic groups.
Dilapidated school infrastructure has repercussions on deficient environmental comfort, and thereby, student well-being. FES guarantees the conditions for a healthy environment and provides quality infrastructure, along with access to an integrative education. It allows creating better conditions for innovative teaching practices that are supported by the classroom’s spatial setting.
The proposal gives the local Bio-Bio population, educators, designers, wood construction companies, and architects, a demonstration space that combines innovative solutions.

GOAL  9 INDUSTRIES, INNOVATION, and INFRASTRUCTURE: “Build resilient infrastructure, promote inclusive and sustainable industrialization, and foster innovation”. 
FES encourages innovation and the transfer of state-of-the-art models for school infrastructure, as it is linked with the construction industry through innovative construction systems. Modular prefabricated architecture has been evolving in its efficiency and sustainability, permitting a quick, adaptable, light, and quality construction process.
FES is projected as a solid wood construction system and promotes wood-based architecture in the education area, looking to drive innovation among the wood companies of the Bio-Bío region, where the project is based. CLT construction systems allow prefabricating several-story buildings using horizontal and vertical structuring modules. The design’s geometry was projected using the technological construction skills requirements of local wood companies, aligned with the search for innovation in the educational setting.',
    TRUE,
    'IFF12', 'Beatriz Piderit (FES Project Director), Maureen Trebilcock (FES Project Coordinator), Alejandra Bancalari (Design Architect), Valentina Chandia (Design Architect), Carlos Coronado (Design Architect), Javiera Leighton  (editor)', NULL, NULL
);

