    'steidle architekten', 'Johannes Ernst', 'ernst@steidle-architekten.de', 'Werksviertel Mitte',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Munich', 'Germany',
    NULL, NULL,
    'Development of an former industrial area into an independent quarter for living, working, social and cultural use with open public spaces for events and entertainments.', 'The Werksviertel understands the vitality and complexity of the existing development and uses the positive potential for the emergence of the new quarter. The existing activities are to be gradually cultivated, consolidated and updated, while new developments are initiated at the same time. Urban diversity, spatial events and programmatic innovation are the focus of the design work, which is joint by several european architecture studios.', 'The Werksviertel is based on economic sustainability through inventory management and the settlement of a highly differentiated range of tenants. This creates a high degree of diversity, which is particularly reflected in a lively and used public space. The careful addition of previously non-existent uses such as hotel/hostel, retail, fitness, offices and, at the end, apartments, generates a wide range of offers for most urban demands and, overall, a differentiated macroeconomic composition.',
    TRUE,
    'LDP1', 'Johannes Ernst', NULL, NULL
);

-- Row 15: LDP12
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'The Architectural Society of China', 'Yehao Song', 'sup_atelier@supatelier.com', 'Yunzhai Community Center',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Changyuan, Hunan Province', 'China',
    NULL, NULL,
    'With integrated design of both interior and exterior spaces, a “multi-dimensional Chinese garden” has been formed. For locals, it’s an auditorium for celebrations, films and lectures, as well as a leisure space for seniors and children. For visitors, it’s a tourist center for tourist reception, services and cultural activities.', 'With relatively small site area and building area, as well as a limited budget, the project aims to make much difference with little intervention. A series of design approaches have offered diverse options for villagers’ activities, including the ground-level courtyard, the roof terrace and interior areas. To save operation and maintenance cost, the community center’s management is both time-dependent and zone-dependent. People of all ages from surrounding villages can come here at any time of the day for recreation or gathering, rediscovering the village’s long-lost vitality.', 'Time & zone-oriented management facilitates the 24-7 operation of the community center
    To weaken the sense of full enclosure of traditional courtyard system, various openings are planned on the walls to make the boundaries permeable rather than closed and solid. The boundaries, with their original function of enclosure preserved, provide easy access for people and bring landscape on both sides of the walls together, making the community center highly open and sharable.
The enclosed interior spaces, the exterior courtyards and the roof platform are connected with multi travelling routes and managed separately, so that during periods when interior spaces are closed, visitors can still enjoy the multi-dimensional exterior garden at any time of the day, thus saving operation and maintenance costs while maximizing the utility of available spaces.',
    TRUE,
    'LDP12', 'Yehao Song, Xiaojuan Che, Dan Xie, Jingfen Sun, Yingnan Chu, Tianyu Kuang, Zhihao Huang, Yuyan Xia, Wenbo Yue', 635.0, NULL
);

-- Row 16: LDP21
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SUP Atelier of THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'Village Lounge of Shangcun',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Shangcun Village, Xuancheng city', 'China',
    NULL, NULL,
    'Through invigoration and utilization of the ruined courtyard, the design has presented a roofed space with 6 bamboo umbrellas for local people’s gatherings and leisure activities, doubling as an exhibition hall of local culture and history.', 'Make use of old and local materials
The team encouraged the villagers to collect usable black bricks, black tiles, stones. and timber for construction. 
Open up the space to the public
The walls of the family house have been partially torn down, turning the private courtyard behind the walls into a public joint.
Form a set of "umbrellas” with bamboo and integrate with the nature
The design team picked bamboo as the main material for construction. The bamboo canopies were made to be easily dissembled and upcycled.', '"Village Economic Cooperative" "Migrant Association" "Rice Hoarding Association" were held to implement social protection system.
Those organizations bring the villagers together to boost future development projects, such as operation hostels, the renovation for local homestays, the upgrading of landscape and infrastructure, and the promotion of cultural and tourism programs, which can raise their incomes and share the benefits equally
An open roof could boost natural ventilation. The lounge could serve as a community school for villagers.',
    TRUE,
    'LDP21', 'Yehao Song, Jingfen Sun, Yingnan Chu, Dan Xie, Xiaojuan Chen, Haowei Yu', 150.0, NULL
);

-- Row 17: LDP28
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SJK Architects', 'Sarika Shetty', 'sarika@sjkarchitect.com', 'JSW Sanjeevani Hospital, Aibaugh',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Alibaug', 'India',
    NULL, NULL,
    'JSW Sanjeevani Multispeciality Hospital offers high quality healthcare to a 50-km stretch in rural Raigad area with limited healthcare infrastructure; designed to express compassion, wellness, and beauty to enable physical and psychological well-being.', 'The intervention of JSW Sanjeevani Multispeciality Hospital has changed a previously slag-filled, barren site into a lush, green zone. Landscaped greens on the south facilitate connection with nature. Balconies, terraces, and corridors bring in natural light and air, while common areas offer opportunities for rejuvenation and interaction. A bio-diverse micro-climate promotes healing and calmness which is crucial for patient recovery. Clear planning adjacencies and circulation ensure ease of movement for staff, patients, and families even during times of distress.', 'The JSW Sanjeevani hospital''s strategic location on the Mumbai-Goa highway helps address accidents. This intervention has 100% rainwater harvesting and other eco-friendly features and also uses AAC blocks for better insulation and nearby steel plant slag for plinth filling.The hospital prioritises natural ventilation and wide corridors to reduce airborne disease transmission and incorporates balconies and indigenous vegetation to promote patient engagement and recovery. As an initiative of the JSW Foundation, it offers 13+ specialised consultancies with competitive rates and free services under government schemes, while employing 99% of its staff from a 25-km radius.',
    TRUE,
    'LDP28', 'Shimul Javeri Kadri, Sarika Shetty, Sapna Rohra, Harshini Yohee, Bhavin Patel, Rishit Jain.', NULL, NULL
);

-- Row 18: LDP43
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Architectural Society of China', 'Wei ZHANG', 'zw1998@vip.163.com', 'Kuyangshu Biathlon Center',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Chongli', 'China',
    NULL, NULL,
    'Kuyangshu Biathlon Center is one of the main competition venues in Zhangjiakou Zone of the Beijing 2022 Winter Olympic Games. It is the venue with the largest number of gold medals.', 'Sustainable design with minimum influence on nature and equal quality design for disabled athletes and spectators are the two main concepts. During the games, it will undertake all competitions of the biathlon of the Winter Olympic Games and the biathlon and cross-country ski of the Winter Paralympic Games, setting a total of 11 gold medals of the Winter Olympic Games and 38 gold medals of the Winter Paralympic Games. It will become the training base of the national team after the Games.', 'The venue covers an area of 132ha, with only 8795㎡ permanent building area.Facilities unnecessary after Olympics were built with cabins or tents. Walls in building are flexible and removable. Instead of a big reservoir on the mountain, we created five small lakes among the courses, minimizing the influence on nature. Gravel pavement courses can be changed into mountain bike courses or just melt into nature after the Games. Special design for disabled spectators and athletes are made in the venue.',
    TRUE,
    'LDP43', 'Architect In Charge: Weimin ZHUANG, Wei ZHANG, Hong ZHANG Design Team: Jingxian ZHAO, Jiazhen GONG, Xiangyi LI, Sisi LIANG, Haiyang HUANG, Siyu LEI, Zhonglin GONG, Yuan JIA', NULL, NULL
);

-- Row 19: IFF24
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Vijay Gupta Architects', 'Saurabh Gupta', 'media@vga.co.in', 'Euro School',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Bengaluru and India', 'Unknown',
    NULL, NULL,
    'The design for Euro School, Bannerghatta aims to break the conventional school model with an organic built morphology that weaves in nature with the manmade, fostering a respect for nature among students.', 'The school’s design incorporates the site’s natural topography into its built mass, retaining all existing trees on site. Play areas and outdoor classrooms encourage students to spend more time outdoors – also reflected in the school’s curriculum. The zero-discharge campus employs pragmatic planning to minimally harm the site’s terrain such as using the natural swale to replenish the groundwater table. Employing local/recycled materials in the design also reduces the project’s carbon footprint.', 'A student’s holistic development must foster sustainable values in them from an early age. The school employs strategies to provide outdoor learning opportunities where teaching takes place with and through nature. The school aims to be a model that considers the natural environment and built habitat as mutual entities countering the disconnect between the two in most metropolitan cities. By establishing a connection with the natural site at different levels, the school’s objective is to foster respect for and curiosity towards the natural world.',
    TRUE,
    'IFF24', 'Vijay Gupta, Saurabh Gupta, Akanksha Gupta', NULL, NULL
);

-- Row 20: IFF37
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Instituto de Arquitectos do Brazil (IAB)', 'Ruben Otero Marquez', 'rubenoterom@gmail.com', 'Chácara Flórida',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo', 'Brazil',
    NULL, NULL,
    'The urban project of Chácara Florida has as main objectives the basic sanitation, the depollution of the existing waterways, which serve as a supply of drinking water to the city of São Paulo, and the elimination of serious geological risk. For this, it is planned to create parks around the streams and on the bank of the dam, which today receive sewage directly from the surrounding houses, containments in the risk areas and the construction of small houses to resettle the residents affected by the work.', 'The Chácara Florida reurbanization Project main idea lies in the fact that in Latin America we are daily faced with social injustice. This extends to the point the most needed are forced to move into areas such as riversides, wetlands or risky hills, which are amongst our design area. Throughout a participative process, the design aims to not only be a role model of intervention of vulnerable areas, but also to prove that is possible to overcome poverty in addition to sustainable architecture.', 'Through the urbanization project of Chácara Florida, the sanitation of the more than 3000 families that reside in the place will be carried out, in addition to the depollution of the dam that is part of the drinking water supply system of the city of São Paulo, which suffers from water crises every year. Linked to sanitation, the favela will undergo a major urbanization process with the execution of parks and public facilities, including a market and public garden that will serve as an incentive for sustainable consumption.',
    TRUE,
    'IFF37', 'Responsible architects: Ruben Otero and Monica Drucker. Project team: Elisabete França, Maria Teresa Fedeli, Vanessa Padiá, Mariana Guimarães, Juliana Pedroso, Rodrigo Camara, Nicole Milko, Pedro Flosi Trama, Marise Jacobsen, Matheus Alves, Bruna Bonfim and Angelica Di Febbo.', NULL, NULL
);

-- Row 21: LDP17
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Craft Narrative', 'Yatindra Patil', 'info@craftnarrative.com', 'Vaulted School',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Pune & India', 'Unknown',
    NULL, NULL,
    'Vaulted school the initiative from the founder of Nabhangan foundation & an artist Rajshri Deshpande. Foundation working in the fields of rural regeneration & community building to empower villages to self reliance.
 
Vaulted school is built just minutes away from Dhorkin Tanda, a hamlet in Maharashtra inhabited by sugarcane-cutting labour near Paithan, Aurangabad. The hamlet had one school accommodating a total of 30 students, which was dilapidated.
 
What the old structure lacked, the new structure had it hacked: ample lighting and ventilation achieved with the help of vaulted roofs, stand-alone sanitation facility, a kitchen for mid-day meals, and an overall conducive environment for knowledge to reside in and foster with the ‘play and learn’ ideology.
 
The vaulted school is designed to evoke and satisfy the curiosities children are capable of, and answers them in the most natural way possible: the breeze on their faces that flows because of the Venturi effect, the green buffer zones that cut off the glare, and the importance of planting native flora and fauna in and around the school.
 
The planning provides ample space for one of the most essential needs of a school—the playground, tucked on one side of the site.', 'Vaulted school the initiative from the founder of Nabhangan foundation & an artist Rajshri Deshpande. Foundation working in the fields of rural regeneration & community building to empower villages to self reliance.
 
Vaulted school is built just minutes away from Dhorkin Tanda, a hamlet in Maharashtra inhabited by sugarcane-cutting labour near Paithan, Aurangabad. The hamlet had one school accommodating a total of 30 students, which was dilapidated.
 
What the old structure lacked, the new structure had it hacked: ample lighting and ventilation achieved with the help of vaulted roofs, stand-alone sanitation facility, a kitchen for mid-day meals, and an overall conducive environment for knowledge to reside in and foster with the ‘play and learn’ ideology.
 
The vaulted school is designed to evoke and satisfy the curiosities children are capable of, and answers them in the most natural way possible: the breeze on their faces that flows because of the Venturi effect, the green buffer zones that cut off the glare, and the importance of planting native flora and fauna in and around the school.
 
The planning provides ample space for one of the most essential needs of a school—the playground, tucked on one side of the site.
 
The overall site of 305sq. m. offers a classroom equipped with storage shelves for books and educational toys, a staff room for the teachers, designed with storage units for examination papers and academic journals, and lastly, multi-purpose hall which doubles up as an additional classroom or a dining hall if and when need be.
 
In the foresight, an additional floor can be added by dismantling the vaulted roof temporarily for construction. The same can be assembled as a roof for the next level and the central gutter beam can unfold to extend the slab floor. Even with these changes the dynamics will only be affected positively.
 
All the current spaces are carefully designed in the 102 sq. m. built-up area the premise offers. The classroom’s orientation responds evidently to the breeze pattern and sun path. Considering the soil conditions present, a pile foundation is constructed to strengthen the substructure on which the load-bearing brick walls find their ground. The process is furthered with the vaulted metal sheet roof that minimizes the heavy structural cost and makes the form structurally rigid with minimal support.
 
As one looks deeper into the shape of the structure and the design of the classrooms, the semi-circular volumes serve as noise buffers to the disturbances caused by vehicles passing by on the adjacent side of the road.
 
A free path for ventilation and light is created by the high ceilings, which on the outer side are made up of non-reflective roofing material to reduce heat gain.
 
Each and every wall is painted with pieces of information the child will imbibe even while sitting idly; one of the prominent being a depiction of The Big Dipper on the classroom’s low-height ceilings which is a craft intervention made by inserting an acrylic rod within the slab.
 
Yellow glossy coloured epoxy flooring added additional layer of fun and are painted with mathematical learnings and traditional floor games to utilise the flooring area at its best. Moreover, the playground, just like the classroom, is a product of psychologically backed design thinking, subtly introducing the concept of an amphitheatre to its tiny users. The steps under the overhang double up as seats for when the school is to conduct a recreational activity that requires staging and audience areas. The superstructure revolves around local bricks & traditional pattern as infill materials to bridge the gap between technicalities and rooted aesthetics.', 'A school built minutes away from Dhorkin Tanda, Hamlet, in Maharastra. It is inhabited by sugarcane-cutting labourers in Paithan, Aurangabad. The children had adapted to the fallible condition of their previous school, where they didn''t have proper access to light and ventilation. The school was in the vicinity of an alcohol brewery, which had a  furnace nearby. The school had dingy rooms and unhygienic toilets. Another factor affecting education was parents that expected their children to accompany them for their labour work, which instilled even less desire among children to attend school. The challenge was to design a school where children could feel a safe and fun place with a tight pocket and harsh climatic conditions. 

A school is anticipated to be holistic learning for students, which will help them grow physically, emotionally and socially. Our main ideology was ''play and learn''. The school is a profound design for children to explore their curiosity amidst learning their native environment and craft. The spaces mould according to anthropometry and children''s usage, making them the first priority. The play in open and closed spaces provided noise buffers and adequate sunlight for learning and protected from the harsh climate of Dhorkin. The spaces are carefully designed in the 102 SQM build-up area to leave a colossal chuck as a playground. Learning being the central idea of the school, the design revolves around grasping knowledge from the surroundings and architectural elements such as roofs, walls and even floors. Introduction to modern methods like cognitive learning and social and intellectual development have been assimilated for overall child development.

A free path for ventilation and light is created by the high ceilings, with non-reflective roofing material to reduce heat gain. The classroom orientation, vaults and openings respond to the breeze to keep comfortable temperatures for students. This takes a step towards the green initiative, helps students concentrate and is cost-effective. Clean toilets and kitchen facilities are designed for the students. 

The vaults made of metal sheets are a cost-effective material that provides classroom volume for holistic and focused learning. The structure is made of local bricks and traditional patterns to continue the rooted aesthetics and create a cost-effective building with a grounded feeling to the elevation. The budget was a major constraint in the project; materials like epoxy for flooring, corrugated sheet and brick, which were readily available around the site, were used. Learning is central to the idea; the playground also becomes a classroom and vice-versa. The subtle introduction of the amphitheatre, which faces the playground, helps students pick the concepts of sports.',
    TRUE,
    'LDP17', 'Yatindra Patil & Vijay Kharade', NULL, NULL
);

-- Row 22: LDP20
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Craft Narrative', 'Yatindra Patil', 'info@craftnarrative.com', 'Library Pod',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Pune', 'India',
    NULL, NULL,
    '“It all started with my father, saying when there is bus stops in each village then there should be a library stop too.”
This is the vision shared by our patron, an artist  Rajshri Deshpande. She is also the founder of  Nabhangan  foundation.
 
The design conceived as Knowledge pod. A place to learn, contemplate & play all around.
Pod has potential to form communal space, where villagers with diverse age can gather, accomplish  the reading habit and also a perfect setting  for storytellers  too.
 
A deliberate attempt to insert  the library pod within the existing rural school & our intent is to shape it as part of the school &  surrounding.
Pod amidst existing rain tree, pipal  tree and also encircled by graffiti art works created by local artist & students. It creates the colourful and shaded foreground.
 
This inserted library pod serves as the two parallel worlds, A one being introverted book shelf  & other as vibrant scribble or black board.
Book shelf positioned to create intimate seating possibilities with existing steps around and rubber wood bench as part of the pod. The large overhang serves the purpose for seating area.
 
Black board oriented  towards larger shaded open space, Creates the place under shade to serve as outdoor classroom.
A backdrop for early morning gatherings & lunch time play activities.
 
Library pod Insert  accomplishes the multifaceted activities for students and villagers.', 'As we trace back our academic culture to the gurukul system while evolving into a society that focuses on technology in education, the Indian demographical context cannot be ignored. The quest for knowledge doesn’t know restrictions, it is where the willingness is— across age groups and interests, and it has to be addressed at the grassroots level in order to excel collectively. What better way to address it than to start from the villages of India, where natural inquisitiveness thrives, despite proper infrastructure and resources.
 
“When there are bus stops in each village, there should be a library stop too.”
 
 This was the thought behind Rajshri Deshpande’s initiation for Library Pod—an arena for knowledge that has the potential to form a communal space where villagers of diverse ages can gather, and accomplish the reading habit and also a perfect setting for storytellers too. The crux of the project lies in its location—it is a deliberate architectural intervention that utilizes only 17.16 sqm of space in a rural school that has an area of 220 sqm. The pod is built where knowledge resides—a school in the village of Aurangabad, Maharashtra. It takes up a lot less space as compared to the impact it puts on the virtue of education. The structure is strategically built under a peepal tree, in a space encircled by graffiti artworks created by local artists & students. It consists of a storage shelf and a projecting metal roof designed to shield the users from extreme weather conditions, made up of thin steel plate rafters and purlin that taper towards the edges to express the lightness against the visually heavy bookshelf. The entire unit in metal doubles up as water-tight bookshelves and as blackboards on the other side, which cater to the outdoors, making it suitable to conduct a class under the peepal tree as well.  Since it is outside the built school structure and open to sky, the bookshelves had to be made water and dust-free by using rubber gaskets to seal them and GI sheets to make up their framework and shutters. The bookshelves were made by the manufacturers of streetside electrical distribution board boxes, who have prefabricated the unit and assembled it at the location to maintain workmanship and quality. An extension of this unit is made by adding a rubber wooden bench beside it. The flooring for this pod is constructed with bricks, in a way that they start from level zero and up to the pod’s level by creating small steps in between, also serving as a place to sit. The brick base is covered by the overhang which is supported by 80mm*80mm M.S. box sections as columns. The pod also serves as a backdrop for early morning gatherings and lunchtime play activities in the school while successfully accomplishing multifaceted activities for students and villagers alike. With that being stated, the Libray Pod is an example of how the biggest of achievements start with the smallest of inventions.
 
The pinnacle of mankind can be understood by the way inventions are made. It is in the bigger achievements that the technological advancements are measured, however, the smallest of interventions making the biggest of differences are worth paying attention to. Completed in December 2021, the Library Pod is a successful initiative by Nabhangan Foundation, which now serves as a place to learn, contemplate and play around.', 'A school in the rural boundaries of Pimpal Gaav Pandhri, in Aurangabad, has students who are curious to read and discover the world through books but needed motivation. The school had donations of books each year, which disappeared within a year as a system of using these books needed to be adopted. The library pod began as an experiment. 
The significance of having a library in schools cannot be under-emphasized. It encourages the development of the students and villagers, assists in developing the vocabulary, increases comprehension, instils the habit of reading in silence, and encourages a problem-solving approach in students, especially at a young age.
The intent is to shape it as part of the school and cultivate a community of readers. The pod has a rural setting amongst the rain and pipal trees, surrounded by artwork by local artists and students. 
The design is envisioned as a Knowledge Pod—a place to learn, contemplate and play around. The pod is like a coin, revealing its two sides, one the introverted, where reading is the main activity under the comfortable shade of trees. In contrast, the other is the extroverted side, which brings together a class.  

The pod has a unique design where it borrows shade and seatings from trees and the buildings around it and offers its own. The library is designed as a quiet space with a bookshelf and seater. The back of these bookshelves turns into a blackboard that caters to several activities, provides an under-the-tree outdoor classroom, and caters for activities like storytelling and morning assembly. The library pod is positioned as a pause point for the school as well as villagers, to take their quiet time to read. It also provides a welcoming seater for anyone from the village who wishes to cultivate a habit or gain knowledge. 
The material is mostly steel sections used for electric boards with an interlocking mechanism. The roofing was a simple corrugated sheet with a paint finish. The structure is kept light and according to the child''s anthropometry. 
The library helps students understand their own culture and exposes them to other cultures, gives them the most recent information, and exposes students to fresh ideas, literature, and ideas, making their awareness of the history and geography of both the near and far regions. An intervention like the Library pod holds the potential to administer a thought and a change of wave.',
    TRUE,
    'LDP20', 'Yatindra Patil & Vijay Kharade', NULL, NULL
);

-- Row 23: LDP23
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Localworks', 'Angela Nkurunziza', 'angela@localworks.ug', 'Mustardseed Junior School',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Wakiso', 'Uganda',
    NULL, NULL,
    'MJS is a newly founded private initiative with the aim of creating an exemplary kindergarten and primary school that provides an inspirational and practical education to the young children in its care. It is located near Sentema, a village about 20km west of Kampala. The inspiration for the design was to create a ‘large home’ for the children that functions as a comfortable enabling educational environment. The architectural ambition is not programmatically prescriptive, but rather to inspire teachers and students alike to inhabit spaces in multiple and creative ways, to (literally) think outside the box and to treat the entire school, not just the classroom, as a greater learning environment.', 'At Mustardseed, no two classrooms are alike and none of them are in the shape of a rectangle. Spaces are organically shaped and characterised by a warm, natural materiality accentuated by playful and inspiring colours. The thick, earthen, undulating external walls stop short of the roof allowing the flow of fresh air to cool down the spaces. Direct sunlight is filtered through the roof in selected areas filling the space with comfortable levels of natural light. Along circulation routes, colourful window shutters enclose relatively small and squarish openings. Each classroom has a dedicated outdoor learning area shaded by trees which can be accessed through a series of double doors. Across the school, furniture has been carefully designed and integrated into the program: this includes built-in benches and shelves, cubby holes, large full-height black boards and light-weight yet sturdy tables and chairs.
The landscape and architectural design are in complete harmony with each other. Free flowing forms of internal teaching spaces resonate in the landscape design in fluid, flowing lines which seek to nurture curiosity for learning within children. A holistic approach to teaching is core to the overall concept of Mustardseed which means learning from and with nature is of central importance. This objective is taken seriously in the design by literally creating a space for nature. Another ambition of this project is to improve biodiversity, despite the construction, and to (re-) create indigenous forests, whilst ensuring human activities on the land are sustainable, practical, and enrich the overall environment. These goals are being achieved through conservation agriculture, soil regeneration and sustainable indigenous timber plantations.', 'Alongside the application of extensive passive design systems, all building materials have been carefully selected. Almost all of the building material is sourced and harvested on or within a 2km radius of the site keeping production costs low and the carbon foot print close to zero. Not only is this project constructed sustainability, but also, it leaves the site with more biodiversity that it started with. Conservation agriculture, soil regeneration and planting an on-site forestry program using fast growing indigenous species have been developed in concert with the schools ecologically-oriented curriculum.
In addition to efforts to improve local school building standards, this innovation protects the environment ecologically. The non-stabilized earth building material not only prevents deforestation stimulated by the burning of commonly used clay bricks but also, all buildings retain the potential to be demolished with minimal damage to the site which can be easily repurposed. Across Uganda, fast growing eucalyptus trees are being planted more and more frequently; it is a non-indigenous species that degrades the local environment. Whilst necessary to meet the high firewood demand for cooking, instead of eucalyptus, this project will use indigenous softwood trees, planted as part of a carbon-positive sustainable forestry program. This effort promotes and encourages the return of local vegetation species that are slowly dying out.',
    TRUE,
    'LDP23', 'Allan Semakula, Deborah Tusiime, Edson Agume, Felix Holland, Geoffrey Addah, Guy Namanya, Morgane Charron, Norbert Ahumuza, Paul Kyoma Asiimwe, Peter Ssemakula Mukiibi, Philip Matovu, Robert Mugisha, Sarah K Ndagire, Torsten Lorange', NULL, NULL
);

-- Row 24: LDP67
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Hoang Thuc Hao & 1+1>2', '1+1>2 Architects', 'amedia@112.com.vn', 'Highland School System',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Ha Noi', 'Viet Nam',
    NULL, NULL,
    'Since 2014, 52 schools have become operational. Many more are in the process of construction in every region of the country. Every school aims to serve its community, support teachers and students', 'School designs are inspired by the everyday, design cues can come from the rhythm of Thai dance, or a forest flower inspires roof shapes. The school design is based on four core principles: respect the surrounding environment; promote the indigenous spirit and traditional culture; take advantage of local materials and hire local workers; combine design suitable for modern education with traditional methods.', 'Though varied in context and design, schools sprung up like “flowers of the soil”, representing justice, the spirit of integration and inspiration. They served to build strong social consciousness, contribute educational significance, and safeguard indigenous traditions. Just as importantly, they motivated disadvantaged communities to raise their voices and contribute to humanity’s rich and diverse culture.',
    TRUE,
    'LDP67', 'Hoang Thuc Hao & 1+1>2', NULL, NULL
);

-- Row 25: IFF3
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Arquiteta e urbanista', 'Anna Candida Valentim', 'annavst29@gmail.com', 'Cidade Delas: Safer urban spaces for girls and women',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Manhumirim', 'Brazil',
    NULL, NULL,
    'The booklet Cidade Delas: safer urban spaces for girls and women, seeks to inform about the problems related to the design, uses and occupation of public space that cross the social representations of gender, because like him, the city is also a social construction.', 'The booklet presents five elements of the right to the city and women''s lives and how
the absence or violation of each element that makes up the right to the city can affect the
women''s urban experiences, namely:
 Right to adequate housing;
 Right to quality democratic management;
 Right to adequate public services;
 Right to urban planning;
 Right to urban mobility.
In addition, articles of the federal constitution are indicated, decrees that guarantee the
women''s rights to the city, information, curiosities and quotes from authors about the right to the city.', 'Despite all the achievements of women in society and the advances of their own, the city is still being planned and produced from the perspective of patriarchy. Urban planning does not take into account the demands of the population regarding the inclusion of a plurality of races, genders and social classes, which, in this way, influence the use of space and urban design.
The urban violence suffered by women goes beyond criminality, these situations are even more reinforced by poorly planned urban spaces, such as abandoned land, precarious public lighting, unsecured parks, poorly planned bus routes, among others. The way the city is planned directly interferes with women''s lives, therefore, when the planning does not include them, the space becomes unsafe.
The city is a reflection of society, which is why it is important to grant inclusive, accessible spaces that encourage feminist struggles in favor of gender equality, that allow the female place in public spaces to be free, circulations and routes to be unlimited and safe.',
    TRUE,
    'IFF3', 'Anna Candida Valentim', NULL, NULL
);

-- Row 26: IFF7
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'One University One Village team, The Chinese University of Hong Kong', 'Li Wan', 'wanli@cuhk.edu.hk', 'Sustainable Rural Development Program: One University One Village',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Southwest rural China', 'Unknown',
    NULL, NULL,
    'The One University One Village (1U1V) Initiative was launched by Prof. Edward NG and Dr. Li WAN at The Chinese University of Hong Kong (CUHK) in 2014. It aspires to bring together the expertise, knowledge and human resources of “a university” to improve the livelihood of “a village” and its needy villagers in a strategic, systematic and sustainable manner. In 2015, 1U1V team conducted a post-earthquake reconstruction project in Yunnan, China to demonstrate the use of “high-science-low-technology” strategies with the “local materials, local labour, and local technology” principle of rural construction, and to encourage endogenous development in rural China. The project and the holistic strategy behand it creatively mended the environmental, economic, and social sustainable development of poor rural areas. Since 2017, the team started to scale up the work, and to continue the work more systematically, with the building of the Terra Centre in Kunming as the working base in China to research, promote, train and knowledge transfer. With funding support from the Chan Cheung Mun Chung Charitable Fund, 60 more village houses have been rebuilt and more than 70 houses are under construction in Southwest China.', 'Sustainable rural development is a significant issue in China, which has more than 40% of its population living in rural areas. The development of poor rural areas in mountainous regions of Southwest China has been relatively slow and unsustainable. The crucial support that poor rural areas of China require is not only funding but also innovative ideas and systematic strategies. Rammed earth construction has a long history in China. Raw earth is the main material used in traditional architecture because it is inexpensive, accessible and exhibits remarkable thermal performance. However, under the impact of urbanization, rural residents tend to think that earthen buildings are associated to poverty and backwardness. Moreover, improving the seismic performance of earth buildings is a big challenge since many of them are located in earthquake-prone areas. To provide a suitable and sustainable solution for rural reconstruction in Southwest China, our team explores the research and innovates rammed earth building technology to provide a safe, economical, simple, and sustainable reconstruction strategy that the rural residents can afford, own, and disseminate.
To ensure systematic and sustainable rural reconstruction work with innovative ideas, scientific research is essential to understand the context, identify the problem, and find a proper solution. To empower the rural residents and encourage endogenous development, “high-science-low-technology” strategies and “local labour, local materials, and local technology” principle was applied in poor rural areas in Southwest China. Instead of promoting the benefits of imported brick and concrete, our team determined whether the shortfalls of traditional rammed earth technology and the fragility of village life could be addressed in situ. The implementation of this strategy was a simple step in rebuilding the lives of the people. Since 2014, our team has started to build rural houses to demonstrate a comprehensive and systematic construction system and resulting substantially high building quality. Meanwhile, the residents were empowered through the demonstration projects with craftsman training and co-construction. Through this long-term cooperation and learning-by-doing process, we established mutual trust with the villagers and convinced them that the innovative, anti-seismic rammed earth building was a good solution. 
Our rural programme provides an interdisciplinary, innovative and sustainable solution for poor rural areas in China. This solution has been generated by multidisciplinary partnerships and networking platforms. We also hope this knowledge database can also inspire and lead the work of the local governments and other NGOs in China and other underprivileged areas in less-developed countries, and eventually create a knowledge value chain that helps build a better future for rural communities around the world. More than 60 village houses have been rebuilt and more than 70 houses are under construction in Southwest China. More than 6 villager craftsman construction teams (including a women construction team) were established. Moreover, the innovative rammed earth building technology can be replicated for the improvement of poor rural areas where there are similar natural and social conditions to those in the poor rural areas of Southwest China, for example, in the rural regions of Nepal and India.', 'The 1U1V program helps villagers find local employment, increase their skills and incomes, and improve building safety to avoid poverty caused by earthquakes. This responds to SDG 1 (End poverty in all its forms everywhere)
Our craftsman training plan and construction organization have a comprehensive and positive impact on the psychological needs of villagers at all levels. It responds Target 4.4 (substantially increase the number of youth and adults who have relevant skills, including technical and vocational skills, for employment, decent jobs and entrepreneurship) of SDGs.
We engaged women into construction to promote gender equality. Furthermore, a women construction team with a female leader and half of women workers has been established after this project. Men and women get equal pay for equal work. This strategy is aligns with SDG 5 (Achieve gender equality and empower all women and girls).
At least 6 village construction teams were established. With the formwork and rammer donated from our team, villagers can own this technology and pass it on. Supporting productive activities, decent job creation, entrepreneurship, creativity and innovation, and encourage the formalization and growth of micro- and small-sized enterprises is also emphasized in Target 8.3 of SDGs.
Preferential use of local and natural materials minimized the embodied energy and respond to the target 12.2 (Achieve the sustainable management and efficient use of natural resources.)of SDGs.
The esteem needs and self-actualization needs of villager craftsmen are also considered and valued in this project. This process changed the attitude of the villagers towards rammed earth buildings. They became interested in switching back from brick-concrete houses because this method protected their traditional technology and lifestyle. Such a shift is consistent with the Target 12.8 (ensure that people have the relevant information and awareness for sustainable development and lifestyles in harmony with nature) of SDGs
Our team not only provide design as architects but also worked with the villagers throughout the process as partners. Besides, we established effective network of academics, professionals, students and volunteers who share the same aspiration to generate academic and societal impact by intervening practical projects, to build a knowledge community. Local government is also involved to coordinate and explore this new sustainable way of rural reconstruction. This model not only benefits the villagers, but also has a positive impact on other participants and contributes. It responds the Target 17.16 (Enhance the Global Partnership for Sustainable Development, complemented by multi-stakeholder partnerships that mobilize and share knowledge, expertise, technology and financial resources, to support the achievement of the Sustainable Development Goals in all countries) and Target 17.17 (Encourage and promote effective public, public-private and civil society partnerships, building on the experience and resourcing strategies of partnerships) of SDGs.',
    TRUE,
    'IFF7', 'Edward Ng, Li Wan, Xinan Chi, Wenfeng Bai, Fang Tian, Xiaoxue LIU, Lai Zhou, Jingwei Zhou', NULL, NULL
);

-- Row 27: LDP11
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'TecTo Arhitectura', 'Sergiu C. Petrea', 'office@tecto.ro', 'FIRST CLT MULTI COMFORT OFFICE BULDING',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_II', 'Reci, Covasna County', 'Romania',
    NULL, NULL,
    'The project was designed as the first large scale project with CLT and GLT structure in S-E Europe as flagship two-levels office building, based on utmost ecological and long-term sustainability. The building acts as a visual interface between two antagonistic spaces – an industrial platform used for production and a natural landscape with strong horizontal lines.', 'The design workflow followed four major objectives: Sustainable prefabricated CLT and GLT construction, Healthy and Inclusive Working Spaces: individually room-controlled comfort and high-quality work environment, increased noise protection, passive construction for insulation and air-tightness, heat recovery ventilation system; Ecology: use of geothermal energy, high efficiency biomass co-generation plant for heating and electricity, optimization of utilities costs, green roofs, enhanced daylight autonomy, increased degree of recyclable building; High quality architecture and landscape.', 'The main challenge was to create an office building for around sixty people that had to provide healthy lives and promote well-being for all at all ages and achieve gender equality through operational use. The owner aimed to achieve full and productive employment and decent work for all through a sustainable building. The green roofs and the surrounding landscape collect and filter rainwater ensuring availability and sustainable management of water. Moreover, it restores to nature the built footprint and promotes sustainable use of terrestrial ecosystems, enhancing local biodiversity. The building has a heating and cooling system based on a well with enhanced heat collection and a heat pump with hot/cold puffer system and a biomass co-generation plant for heating and electricity while the ventilation system uses heat recovery to minimize consumption. This ensures sustainable consumption and production patterns and acts as an example of fighting against climate change. The project strategy uses resilient infrastructure and promotes inclusive and sustainable industrialization. Finally, it is an example of good architectural practice to show how built environment may become inclusive, safe, resilient and sustainable, its awards in several competitions backing up the idea.',
    TRUE,
    'LDP11', 'PhD. arch. Sergiu-Cătălin Petrea, arch. Sabrina Ene-Butnariu, arch. Cristina Mototolea, arch. Sebastian-Ștefan Apostol, arch. Dan - Alexandru Roșu, arch. Tania-Victoria Băncilă, arch. Diana-Elena Fusea, arch. Ovidiu-Ion Bălășoiu', NULL, NULL
);

-- Row 28: LDP59
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'IAP - Institute of Architects Pakistan', 'Amina Qayyum Mirza', 'aaomd2@gmail.com', 'Product Development & Marketing Offices, Khurrianwala, Punjab, Pakistan | Creating Equality/Inclusiveness in the Workplace-A Catalyst for Change',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Khurrianwala, Punjab', 'Pakistan',
    NULL, NULL,
    'The project is located in peri-urban area in an industrial estate. The project- product development & marketing offices are connected to a production facility. The design is conceived as an open plan inclusive and a non-discriminatory workplace.', 'The locality of this project is important as the preconceived notion of women’s subservient status is prevalent in society as a whole. 

The new offices were designed to create gender equality in the workplace in an open-plan by placing women with ease next to their male colleagues, thus normalizing the feminine presence. The shared workspaces were interspersed with occasional meeting areas to encourage collaboration; cultivating gender interaction. 

The open-plan fostered communication between various management levels. Facilitating the rightful candidate to rise in the hierarchal order in the company. 

Gender-specific spaces were created to give women privacy, security, and comfort. The new building incorporated principles of biophilia, passive design and energy conservation.', 'Pakistan is the fifth most populated country in the world, with more than 50% female population. (Pakistan population 2022). 

The engagement of women workforce benefits the country’s economy and help alleviate poverty.

At a micro level in the peri-urban area, these projects act as a catalyst for a change in the perception of built space and work environment. It created an enabling equitable non-discriminatory environment lessening the gender divide.

The project had significant impact on the company’s policy for inclusion and recognition of gender-specific needs. Leading to women empowerment as an integral part of Vision 2025. 

At a macro level, women empowerment benefits the country as women prioritize wellbeing of their families and invest all their earnings in improving the future prospects of their children.',
    TRUE,
    'LDP59', 'Amina Qayyum Mirza', 1858.0608, NULL
);

-- Row 29: LDP6
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'The Chinese University of Hong Kong and Kunming University of Science and Technology', 'Li Wan', 'wanli@cuhk.edu.hk', 'Terra Centre',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Kunming，China', 'Unknown',
    NULL, NULL,
    'Through the cooperation with Kunming University of Science and Technology (KUST), One University One Village team have improved the construction technology and seismic performance of the earth construction in Southwest rural China. In order to carry out long-term artisans training, to provide space for conducting experiments, research and practical study, and to showcase the technologies and achievements of new seismic earth construction, the 1U1V team built the Terra Centre in KUST campus with funding support from the Chan Cheung Mun Chung Charitable Fund.
The project design is highly based on the local climate condition of Kunming. Appropriate passive design strategies guaranteed low operating energy consumption. All the materials used in the wall are natural materials. No industrial stabilizers were added in the earth wall. The wall is 100% recyclable, degradable, and pollution free. 
The Terra Centre is not only a building but a research and education tool. The team trained and employed villagers to build the Terra Centre and thus transfer to them a way to make their livings economically later. The result verified an appropriated solution of the local reconstruction that provides references for national rural construction policies and earth building seismic standards.', 'Research shows that socioeconomic value is crucial in sustainable rural development. The environmental load of vernacular houses in poor rural areas is low already. The key issue is how to improve the safety, quality and dignity of the living environment without adding substantial environmental load. Earth building has a very long history in China. Terra Center as a research centre for earthen architecture and rural sustainable development, applied “high-science and low-technology” strategy with “local materials, local labour and local technology” principle to encourage endogenous and sustainable development in poor rural areas in China.
    The building design is highly based on local climate condition so that proper passive design strategies can be selected. Kunming has a moderate climate with abundant sunshine and large temperature difference between day and night. With good thermal mass, rammed earth wall is a very suitable material. We designed a semi-outdoor space with top lighting in the middle of the building to provide a comfortable multifunctional space for multiple training and academic activities. Passive design strategies including passive solar heating, natural ventilation, and shading guaranteed high indoor environmental quality and low operating energy consumption. No active cooling and heating equipment has been used in this project.
    To minimize the impact to the local environment, 89% of the building materials (by weight) are local natural materials (raw earth, gravel, sand, and bamboo). No industrial stabilizer was added to the wall, i.e., the wall is 100% recyclable and pollution-free. The roof structure is made of bamboo that is a fast-growing material with low embodied energy. No decoration material was used on the building façade and interior walls. Industrial materials, such as cement and steel, are limited and efficiently used in key structural parts to ensure building safety and building environmental quality.
    We meet the safety needs of people by improving the building seismic performance. To improve wall strength and reduce cracks, we analyzed the basic properties of the soil and optimized the proportion by adding gravel and sand. The air compressed rammers and the aluminum alloy formwork are applied to Improving the compressive strength of the wall. In terms of structural design, reinforced concrete tie columns, ring beams, foundation and floor slabs are applied to enhance the structural integrity. The result of mechanical property tests and shaking table tests corroborates that the seismic performance of the rammed earth building significantly is improved, thereby meeting the local seismic codes perfectly.
The Terra Centre is not only a building but a research and education tool. We trained and employed villagers to build the Terra Centre and thus transfer to them a way to make their livings economically later. 33 villagers (including 5 women) joined this project and passed the craftsmen training. The project changed the attitude of the villagers towards rammed earth buildings. They became interested in switching back from their brick-concrete houses because the project protected their local traditional construction method and lifestyle. The project result provides references for national rural construction policies and earth building seismic standards.', 'Our craftsman training plan and construction organization have a comprehensive and positive impact on the psychological needs of villagers at all levels. It responds Target 4.4 (substantially increase the number of youth and adults who have relevant skills, including technical and vocational skills, for employment, decent jobs and entrepreneurship) of SDGs.
We engaged women into construction to promote gender equality. Furthermore, a women construction team with a female leader and half of women workers has been established after this project. Men and women get equal pay for equal work. Accordingly, the equipment has been improved to make them more convenient to control for women. This strategy is aligns with SDG 5 (Achieve gender equality and empower all women and girls).
    At least 5 village construction teams were established after completion of the Terra Centre. They can use their knowledge of such new construction technology as their livelihood. With the formwork and rammer donated from our team, villagers can own this technology and pass it on. Supporting productive activities, decent job creation, entrepreneurship, creativity and innovation, and encourage the formalization and growth of micro- and small-sized enterprises is also emphasized in Target 8.3 of SDGs.
    Preferential use of local and natural materials minimized the embodied energy and respond to the target 12.2 (Achieve the sustainable management and efficient use of natural resources.)of SDGs.
    No industrial stabilizer was added in the wall, i.e., the wall of this building is 100% recyclable and pollution-free. This project reduces the construction waste caused by building construction, responding to the Target 12.5 (Substantially reduce waste generation through prevention, reduction, recycling and reuse) of SDGs.
    The esteem needs and self-actualization needs of villager craftsmen are also considered and valued in this project. This process changed the attitude of the villagers towards rammed earth buildings. They became interested in switching back from brick-concrete houses because this method protected their traditional technology and lifestyle. Such a shift is consistent with the Target 12.8 (ensure that people have the relevant information and awareness for sustainable development and lifestyles in harmony with nature) of SDGs.
    Our team not only provide design as architects but also worked with the villagers throughout the process as partners. Besides, we established effective network of academics, professionals, students and volunteers who share the same aspiration to generate academic and societal impact by intervening practical projects, to build a knowledge community. Local government is also involved to coordinate and explore this new sustainable way of rural reconstruction. This model not only benefits the villagers, but also has a positive impact on other participants and contributes. It responds the Target 17.16 (Enhance the Global Partnership for Sustainable Development, complemented by multi-stakeholder partnerships that mobilize and share knowledge, expertise, technology and financial resources, to support the achievement of the Sustainable Development Goals in all countries) and Target 17.17 (Encourage and promote effective public, public-private and civil society partnerships, building on the experience and resourcing strategies of partnerships) of SDGs.',
    TRUE,
    'LDP6', 'Edward Ng, Li Wan, Lucia Cheung, Xinan Chi, Wenfeng Bai, Marc Auzet, Juliette Goudy, Fang Tian, Xiaoxue Liu, Lai Zhou, Shan Dai, Changzhuan Shao', 1328.5, NULL
);

-- Row 30: LDP72
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'IAB - Institute of Architects Bangladesh', 'Razib Hassan Chowdhury', 'silt.studio@gmail.com', 'বোতলবাড়ি'' - Community hub and wash facilities for women',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Kuakata', 'Bangladesh',
    NULL, NULL,
    'A resilient community hub providing friendly space for women and adolescent girls with access to proper toilets and bathing facilities- A space to foster inquisition, collaboration, and self-reliance.', 'A water-starved, Cyclone prone community in kolapara , kuakata hosts this structure where local women commune to identify, discuss and find solutions to their constraints. A low-cost and easily replicable solution for resilient shelters is achieved by utilizing waste plastic bottles, bamboo posts, old fishing nets and mud. In addition to addressing the lack of sanitation the structure also houses a repurposed underground bunker as a communal strong room for valuables during cyclones.', 'A safe space for women to engage, build a resilient community, and gain access to hygiene facilities in an area prone to water scarcity and natural disasters. The combination of locally available materials with repurposed waste in an easily replicable technique keeps carbon the footprint and construction costs to a minimum. Women''s active participation in learning the techniques and building the shelter empowers them with new skills while also fostering a sense of ownership of the space.',
    TRUE,
    'LDP72', 'SILT', NULL, NULL
);

-- Row 31: IFF2
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
