    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Igor de Vetyemy Arquitetura', 'Igor de Vetyemy', 'igordevetyemy@gmail.com', 'Re-bridge',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Rio de Janeiro and Niteroi', 'Brazil',
    NULL, NULL,
    'Linear park under the Rio-Niteroi bridge with hotels, restaurants, culture facilities, social housing, sustainable mobility, generation of clean energy, and support for recuperating the marine life.', 'The Guanabara Bay is crossed by a colossal and obsolete structure used only by cars, the Rio-Niteroi bridge. This proposal creates a linear park under the bridge with supporting program including hotels, restaurants, social housing and culture facilities. The project involves sustainable urban mobility, generation of clean energy, mitigation of the housing deficit close to Rio de Janeiro`s city center, creation of spaces for leisure and interaction; and support for recuperating the marine life.', 'The project ensures healthy lives and promotes well-being for all by creating the possibility of active means of transport to connect the neighbour cities in more inclusive, and sustainable ways. It ensures sustainable management of water and promotes sustainably use of the marine resources with research facilities to work on the recuperation of the bay waters, once house for hundreds of dolphins and whales. It uses the waves, wind and sea tides to generate sustainable energy for public use.',
    TRUE,
    'IFF2', 'Igor de Vetyemy, Mariana Barbosa, Rogério Chieza, and Felipe Calazans', NULL, NULL
);

-- Row 32: LDP2
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Kuee Architecture', 'Ar Shyuan Kuee', 'shyuan@kueearch.com', '1 Lasam',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Ipoh', 'Malaysia',
    NULL, NULL,
    'Taking 10 years to conceptualize, 1 Lasam is the first GBI Platinum Building in Perak. Its V-shape footprint designed to maximize the footprint, with a courtyard carved out in the centre for natural ventilation throughout. Fully built with exposed red-bricks and concrete, this green building is also entirely powered by solar panel. Lush greenery occupies breakout spaces for the worker who to enjoy views out to the nature. Double layered brick walls at the west facing facade cut down heat gain substantially.
Being the first building in the country to win PAM Awards in SDGs category, 1 Lasam has fulfilled eight category in this United Nation''s standard. It is a bold addition to Ipoh''s cityscape and contributes positively to the country''s sustainability scene.', '1 Lasam was conceptualised more than eight years ago by the owner Dato Lim, when GBI rating tool was new and there was still no other green buildings in Perak. The amicable and ambitious client wanted to build the first ever GBI Platinum building in the state, to resonate with the group’s motto of being a pioneer in many of the businesses they have ventured in since decades ago.

¬ A central courtyard was carved in the centre, to allow more daylighting into the office spaces. Nako windows were installed at high levels of all office spaces for natural cross and stack ventilation through the central courtyard, so that during a cool day no air conditioning would be required. 

Measuring about 30,000sf of office space, the 5-story office block comes with majority workspaces with ancillary spaces e.g. conference room, gallery space etc.The design team explored the concept of floating boxes which further developed into box-in-box geometry. The higher floors were lifted up supported by a bold V-shape column, to allow for vehicle circulation on the street level. With the neighbouring army camp, many restrictions in building design were imposed. The west facing double layered wall installed with dense louvres not only eliminated direct view to the camp, it also blocked the heat and sunlight to the office spaces in the evening. On this gesture, the Architect managed to kill two birds with one stone.
Eight categories for United Nation’s Sustainable Development Goals were achieved. The complying categories included Responsible Consumption and Production, as relatively high percentage of construction material was used and many construction waste being recycled. Clean Water and Sanitisation also played an important role in the design of the building. While both rainwater harvesting and greywater recycling led to high reduction in portable water, storm water control was also catered for, with a bioswales constructed on site for effective water drainage.

Other green features included maximising electricity generation from the solar panels, rainwater and grey water harvesting, tinted glass, grasscrete for lowering heat island effect, and bioswales on site for effective storm water drainage etc. 

Materials were selected carefully to reflect the client’s intention to keep the building as “raw” as possible. Exposed bare concrete, red bricks applied with waterproofing solution, simple aluminium framed tinted glass, exposed ceiling throughout, and to many’s surprises, not a single drip of paint was used in the entire building. 

To resonate further the V-shape land and V-shape column, V-shape balustrades were designed to emphasise the strong alphabet presence of the client’s mother company name “BVH”.

1 Lasam was perhaps one of the boldest new addition to Ipoh’s low profile skyline. It’s head-turning architecture has attracted interests from professionals and the public in general since it’s completion. With Dato’s intention to allow public access on the ground floor for green building education, we believe this building will contribute positively to the local sustainable architecture scene in many years to come.', '3 3.9 1. Waterproofing sealant with no formaldehyde 3.A 1. 10 m of outdoor building smoking area away from building openings 6 6.3 1. Storm water control meeting MSMA requirements 6.4 1. Rainwater harvesting leads to 51% reduction in portable water 1. Greywater recycling leads to 12.03% reduction in portable water 1. Potable water for ALL landscape irrigation is NOT needed 1. Reduced annual potable water consumption by 67.55% 7 7.2 Solar PV panels for renewable energy (40kWp) 11 11.C Up to 37.10% of the total material cost are regional materials 12.1. Up to 26.40% of total material cost to have recycled content 1. Dedicated recycling bins during construction stage 1. At least 75% of construction waste is diverted to recycling centre 12.6 1. Dedicated recycling bins during construction stage 1. At least 50% of construction waste is diverted to recycling centre 12.8 1. Real time energy and water usage display 13 13.1 Use zero ODP products 14 14.1 Storm water control meeting MSMA requirements 15 15.1 Project complies with local town planning requirements 15.2 1. 100% of all timber products (mainly doors) were certified by MTCC/ FSC',
    TRUE,
    'LDP2', 'Ar. Shyuan Kuee', NULL, NULL
);

-- Row 33: LDP31
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Architectural Society of China', 'Yehao Song', 'sup_atelier@supatelier.com', 'Wastewater Resource Recovery Plant of Yixing',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Yixing, Jiangsu Province', 'China',
    NULL, NULL,
    'The Concept WRRF Yixing, is a future-oriented Water Resource Recovery Facility & factory. The aim of the project is to upgrade conventional sewage treatment plants to environmental-friendly and re-cycling-oriented plants. Alleviating the Not-in-my-backyard effect, the upgrade will transform a closed pollution-control plant into a sustainable and future-oriented infrastructure project that is environmental-friendly, open to the public, harmonious with its neighborhood and available for sci-ence education.', 'The overall planning of the plant is implemented in pursuit of an intensive layout, the efficient use of land, the integration of landscape & buildings, and the care for human. 
The waste water will be treated into clean water , fertilizers and energies, such as biogas and thermal energy. The clean water will irrigate farmland and return to nature. The fertilizers and energies are sustainable products from waste resources.
A special “Tank Cafe” clings to the southern wall of a secondary sedimentation tank. The specially designed space can be also transformed into a muti functional conference hall or exhibition hall, serving for both professional and popular science activities. Several small courtyards scattered in the coffee shop has optimized views and positions of openings while covering structural elements and separating different zones. 
Here people can percept, experience or even play with its features, enjoying the changes of nature, the diversity of ecological environment. Through the project, the conservation of resources, the care for environment and the respect for humanity are spread to the public
The core value of the project lies in creating a conceptual plant that not only meets industrial de-mands, but also serves as a public space that draws people close to it. Here people can percept, ex-perience or even play with its features, enjoying the changes of nature, the diversity of ecological environment and the ever-changing patterns of light. Through the delicate spatial experience, con-cepts of the plant are conveyed to people, raising their awareness for the conservation of resources, the care for environment and the respect for humanity.
The overall planning and architectural design of the plant area respect and integrate the design of sewage and sludge treatment processes, and basically achieve the four goals of "water quality sus-tainability, resource recycling, energy self-sufficiency, and environmental friendliness".', 'The Concept WRRF Yixing, is a future-oriented Water Resource Recovery Facility & factory. The aim of the project is to upgrade conventional sewage treatment plants to environmental-friendly and re-cycling-oriented plants. Alleviating the Not-in-my-backyard effect, the upgrade will transform a closed pollution-control plant into a sustainable and future-oriented infrastructure project that is environmental-friendly, open to the public, harmonious with its neighborhood and available for sci-ence education.
The overall planning of the plant is implemented in pursuit of an intensive layout, the efficient use of land, the integration of landscape & buildings, and the care for human. 
The waste water will be treated into clean water , fertilizers and energies, such as biogas and thermal energy. The clean water will irrigate farmland and return to nature. The fertilizers and energies are sustainable products from waste resources.
The overall planning and architectural design of the plant area respect and integrate the design of sewage and sludge treatment processes, and basically achieve the four goals of "water quality sus-tainability, resource recycling, energy self-sufficiency, and environmental friendliness".',
    TRUE,
    'LDP31', 'Song yehao, Sun jingfen，Xie dan, Shi lei, Chen xiaojuan, Chu yingnan, Loo huixin', 14601.0, NULL
);

