    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Council of Architecture and Urbanism of Rio Grande do Sul (CAU/RS)', 'Tiago Holzmann da Silva', 'gabineteathis@caurs.gov.br', 'No House without a Bathroom | Nenhuma Casa Sem Banheiro',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Canoas, Rio Grande do Sul', 'Brazil',
    NULL, NULL,
    'The project aims to meet basic sanitation needs related to water use, hygiene and proper disposal of sewage by building sanitary facilities in households where there are no or inadequate toilets.', 'In the midst of the Covid 19 pandemic, the Council of Architects conceived the "No Home without a Bathroom" project to mobilize public authorities around the urgent need for investment in household sanitation. The inter-institutional cooperation between institutions of public interest, governments and institutions of architects supported the implementation of the initiative and some emergency actions to reduce the sanitation deficit in 11 thousand houses in Rio Grande do Sul (IBGE, 2012). To date, 458 families have benefited from the initiative.', 'The main purpose of the project is to improve inequitable access to public goods and services and adequate housing, and to bring about resolutions on essential health measures necessary to ensure the lives of the population and future generations (SDGs 3, 10, 11, 16). The project also promotes reducing the impact on access to water in times of drought or flooding through the construction of water storage facilities and the proper disposal of household sewage (SDGs 6, 13). Finally, the Architects'' Council has offered courses for municipal managers and technicians to promote knowledge sharing on the means to implement housing programs in Brazilian cities (SDG 17).',
    TRUE,
    'LDP37', 'Council of Architecture and Urbanism of Rio Grande do Sul (CAU/RS), Association of Architects and Engineer of Canoas (SEACA), State Department of Housing (SOP/RS), Municipality of Canoas, Secretary of Urban Development and Housing (SMDUH).', NULL, NULL
);

-- Row 35: LDP61
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
