) VALUES (
    'Ubuntu Arquitetura', 'Vitor Daher', 'daher.arquitetura@gmail.com', 'SL House',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Valinhos', 'Brasil',
    NULL, NULL,
    'Casa SL is a single-family dwelling built with prefabricated materials and designed to embrace the sun, wind, light and surroundings through passive bioclimatic design.', 'The design of the SL house has been thought out so that it can interact in the best possible way with the terrain and its landscape.
The social area (ground floor) explores more intensely the relationship with the terrain, while the intimate area (first floor) creates a more intense visual relationship with the landscape and is oriented according to the position of the sun. 
The rotation between the two blocks emerges as a result of the strategies adopted and creates spaces for conviviality and contemplation.', '6-Capture and use of rainwater for irrigation and cleaning.
6- Low-flow faucets, showerheads, and toilets to achieve water savings.
7- 100% of the energy used by all structures on the property (2 houses, leisure pavilion, swimming pool, vegetable garden and workers house) is produced by solar panels on the roof of the SL house.
8- Hiring local labour.
9- Production and use of prefabricated parts reducing rubbish and increasing the efficiency of production.
10- Passive bioclimatic design allowing the House to stay between 19ºC and 24ºC without the use of air conditioning.',
    TRUE,
    'LDP61', 'Vitor Daher, Pablo Mauleon', 600.0, NULL
);

-- Row 36: LDP73
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Prefeitura Municipal de Sobral; Hidrobotânica Ambiental.', 'Yvo Gabriel Sousa Galvão', 'yvogalvao@sobral.ce.gov.br', 'Pajeú Filtering Gardens',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Sobral', 'Brazil',
    NULL, NULL,
    'The gardens benefit the aquatic ecosystem and the quality of life of citizens residing around the area by improving water quality in addition to landscaping the Pajeú Park.', 'Considered the largest built in public areas in Brazil, the Biofiltering Gardens of Pajeú Park have 1.19 km of linear gardens, totaling 12,000 m², acting as a natural set of sewage treatment through aquatic plants and substrates, without using chemical products, through a system of natural and constructed wetlands, operating by gravity, promoting the local fauna and flora, in addition to cleaning up the Pajeú creek and Lagoa da Fazenda.', 'In addition to the main objective of improving water quality and subsequent depollution of Riacho Pajeú and Lagoa da Fazenda using Nature-Based Solutions (NBS), the project included the urbanization of the surroundings of the stream, providing a safe, inclusive, public space accessible and green while strengthening resilience and climate adaptation capacity, restoring a formerly degraded area, reducing the effects of droughts, floods and loss of biodiversity in Pajeú Park.',
    TRUE,
    'LDP73', 'Bruno Ary Ferreira; Úrsula Priscyla Santana Nóbrega.', NULL, NULL
);

-- Row 37: IFF34
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Universidad de Guadalajara/ Laboratorio Nacional de Vivienda y Comunidades Sustentables.', 'Fernando Córdova Canela', 'fernando.cordova@cuaad.udg.mx', 'Ecotechnological Center for Innovation, Dialogue and Learning for Sustainable Habitat (CEIDAHS in Spanish)',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Guadalajara', 'México',
    NULL, NULL,
    'Ecotechnological Center for Innovation, Dialogue and Learning for Sustainable Habitat (CEIDAHS in Spanish) will be a space for society, together with technicians and specialists, to plan, manage and carry out innovation projects to improve their living conditions and become involved in the decision-making processes together with other actors.', 'The CEIDAHS project is designed so that different actors related to habitat management can dialogue, learn, and collaboratively generate knowledge on eco-technologies; bioclimate; participatory governance methodologies; development of public policy instruments in housing and innovation; incubation and strengthening of social entrepreneurship; and technological tools related to industry 2.0. The CEIDAHS aims to contribute in the medium and long term to overcoming social backwardness, territorial inequities, and inequalities in fair access to habitat through forms of public action that consider the systemic dimension of the problems in line with the SDGs. The building will have green spaces designed to generate hygrothermal comfort for users, green roofs for experimenting with urban agriculture, solar chimneys, and passive air conditioning. This design will reduce the use of artificial air conditioning by 45%.', 'SDG 7. The formation of new technological development and energy efficiency practices can improve the quality and affordability of housing. In turn, socio-technical transitions and the application of knowledge in the domestic and neighborhood environment in relation to bioclimatic building materials and accessible eco-technology will help reduce the consumption of fossil fuels and promote energy savings.The CEIDAHS constitutes this space for dialogue between different actors to learn, analyze and apply eco-technologies at the household and neighborhood scale.
SDG 11. Inclusive urbanization requires increasing the capacity for action and planning from the communities in conjunction with the actors who manage and study the territory through knowledgeable dialogue. CEIDAHS as a meeting and learning space will enhance the collaboration of different actors in the development of new policies, processes, and actions that promote energy efficiency, renewable energy production, and waste management to significantly reduce the environmental footprint of cities.',
    TRUE,
    'IFF34', 'Fernando Córdova Canela, Hiram Eduardo Urías Barrera, Carlos Emmanuel Aguilar Méndez, Abril Casas Cervantes, Belén Olaya García', NULL, NULL
);

-- Row 38: LDP18
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SUP Atelier of THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'Xuhui Demonstrative Project',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Beijing', 'China',
    NULL, NULL,
    'Located in Xuhui No.26 Block in Shunyi District of Beijing, the project was commissioned by Xuhui Group to create a small-scale sharing space in a leisure park. Powered by the sharing economy in vogue, the space can be booked by residents through an intelligence system. Moreover, through collaboration with BREEAM system in UK and LEED system in the US, the project serves as a zero-energy consumption demonstrative project in cold areas of North China, aiming to reduce energy consumption, improve thermal comfort, and promote sustainability through theme activities of mitigating the increasingly severe environmental problems.

Main structures of prefabricated timberwork and louvers of prefabricated carbonized wood correspond to the zero-carbon concept from perspectives of materials and construction. Architectural elements of the 3 units were classified into various groups of standardized modules with green technology. Through modification and combination, these modules can adapt to various spaces and facilitate comparative studies and promotion of sustainable technologies.
 
The buildings are equipped with intelligence control systems. Through real-time monitoring of the environmental indicators (temperature, humidity, illumination, CO2, PM 2.5, infrared rays)， the energy system can be controlled automatically to save energy and reduce emission. The public can view the real-time indicators, too.', 'Located in Xuhui No.26 Block in Shunyi District of Beijing, the project was commissioned by Xuhui Group’s Beijing office to create a small-scale sharing space in a leisure park. Powered by the sharing economy in vogue, the space can be booked by residents through an intelligence system. Moreover, through collaboration with BREEAM system in UK and LEED system in the US, the project serves as a zero-energy consumption demonstrative project in cold areas of North China, aiming to reduce energy consumption, improve thermal comfort, and promote sustainability through theme activities of mitigating the increasingly severe environmental problems. 

 The project borders a community playground on the south. Unlike the centralized layout often seen in sustainable projects, the main building consists of 3 similar units that are scattered among trees as small-scaled landscape buildings: a fitness center, a lounge and a book cafe (doubling as a showroom of popular science), which can be operated separately. The 3 units center on a sunken courtyard paved with permeable gravel. Users can enter this small building cluster via a wooden walkway through the rain garden. The overhead wooden walkway and the pipe trenches underneath connects the 3 units with a half-earthed energy & smart control center, forming a “3 driven by 1” mode. 

Main structures of prefabricated timberwork and louvers of prefabricated carbonized wood correspond to the zero-carbon concept from perspectives of materials and construction. Architectural elements of the 3 units were classified into various groups of standardized modules with green technology. Through modification and combination, these modules can adapt to various spaces and facilitate comparative studies and promotion of sustainable technologies.
 
As an experimental platform for prefabricated buildings with zero energy consumption, the project has established an integrated mechanism of “design-construction-test-feedback” process. With the help of information technology, the analysis of sustainable indicators can bring forth implementation methods, which can fit in newly built and renovated buildings in cold areas, or serve as prototypes in both public and housing projects. 

This project is located in a cold area, where heating and cooling energy consumption are both huge. High-performance envelopes with thermal indicators greatly outperforming the minimum code. Passive design strategies, such as projected roofs with air-ducting devices and composite façades with photovoltaic double glazing and prefabricated double-layered wooden envelope, which can boost natural ventilation. 

The applications of renewable energy include film glass, photovoltaic power generation, and a hybrid heating system powered by both solar thermal power and air-source heat pump. Sustainable drainage strategies have been integrated into the landscape, too: Green roofs and a permeable courtyard can purify and retain rainwater. 

The buildings are equipped with intelligence control systems. Through real-time monitoring of the environmental indicators (temperature, humidity, illumination, CO2, PM 2.5, infrared rays)， the energy system can be controlled automatically to save energy and reduce emission. The public can view the real-time indicators, too.', 'SDGs 3: Ensure healthy lives and promote well-being for all at all ages
Connection: The project was to create a small-scale sharing space in a leisure park. 
The main building consists of 3 similar units that are scattered among trees as small-scaled landscape buildings: a fitness center, a lounge and a book cafe (doubling as a showroom of popular science), which can be operated separately. Powered by the sharing economy in vogue, the space can be booked by residents through an intelligence system.

SDGs 6: Ensure availability and sustainable management of water and sanitation for all
Connection: The 3 units center on a sunken courtyard paved with permeable gravel. The overhead wooden walkway and the pipe trenches underneath connects the 3 units with a half-earthed energy & smart control center, forming a “3 driven by 1” mode. Sustainable drainage strategies have been integrated into the landscape too: Green roofs and a permeable courtyard can purify and retain rainwater.

SDGs 7: Ensure access to affordable, reliable, sustainable and modern energy for all
Connection: The applications of renewable energy include film glass, photovoltaic power generation, and a hybrid heating system powered by both solar thermal power and air-source heat pump.
The buildings are equipped with intelligence control systems. Through real-time monitoring of the environmental indicators (temperature, humidity, illumination, CO2, PM 2.5, infrared rays)， the energy system can be controlled automatically to save energy and reduce emission. The public can view the real-time indicators, too.

SDGs 13: Take urgent action to combat climate change and its impacts
Connection: Main structures of prefabricated timberwork and louvers of prefabricated carbonized wood correspond to the zero-carbon concept from perspectives of materials and construction. Architectural elements of the 3 units were classified into various groups of standardized modules with green technology. Through modification and combination, these modules can adapt to various spaces and facilitate comparative studies and promotion of sustainable technologies.
This project is located in a cold area, where heating and cooling energy consumption are both huge. High-performance envelopes with thermal indicators greatly outperforming the minimum code. Passive design strategies, such as projected roofs with air-ducting devices and composite façades with photovoltaic double glazing and prefabricated double-layered wooden envelope, which can boost natural ventilation. 
As an experimental platform for prefabricated buildings with zero energy consumption, the project has established an integrated mechanism of “design-construction-test-feedback” process. With the help of information technology, the analysis of sustainable indicators can bring forth implementation methods, which can fit in newly built and renovated buildings in cold areas, or serve as prototypes in both public and housing projects.',
    TRUE,
    'LDP18', 'Yehao Song , Xiaojuan Chen, Dan Xie, Zhenghao Lin', 157.0, NULL
);

