    'SUP Atelier of THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'The indoor playground of the rural middle school',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Yueyang County, Hunan Province', 'China',
    NULL, NULL,
    'Located in central rural China, the project creates an indoor playground and lecture hall with natural ventilation and natural lighting, and invigorates the regularly planned campus.', 'Located in central rural China, the project accommodates an indoor playground and lecture hall and invigorates the regularly planned campus. The building stretches across the altitude of the site with the main space at the higher part and service room at the lower part. Natural ventilation and lighting serve as major sustainable strategies to improve thermal comfort. Prefabricated materials and construction methods are chosen to reduce the cost of equipment and maintenance of the project.', 'The project is being used as a shared teaching facility for villagers and students to reduce poverty, improve education quality and creates sustainable communities. It retains the trees of the current land, uses recyclable and prefabricated materials for construction, and integrate innovative passive design strategy to reduce construction cost and energy consumptions. The color puzzle façade design originates from the local lake and popularizes the concept of sustainable architecture in daily use.',
    TRUE,
    'LDP19', 'Yehao Song, Xiaojuan Chen, Dan Xie, Jingfen Sun, Suritu Bai, Yingnan Chu, Dongchen Han, Haowei Yu.', NULL, NULL
);

-- Row 40: LDP22
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SUP Atelier of THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'Gaobeidian Railway City sustainable demonstration pavilion',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Gaobeidian City, Hebei Province', 'China',
    NULL, NULL,
    'The project is an exhibition pavilion with passive house certification, within which the sustainable architecture strategies and the edge-cutting building techniques could be introduced to the public.', 'The pavilion is targeted at PHI standard combined with sustainable strategies and architectural interests of the team. The basic prototype is made of two wedges, an atrium inserted into the main body improving interior ventilation and a terraced atrium connecting exterior and interior. The north side is sheltered with earth merging into landscape, highly reducing the thermal losses. The curtain wall on south side works as a solar collector in winter and helps to prevent interior from overheat with an automatic sun-shading system. As for landscape, traditional Chinese garden features are adopted to create interesting experience outdoors.', 'The project aims to create a healthy, comfortable and eco-friendly nZEB building using passive strategies and active strategies and introduce a low-carbon lifestyle to the public. The project is also an experimental platform for scientific research-practice linkage to promote the development of sustainable building, cultivating high-quality contractors and workers, practicing design strategies and edge-cutting techniques and laying the foundation of carbon neutrality. During the whole process of the project, female participants play important roles in each decision-making process.',
    TRUE,
    'LDP22', 'Yehao Song, Jingfen Sun, Dan Xie, Yingnan Chu, Xiaojuan Chen, Dongchen Han, Zhenghao Lin', 1400.0, NULL
);

-- Row 41: LDP62
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
