    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Architectural Society of China', 'Yehao Song', 'sup_atelier@supatelier.com', 'THE-Studio (Tsinghua Eco Studio)',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Guian New Area, Guizhou province', 'China',
    NULL, NULL,
    'THE-Studio(Tsinghua Eco Studio) is both a practical demonstration case which deeply integrates sustainable design strategies with ecological technologies,and an experimental platform for sustainable, aiming to building technologies can truly suit to the local conditions of climate and culture.', 'In THE-Studio timber frameworks are employed in the large-space exhibition hall and the prefab light-steel modules are used to at both sides. Sustainable service systems are mostly plugged into the cavity of facades.The modular double-skin facade system is a unique integration of vernacular rattan-weaving craftsmanship with industrial prefabrication technology,highly expressing site-specific characteristics.
The passive design methods responding to local climatic factors of natural wind,solar radiation and daylight are further contrived by the design team.The design team highly encourages usage of renewable materials and promote the employment of vernacular materials and craftsmanship which can decrease the carbon footprint during .', 'THE-Studio can provide a high-quality research space for both men and women to enhance their professional competence.The design team placed great emphasis on passive design strategies that respond to local climate factors.First,the double-skin facades consisting of double-glazed and the rattan-weaving double skin are typical climate responsive design.Second,the use of renewable energy has greatly reduced the waste generation.Building adopts the passive air-conditioning system.It also combines Rainwater recycling and ecological landscape together.Using renewable materials can both decrease the carbon footprint during whole life span.In the construction process,the design team mobilized the local people,provided a large number of jobs,and brought opportunities and development to the industry.In the future,local people can replace the rattan weaving on the facade by themselves.',
    TRUE,
    'LDP62', 'Song Yehao,  Sun Jingfen,  Chen Xiaojuan,  Lin Zhenghao, Han Dongchen, Xie Dan', 701.0, NULL
);

-- Row 42: LDP8
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Juri Troy Architects', 'Prof. Arch. Mag. Juri Troy', 'office@juritroy.at', 'VELUX Sunlighthouse',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Pressbaum/Vienna', 'Austria',
    NULL, NULL,
    'The Sunlighthouse is the first CO²-neutral single-family-house in Austria. The challenge was to develop an energy and ecological concept that would eliminate the ecological footprint for the next thirty years.', 'The building equipment includes a high performing heat pump, 48 m² mono crystalline photovoltaic roof panels, 9 m² thermal solar panels for hot water and a controlled air system with heat recovery. The roof and facade windows were strategically positioned to maximize passive solar energy, to enable optimal, natural ventilation during summer and to minimize the thermal losses during winter. The Sunlighthouse will produce more energy than the construction as well as the usage of the house consumes.', 'Our team took the big challenge to create a house that will produce more energy in 30 years than it will need for building, transport, heating and electrical use all together. That means that after this period it will produce even more energy as it ever consumed and will therefore be some kind of a small power station. We also focused on the use of new well performed materials that need very few ore non CO² to be produced.',
    TRUE,
    'LDP8', 'Prof. Arch. Mag. Juri Troy, DI Matthias Hein', NULL, NULL
);

-- Row 43: IFF48
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'ESTIDAMA Center', 'Mohammad Fahmy', 'md.fahmy2013@gmail.com', 'THE NEO-ARID CITY',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Egypt cities; Aga, New Atfeh, New Obour', 'New Cairo',
    NULL, NULL,
    'An Urban-Building Climate-Economy 5th Generation Responsive City Movement Paradigm. Please view the Neo-Arid City report pdf file from here:
https://drive.google.com/file/d/199D4Vg2JvdAnGnMt53rnkaxS4Fwqnuqw/view', 'Present global challenges, urge to anticipate the coming WWIII with low-tech but preserved city image. Neo-Arid city, a 5th generation city emerged by coupling Urban-Building design with Climate-Economy responses at four sites in Egypt, combines semi-compact pattern with court-yarded clustered low-cost microclimatic housing and neighborhood PV roofs. The recipe of getting back to arid free planning heritage values retrieved sustainability while regenerating a future city image consistent theory.', 'Climate Action (SDG13) has to be targeted with integrated bundle of SDGs’ strategies. Neo-arid city form design with whole roofs micro-climatically oriented acting as an Affordable and Clean Energy (SDG7) bank, and low-cost eco-friendly compressed earth bearing walls both support green urban economy for locals (SDG8) and Sustainable Cities and Communities (SDG11) via the court-yarded clustered neighborhoods that improve thermal comfort, reduce heat gain, energy consumption and carbon emissions.',
    TRUE,
    'IFF48', 'Mohammad Fahmy', NULL, NULL
);

-- Row 44: LDP24
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Natureza Urbana', 'Breno Pilot', 'breno@naturezaurbana.net', 'Terminal and Urban Park in São Luís',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'São Luís', 'Brazil',
    NULL, NULL,
    'The project promoted the renovation of an area, focusing on a new park and bus terminal. The Natureza Urbana office imagined new ways of thinking public spaces in an area full of social inequality.', 'The project comprises a strip from Avenida Vitorino Freire to the Bus Terminal, which is part of the Ring Road around the Old Center. The reorganization of the square and the bus terminal promotes better distribution of commercial points and the elimination of existing physical and visual barriers. The redesign of the space creates small squares with equipment and urban furniture, promoting ideal conditions for the creation of a vibrant public space.', 'Throughout the project’s development, society and public organizations were involved through participatory processes and workshops. Social surveys and analysis of the pre-existing situation of merchants were carried out, with the aim of developing a proposal that would embrace all local demands and needs. The social surveys directed the location of the commercial points, their typologies, training for merchants and the ways of acting and appropriating the public space.',
    TRUE,
    'LDP24', 'Manoela Machado e Pedro Lira (Coordination); Camila Reis e Camila Sanches (Project Leaders); Jalia Marini, Juliana Yoshida, Juliette Tellier, Renata Peres, Raquel Araruna, Renan Ferreira, Roberto Zocchio e Fernando Botton (team).', NULL, NULL
);

-- Row 45: LDP27
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SUP ATELIER OF THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'Tea Leaf Market of Zhuguanlong',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Fujian Province', 'China',
    NULL, NULL,
    'Zhuguanlong Township of Shouning County, Ningde City of Fujian Province, where the Tea Leaf Market is located, is a township fertile in tea leaf yet to be lifted out of poverty at the time of the project’s planning phase. Zhuguanlong Tea Leaf Market featured a multi-functional tea leaf market, aiming for a boost in tea leaf economy and better public spaces for local people..

A large-span space was proposed for various functions at different times of the year based on earlier bamboo construction experience, fundamental functions of the market and other demands by the public. Apart from seasonal tea leaf trading, the market can be used for farm product trading, villagers’ short stay and children’s sports activities. On special occasions such as weddings and funerals, people can also gather under the market’s roof for a feast. 

The project‘s structural form inspired by a sort of traditional woven arch structure built with local raw bamboo. Locally obtained natural materials and recycled building materials such as soil, wood and stone were all used for construction, motivating local craftsmen to wisely “turn wastes into treasures” with refined local building technologies, presenting a well-utilized public building to the villagers.', 'Zhuguanlong Township of Shouning County, Ningde City of Fujian Province, is a township fertile of tea leaf yet to be lifted out of poverty at the time of the project’s planning phase. A multi-purpose large-span space was proposed as a tea market in the town. Apart from seasonal tea leaf trading, the market can be used for farm product trading, villagers’ short stay and children’s sports activities. On special occasions such as weddings, funerals and the local beggar festival, people can also gather under the market’s roof for a feast. 

The design team thoroughly studied building technologies of “rainbow bridge”, a sort of traditional wooden arch bridge achieved with ancient people’s wisdom, searching for solutions. The team found that the shelters could both be built with simple traditional building methods as the rainbow bridge with refined bamboo construction technologies. Finally, through craftsmen’s simple processing of raw bamboo, which Zhuguanlong township was richly endowed with, a woven bamboo structure with an 18-meter span was completed

The project built with locally obtained and recycled materials, which is people-centered, low-carbon and innovative. The design team thoroughly studied the possibility of recycling local materials. Field study showed that red soil on site was frequently used on local rammed-earth walls; bamboo woods prosper in mountainous lands along the site; dilapidated houses, which were being demolished at that time, could provide rubble from wall foundations and wood pieces from pillars and beams. As a result, recycled rubbles were used on newly built walls, while red soil on site was rammed into walls by local craftsmen; moso bamboo, through anti-corrosion treatment by the bamboo contractor, was assembled into large-span structures; recycled wood pieces was processed into wooden couches or wood bricks within rammed-earth walls. 

The design team also visited a stone processing factory to collect stone leftovers from processing, which were later cut into smaller pieces on both exterior and interior pavement. Those recycled materials, usually seen as wastes and thus coming at very low costs, were re-utilized by local villagers and craftsmen and extended their life in a new place, bearing our respect for people’s wisdom and labor. 

Zhuguanlong Tea Leaf Market is one project of the team’s series of sustainable practices and can be viewed as sustainable from environmental, social and economic perspectives. 
To achieve environmental sustainability, the project was built with locally obtained and recycled materials with low innate carbon footprint. Besides, it has made full use of natural ventilation, daylighting and rain-water landscapes, achieving harmony with surrounding natural lands. 

To achieve economic sustainability, the planning of the project was established under the premise of boosting local agricultural economy, enriching daily life in the community and involving local people in construction to make profits for their families. To achieve social sustainability, the market was positioned as a space of the people, by the people and for the people. Besides, through the use of local materials and refined traditional building technologies, local features were showcased throughout the building, celebrating the township’s unique culture and history.', 'Goal 1: No Poverty (1.3 1.4)
The project was built to equal the local Tea leaf trade economy resources, provide the villagers with a quality public space for sharing business opportunities instead of decentralized tealeaf transaction.

Goal 2: Zero Hunger (2.3)
The small scale vegetable farmers has raised their incomes. The Market provides them a better place and chance to sell their products.

Goal 3: Good Health and Well-being (3.3)
An open roof could boost natural ventilation and daylighting, reducing operational costs. Against COVID-19 pandemic, it could be used for pandemic prevention coordination, nucleic tests and medical observation.
 
Goal 4: Quality Education (4.7) 
The project sometimes serves as a community school for villagers.

Goal 5: Gender Equality (5.5) 
The township head is a lady, who participated in decision-making of the project. 30%-40% architects, engineer, artisan, who involved in this project are women.   

Goal 6: Clean Water and Sanitation (6.6)
The rainwater drainages are well organized and all rainwater above the roof were imported either to the Greenland or to the canal to mountain stream.    

Goal 7: Affordable and Clean Energy (7.3)
The design has made full use of sunlight for indoor lighting and natural ventilation in summer for better environment. The passive strategies save lots of energy consumption, use the minimum energy consumption lights up 500sqm.

Goal 8: Decent Work and Economic Growth (8.1 8.8 8.9)
The project improves the tealeaf trade, makes the local economic growth, promotes safe and healthy working environment for tea famers. The iconic architectural design enhances the local tourism popularity.  

Goal 9: Industry, Innovation and Infrastructure (9.2 9.B)
The project encourages the bamboo construction industry, the local rammed earth construction industry, which are the sustainable industrialization. The special bamboo construction technology is distinctive and domestic.

Goal 10: Reducing Inequality (10.1 10.2)
The market is an open space for all tea farmers to share the trade information and resources, to reduce the income inequalities. It’s also a covered square, where the community activities, public meetings, discussions, could be held to promote universal social, economic and political inclusion.  

Goal 11: Sustainable Cities and Communities (11.C 11.4 11.6)
The project is constructed by the local people with recycled materials, local technologies, so the cost is extremely affordable. Bamboo and rammed earth are local materials. The rest construction materials such as rubble and woods from the demolished ruins, roadside abandoned slates, and waste from stone factory, are recycled near the site. They are processed and reused in the project. The construction technologies such as Woven bridge technology is listed in the UNESCO’s Intangible cultural heritage, and the rammed earth technology is learned from the World Cultural Heritage Tulou building. These construction strategies with recycled and local materials, with vernacular technologies and by the local craftsmen, support the least developed area in sustainable and resilient building.

Goal 12: Responsible Consumption and Production (12.2 12.5 12.8)
The main materials of the project are bamboo and rammed earth from natural resources, which could be get from the surroundings environment easily. The recycled materials are appropriate used in the project, reduced the waste generation, and universal understanding of sustainable lifestyles.

Goal 13: Climate Action (13.3)
The project are built by the biodegradable low-carbon material such as bamboo and earth, in low-carbon maintenance and operation. It’s a good case for the public to build knowledge and capacity, that natural material construction could be a solution for climate change.

Goal 16: Peace, Justice and Strong Institutions (16.7)
This project is a results of democratic decision-making. The bamboo roof construction is supported by local villagers and governments. Using the recycled materials were proposed by villagers and supported and approved by architects and local craftsmen, The Multi-functional mode of use are suggested by local residents. 

Goal 17: Partnerships for the Goals (17.1 17.6 17.9)
The project served as tealeaf market, which brings more trade resources and popular tourist scenic spot, brings more local income and benefits, also more revenue collections for the township. During the whole process, the Design team from the best University in China had a chance to lean and share the traditional woven arch bridge technology, rammed earth technology from local, and innovative improve those technology to make them used in modern construction. The Knowledge sharing and cooperation between local craftsmen and scholars and engineers from university, made the special construction innovation.  
The whole project proved, that with the appropriate method, Appropriate technology, natural resources, the SDG capacity in developing countries could be enhanced and distinctive.',
    TRUE,
    'LDP27', 'Yehao Song, Jingfen Sun, Yingnan Chu，Wenwu Wang，Mengjia Liu，Xinran He，Dan Xie，Xiaojuan Chen', 460.0, NULL
);

-- Row 46: LDP45
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Manasaram Architects', 'Ar. Neelam Manjunath', 'mansarch@gmail.com', 'Bamboo Symphony',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Bengaluru', 'India',
    NULL, NULL,
    'Bamboo Symphony, the office of Manasaram Architects is a beacon for a new era of office design. The building embodies the core principles of the firm being a zero energy sustainably built development.', 'Wrapping around the RWH pond spread across multiple levels the open office layout fosters collaboration. The structural system was developed by experimentation, research and working on site with artisans and employing vernacular knowledge. Illustrating use of Bamboo Reinforced Concrete, & slant bamboo columns, the project showcases Bamboo as a 21st CE construction material. Protected yet open to the exteriors the office is well ventilated, & cooler employing bio-climatic design to its fullest.', 'SDG 8:The built work is a beacon for collaborative invigorating workplaces.
SDG 9(9.5 & 9.b):The project was constructed upon research into local knowledge & serves as a beacon in the context of developing countries.
SDG 11(11.a):Ventilation, daylight, RWH & closed loop systems, the project promotes sustainable communities.
SDG 12(12.2, 12.7, 12.8 & 12.a):Using leftover materials & employing bamboo as the primary structural material, this design illustrates the practice of responsible construction.',
    TRUE,
    'LDP45', 'PRINCIPAL ARCHITECT: Ar. Neelam Manjunath  TEAM: Ar. Sanjita Harwalker   CHIEF MASON: Gopal Prasad Tanti  BAMBOO ARTISAN:Anand Lal Marandi  Consultants:  Building material & Technology             – Center for Green Building Material & Technology, Bangalore. Rainwater Harvesting                            – Prof. A.R.Shivkumar, IISc, Bangalore. Waste Water Treatment                        – CDD Society, DEWATs, Bangalore. Compressed Stabilized Earth Blocks    – Dr.Yogananda, Mrinmayee, Bangalore.', 210.0, NULL
);

-- Row 47: LDP70
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Tunisian Order of Architects', 'Adel Hidar', 'adel.hidar@gmail.com', 'Oil mill & cannery of Segermès - Zaghouan / Tunisia',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Zaghouan / Tunisia', 'Unknown',
    NULL, NULL,
    'The oil mill & cannery project is a concept fully integrated into the site, from picking to bottling and labeling. It’s also an attempt to rehabilitate a fringe of territory by infusing new productive energy. An energy that creates values, jobs and well-being.
Respecting the waxworks of organic farming, the olive growing complex now allows the production of very high-quality organic olive oil following a process fully integrated into the site. It employs around 100 men and women during the production phases. Modern technologies allow the use of local resources and place sustainability at the heart of all agricultural and business activities.
Olive cultivation plays an essential role in the social and economic life of Tunisia and represents around 15% of the total value of final agricultural production. In addition, the olive sector represents the direct or indirect livelihood of more than 1 million people.
Rural Tunisian women participate very actively in the picking of olive trees; these jobs, although seasonal, provide rural families with very appreciable annual income which generally contributes to financing children''s education ...
Today, agricultural products from the Segermès estate stand out for their high quality both on the Tunisian market and internationally. Rewarded with numerous distinctions on a worldwide scale.', 'Route & confluence: The establishment of the project emanates from a territorial position. The chosen location maintains a privileged dialogue with a water reservoir as well as a basilica from the Byzantine period. The project is part of the logic of a confluence, an emergence built by the directional multiplicity of the natural and “civilizational” components of this unique place.
A historical past: The foundations of the new building are nourished by the historical roots of the place whose Byzantine remains remain. The ground floor opens onto the landscape and overlooks the old basilica through the presence of a Forum which becomes a semi-public space for meetings and contemplation. The staging of the archaeological remains also helps to revive the historical past of the region which was previously abandoned.
The olive tree at the heart of the process: The architecture of the oil mill, resulting from the framework of the olive grove, also tells the story of the extraction process. The oil is kept in the center of the building and the volume of the silos thus constitutes a link between the two levels of the new building.', '1. End poverty in all its forms everywhere
In Tunisia, regional disparities, particularly those between the center of the country and the Mediterranean coasts, represent the essence of social inequalities. The development of agricultural areas neglected by the country''s youth is the only way to curb the rural exodus and illegal immigration to Europe. In this sense, our project represents a brake on poverty and inequalities of opportunity.

2. End hunger, achieve food security and improved nutrition and promote sustainable agriculture
The production of premium quality organic olive oil is mainly for export to the whole world. The income generated by this fair trade, insofar as it also benefits rural families living in the region, makes it possible to feed the interior regions of the country. Encouragement from the Tunisian government for the labeling of organic olive oil has made it possible to develop sustainable agriculture.

5. Achieve gender equality and empower all women and girls
Olive growing traditionally represents an annual income for rural women in Tunisia. Generally this pension is intended to finance the studies of a child and represents the hope of a better future for many needy families. Although the empowerment of women and girls is still far from being achieved in the rural world, the olive tree and its crops have always been a vector of hope and a major asset for female emancipation.

8. Promote sustained, inclusive and sustainable economic growth, full and productive employment and decent work for all
The fact of combining the functions of an oil mill with those of a cannery has made it possible to offer employment positions throughout the year. Indeed, the olive-growing activity in itself was not enough to guarantee full employment for agricultural workers in the region. The new building which houses these two combined functions is described as the “castle of the olive tree” by its employees, who find there all the conveniences of a dignified job in fair working conditions.

9. Build resilient infrastructure, promote inclusive and sustainable industrialization and foster innovation
The creation of a fully autonomous and integrated infrastructure for the production of olive oil and certain derived agricultural products is a first in Tunisia. This concept of “bottling at the château” is borrowed from the “Appellations d’Origines Contrôlées (A.O.C)” which exist in the economic models of the northern Mediterranean. Typically, processed agricultural products are produced off-site in polluting industrial areas on the outskirts of major cities. The resilience of this project comes mainly from its geographical location and its mixed program.

10. Reduce inequality within and among countries
The project aims to ensure stable and decent jobs in the interior regions of the country. It therefore reduces inequalities and curbs rural exodus and irregular immigration to the northern Mediterranean.

12. Ensure sustainable consumption and production patterns
Organic olive growing sets in motion a whole series of eco-sustainable parameters in its production. Part of the energy is provided by the combustion of the pomace and the vegetable water is recycled for the manufacture of by-products. Moreover, the consumption of olive oil, whose health benefits are well established, is an integral part of Tunisian culinary traditions.

13. Take urgent action to combat climate change and its impacts*
An ecological architecture mainly based on local materials and resources combined with a programmatic study to ensure full employment for the inhabitants of the region are assets that contribute in their scales to these great ambitions for humanity...

15. Protect, restore and promote sustainable use of terrestrial ecosystems, sustainably manage forests, combat desertification, and halt and reverse land degradation and halt biodiversity loss
Our integrated agricultural project uses local resources: plantations of olive groves from Roman times, reverse osmosis water from a well from Roman times, natural fertilizers from farms in the region... Its sustainability depends directly on the preservation resources that surround it and that allow its existence. We believe that this type of equations is good for the balance and preservation of ecosystems.

17. Strengthen the means of implementation and revitalize the global partnership for sustainable development
The production of high-quality organic olive oil in Tunisia makes it possible to compete with Italian and Spanish producers. The economic balance generated in recent years by the major Tunisian labels helps to reduce the disparities between the north and the south. Today, Tunisia is beginning to regain a leading position in the production of early olive oil on a global scale. Small steps that can inspire other agricultural sectors that do not have their place on the scale of the Mediterranean and global economy.',
    TRUE,
    'LDP70', 'Adel Hidar - architect', 1485.0, NULL
);

-- Row 48: IFF16
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Natureza Urbana', 'Breno Pilot', 'breno@naturezaurbana.net', 'Lake Jará Urban Park',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Juriti', 'Brazil',
    NULL, NULL,
    'The project aims the development of public use on the banks of the lake, focusing on controlling the advance of the urban spot over its limits and raising the population''s awareness of its relevance.', 'The project''s strategy started with the implementation of an environmental park on a public area, structured in three zones: The Urban Zone, with socio-cultural activities, expands the offer of public spaces in the city. The Connection Zone creates a transition space between the zones, formed by a forest region with the proposition of contemplative uses. In The Lake Zone we proposed uses related to water and ecotourism, in addition to various spaces for contemplation.', 'The concept of the buildings incorporates elements of vernacular, indigenous and riverside architecture. The proposal of a modular structure using local building techniques, enabled the creation of integrated spaces adapted to the natural environment. The work incorporated renewable materials and local techniques, considering the entire life cycle of the building including its use, maintenance and recycling.',
    TRUE,
    'IFF16', 'Pedro Lira (Coordination); Camila Sanches, Giulia Corsi e Victor Navarra (team).', NULL, NULL
);

-- Row 49: IFF42
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    '#1 individual (dead) painter #2: Individual architect', 'Paolo Caroli', 'P.Caroli@archiworld.it', 'the Common Good',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Pisa (PI) - Italia', 'Unknown',
    NULL, NULL,
    'Rules for a sustainable future: an analogy between the 1338AD ‘Allegory of Good and Bad Government’ fresco and the UN 2030AD Agenda', 'ENCYCLOPEDIA GALACTICA*:
“Both the 1338AD fresco called ‘Allegory of the good government’ and the UN 2030AD Agenda, declined into 17 goals, are prehistorical documents showing some attempts to stop or at least curb the destructive drift of the terrestrial society before its own collapse.”

* All quotations from the Encyclopedia Galactica here reproduced are taken from the 116th Edition published in 1020 F.E. by the Encyclopedia Galactica Publishing Co., Terminus, with permission of the publishers.', 'Most of the human needs can be satisfied only by living in Communities. With the growth (read globalization) of its dimensions, we forgot that the very base of a Community is the shared concept of Common Good.
The ‘Allegory’ anticipates and includes all the SDGs (as indicated in the attached images), and shows how they were ruled in the small but organized Siena around the 1338AD.
The city itself, with all his private and public architectures, is a common good as the house of the Community.',
    TRUE,
    'IFF42', '#1 Ambrogio Lorenzetti #2 Paolo Caroli', NULL, NULL
);

-- Row 50: LDP14
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Oualalou+Choi', 'Oualalou+Choi', 'info@oualalouchoi.com', 'Pavilion for the Kingdom of Morocco at EXPO 2020 Dubai',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Dubaï / United Arab States', 'Unknown',
    NULL, NULL,
    'The Morocco Pavilion at the 2021 Expo in Dubai showcases how traditional Moroccan design and construction techniques can find new relevance in contemporary design and urban development efforts.', 'The Pavilion’s exterior envelope is composed of a 4000 m², 33 m high rammed earth facade, an ambitious technical feat pioneering in its advancement of rammed earth construction methods. Rammed earth, a traditional building material in Morocco, plays a key role in passively regulating indoor conditions in hot and arid places. Its use in the Pavilion proves that it is a material at once traditional and innovative, offering an example of how such building methods can serve to inspire more sustainable models of urban development.', 'The Pavilion’s 34-meter-high rammed earth façade is an ambitious technical feat pioneering in its advancement of rammed earth construction methods. Rammed earth, a traditional building material in Morocco, plays a key role in passively regulating indoor conditions in hot and arid places. To achieve the heights of the Morocco Pavilion’s facade, raw and compacted rammed earth was formed into prefabricated panels coupled with a lightweight concrete frame. Its use in the Pavilion proves that it is a material at once traditional and innovative, offering an example of how traditional building methods can serve to inspire more sustainable models of urban development. 
In line with this commitment to sustainability, after the conclusion of the 2020 Expo, the Pavilion is converted into a housing complex, with existing facilities adapted into apartments and communal spaces.',
    TRUE,
    'LDP14', 'Oualalou+Choi', NULL, NULL
);

-- Row 51: LDP30
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Studio Lotus', 'Harsh Vardhan', 'media@studiolotus.in', 'Krushi Bhawan',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Bhubaneswar', 'India',
    NULL, NULL,
    'Krushi Bhawan is a government facility that transcends the typical closed office campus morphology by integrating governmental functions with direct community engagement and education.', 'Krushi Bhawan engenders community participation with the ground floor designed as a free-flowing public space supporting numerous public functions, including workshops and haats (weekly markets). The terrace features urban farming exhibits and crop samples to educate farmers. The patterned brick façade draws on the region''s famed ikat dyeing techniques and the design integrates passive, low-tech climate mechanisms to limit mechanical air-conditioning to only 20% of the built areas.', 'The project involved over 100 artisans to create a contemporary narrative of traditional Odia craft at an unprecedented architectural scale, promoting craftsmanship and regional scopes of employment. The intervention also demonstrates how public institutions can support regional crafts and sustain the communities built around them. Krushi Bhawan thus seeks to embody the idea of truly inclusive architecture — created for and built by the people and representing their collective cultural identity.',
    TRUE,
    'LDP30', 'Design Team: Ambrish Arora, Sidhartha Talwar, Raman Vig, Sachin Dabas', NULL, NULL
);

-- Row 52: LDP55
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Studio Cardenas Conscious Design', 'Arch. Mauricio Cardenas Laverde', 'm.cardenas@studiocardenas.it', 'Energy Efficient Bamboo House',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Baoxi town', 'China',
    NULL, NULL,
    'Energy Efficient Bamboo House confirms that using natural materials for construction, as bamboo, is the most viable means to reduce embodied carbon in buildings, inspiring new architectural languages.', 'The Energy Efficient Bamboo House, built for the first International Bamboo Architecture Biennale, stands out for its golden proportions and modular design, facilitating assembly of the bamboo canes even by unskilled workers. It is an excellent illustration of BooTech construction system, using mechanically applied joints to connect the bamboo canes. Unlike mainstream approach, which uses cement as a filler, BooTech leaves the cane intact making it possible to replace when needed.', 'Bamboo plant tackles 7 SDGs, using it for construction with a proper technique, as BooTech, offers a truly expendable alternative to the use of polluting steel and concrete, enabling us to rethink architecture in eco-friendly ways, in keeping with the SDGs. Energy Efficient Bamboo House is a resilient architecture that promotes inclusive and sustainable industrialization and sustainable use of terrestrial ecosystems, fosters innovation, combats climate change and can be globally implemented.',
    TRUE,
    'LDP55', 'Arch.Mauricio Cardenas Laverde', NULL, NULL
);

-- Row 53: LDP65
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Casa Cidade Arquitetura e Urbanismo', 'Renata Fragoso Coradin', 'renata.coradin@casacidade.com.br', 'Mata Virgem Urban Park',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'on the border between São Paulo and Diadema / Brazil', 'Unknown',
    NULL, NULL,
    'The Mata Virgem Urban Park consists in the development of new leisure and connective structures with better walking conditions, surrounding a preservation area, which provides well being of the inhabitants', 'The “Mata Virgem” Urban Park is located in a site that ensures environmental preservation between the cities of São Paulo and Diadema. There is an elevated route that surrounds a stream source and connects two areas with 26 meters of level difference, with stairs that provides sights and pleasant walking conditions. On the higher level, there is a deck that extends the sidewalk, creating a belvedere with panoramic view, living areas and public leisure equipment.', 'Located in a socially deficient neighborhood, the “Mata Virgem” Urban Park improves the well-being of the residents of the area qualifying public spaces with leisure structures for all ages and genres. It’s main route is a staircase that connects two cities whilist shortening daily paths, preserving natural conditions and local spring waters. These aspects of the project are aligned with the third of the seventeen sustainable development goals.',
    TRUE,
    'LDP65', 'Renata Fragoso Coradin; Amanda Ramos Silva Santos; Caroline de Souza Moura; Felipe Maike Lima de Souza Oliveira; Giovanna Sambugaro; Ian dos Santos Araújo; Juliana Bizzi Radi de Ponti; Juliana Nunes Watanabe; Letícia Ferreira; Soraya Mayumi Tamate Palmeira de Paula; Suellen Cristina Pivato; Paulo Cássio de Moraes Gonçalves; Guilherme Eduardo Araujo de Souza; Alexandre Horiye Ferreira; Daniela Arduino Dezidera Horiye; Joice Lopes; Elisabete França; Ana Clara Gurgel; Fernanda Souza Silva; Maria Teresa Cardoso Fedeli; Mayra Rodrigues; Vanessa Padiá de Souza', NULL, NULL
);

-- Row 54: IFF17
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
