    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Natureza Urbana', 'Breno Pilot', 'breno@naturezaurbana.net', 'Iguaçu National Park',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Foz do Iguaçu', 'Brazil',
    NULL, NULL,
    'The project is part of the studies for the concession aimed at providing public services to support visitation, modernization, operation, and maintenance of tourist services in Iguaçu National Park.', 'The project included territorial planning of the park''s attraction poles, identifying their vocation and opportunities for enhancing each one. Along with expanding tourism services, new visitor support infrastructure and requalification of existing public use assets and equipment were planned. The main premise was to redefine the park visit experience by providing sustainable interventions for visitors to have greater contact and connection with nature and new experiences.', 'The project guidelines were based on innovation in public use management, accessibility, sustainability, and increased visitation with the motto "park for all". Sustainability was addressed in environmental, cultural, social, and economic aspects, i.e., solutions that go beyond the implementation of sustainable technologies, considering relationships with the surroundings and intervention environment, and seeking to encompass the entire project lifecycle.',
    TRUE,
    'IFF17', 'Pedro Lira and Manoela Machado (Coordination); Camila Sanches (Project Leader), Camila Reis, David Couto, Fernanda Morais, Julia Ximenes and Laura Figueiredo (team).', NULL, NULL
);

-- Row 55: IFF52
