    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'WM Creative Studio - Relab', 'Muhammad Nafeel Qureshi', 'nafeel@wmcreativestudio.com.pk', 'Development Delirium: how architecture nurtures inequality',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Karachi', 'Pakistan',
    NULL, NULL,
    'A Retrofit housing in Gujjarnalla Karachi slums, Pakistan, an equitable and ethical design solutions to negotiate with the existing building/structure/system to improve inhabitants’ life.', 'With more than 55% of the world''s population living in cities, and half of the metropolis citizen lives in informal settlements, it is fundamental to explore design by means of bilateral negotiations and architecture which fulfill citizens’ needs. Retrofit Housing typology is explored based on residents’ needs, cost-effectiveness and encourages communities to rebuild their homes to improve community engagement through design to improve livability.', 'The project will address GOAL 10 & 1 to reduce inequalities and end poverty by improving livability by implementing resilient & safe retrofit housing solution GOAL 11. Further providing school, community center & clinic promoting opportunity to quality education and well-being will satisfy GOAL 4 & 5. Improving the dying need of the neighborhood and city by implementing wetland to improve sanitation and improve city ecology will support GOAL 6.',
    TRUE,
    'IFF52', 'Muhammad Nafeel Qureshi, Wajiha Siddiqui Mehdi, and Muhammad Mehdi', NULL, NULL
);

-- Row 56: IFF56
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'WM Creative Studio - Relab', 'Wajiha Siddiqui', 'wajiha@wmcreativestudio.com.pk', 'The Baitussalam School',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Jacobabad (Sindh)', 'Pakistan',
    NULL, NULL,
    'A primary school in Jacobabad, Pakistan, conceptualized to counter education system vulnerabilities & climate emergencies with sustainable modular design, bamboo framework, and child-centric spaces.', 'It is a reimagining of schools in a significantly challenged education system in Jacobabad, one of the hottest rural regions of Pakistan, which was also severely affected by the catastrophic floods of 2022. The adaptable module comprises two rooms and a courtyard, facilitating integration for flexible indoor/outdoor, formal/informal learning spaces. The school also features a step farm, renewable energy rainwater harvesting /solar energy, and an emergency refuge double roof covered with fabric.', 'This school will address Goal 17 through partnerships with the local community and organizations to create a sustainable and affordable learning environment. It will support Goal 13 by utilizing sustainable construction materials and step farming to promote climate action. Job creation in construction and permaculture will satisfy Goals 8 and 2. Goals 10 and 4 will be supported by reducing inequalities in education and designing secure child-centric learning spaces.',
    TRUE,
    'IFF56', 'Muhammad Mehdi, Wajiha Siddiqui Mehdi, Muhammad Nafeel Qureshi, Nihal Ahmed Barry & Muhammad Bilal', NULL, NULL
);

-- Row 57: LDP44
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Centre for Green Building Materials Technology', 'Ar. Neelam Manjunath', 'mansarch@gmail.com', 'Flexi San Shell',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Global application, developed in Bengaluru', 'India',
    NULL, NULL,
    'The uniqueness of these prefabricated toilets lies in their ability to completely collapse on themselves, manufactured and stored, ready for emergencies, deployed with great speed and unskilled labor.', 'Giving back to society, Flexi San Shell was developed by CGBMT in collaboration with the local community. A rapidly deployable toilet with portability at its heart, the structure a lightweight & collapsible. Ideal for use in disaster stricken or remote locations, the structure can create a small shell for sanitation use. The structure serves as a blueprint for community level initiatives for rapid fabrication. A small group of unskilled labour can assemble up to 50 of these toilets per day.', 'SDG 3: Prevent the spread of diseases by providing a safe and hygienic sanitation solution in areas without proper toilet facilities.
SDG 6:We can provide access to basic sanitation facilities in areas without proper sanitation infrastructure. 
SDG 10:We can help to reduce inequalities in access to basic sanitation facilities, particularly for marginalized and vulnerable communities.',
    TRUE,
    'LDP44', 'Architect : Ar. Neelam Manjunath Artisans  : Mr.Anandi Lal Marandi                                    Mr.Gopal   Students : Smt. Neha Hegde                                    Sri. Vinya Kotle                                   Smt. Devina Agarwal', 1.1, NULL
);

-- Row 58: LDP50
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'JP za PUP', 'Filip Joveski', 'fjoveski@gmail.com', 'Kindergarten Tocila, Prilep, N. Macedonia',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_II', 'Prilep', 'N. Macedonia',
    NULL, NULL,
    'The Kindergarten in Tocila, Prilep, N.Macedonia, is a two story building, with a capacity for 252 children (aged 9 months to 6 years). The plot is 5030m2, of which 1530m2 is under the ground floor, and the rest is green open space (playground) and parking plots for bikes and cars (regulations). The design of the facility incorporates simple, yet powerful superposition of volumes, shapes and accented colors. The design is: innovative (following the principles of Neuro Architecture for children); inclusive (without architectural barriers in and outside the buildings); green and sustainable (passive solar design, energy efficiency, environmentally friendly, renewable energy sources), beneficial to the overall well-being of all occupants and economically viable', 'The main idea was to design a projects that is green, sustainable, inclusive and adapted to the needs of every child. The building makes maximum use of the natural benefits offered by the sun. The location of the building within the boundaries of the site allows maximum use of the sun from the south side. All playrooms and nurseries (as well as the open-air playrooms) are with east, south-east, south and south-west direction, and have the possibility of natural ventilation and cooling throughout the year. The design of the facility incorporates simple, yet powerful superposition of volumes, shapes and accented colors (in the design of the floor plans, as well as in its spacial conception). All spaces are designed to benefit memory, improve cognitive capacity and improve mental stimulation of the children. The building has clear floor plans and clear visible circulation - central space and gallery halls that directly lead to each classroom on the ground and on the first floor. It provides landmarks for better orientation (colors and shapes), social spaces, enriched environments, natural light and open views to the green landscape surrounding the kindergarten.', 'The building design promotes good health and well-being (Goal 3) by providing a healthy indoor climate (natural ventilation/cooling and natural lighting, good acoustics and open views), which is very important for buildings with vulnerable users, such as children at their early age. It provides quality preprimary education (Goal 4) and a quality early childhood development and care, by enabling a productive learning environment (by creating spaces that benefit memory, improve cognitive capacity and improve mental stimulation by incorporating neuro architecture design principles), that is accessible and inclusive for all children (no architectural/physical barriers in or outside, with sensory room), which directly reduces inequalities (Goal 10) for the children with disabilities. Minimum energy consumption Is achieved by implementing passive solar system design (Goal 13 – Climate action) and implementation of renewable energy sources (Goal 7 - Affordable and Clean energy): orientation of building that offers max use of sun; compact form of building for reducing heat loss; building envelope elements that enable highest possible energy class; air source heat pump (with heat recovery) that is connected to the HVAC system (underfloor central heating system with time controls and separate thermostats for each room); PV panels that produce renewable electricity on site connected to the electrical installation and the air heat pump; water- and energy-efficient devices; No light pollution; Sanitary hot water (central generation) provided through solar water heating with solar collectors; Green roof for thermal insulation, sound absorption, purification of the air, and temperature reduction- reduction of ''urban heat island effect''.',
    TRUE,
    'LDP50', 'Filip Joveski', NULL, NULL
);

-- Row 59: LDP54
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Tsinghua Architectural Design and Research Institute', 'Guande Wu', 'thad_international@thad.com.cn', 'Entrance Pavilions of Old Neighborhood in Beijing',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Beijing', 'China',
    NULL, NULL,
    'Our project is a series of shelters located at the entrance of low-income communities, designed to promote a sustainable and child-friendly environment over the past three years of the pandemic.', 'The entrances of the old neighborhood were in a state of disrepair, with crude tents providing the only cove. The architects and local residents collaborated to engage over a hundred children in the design of the public spaces. The architects utilized recyclable paper tubes and beer crates as the building material, resulting in a quick-to-build, prefabricated, reconfigurable structure that is waterproof, fireproof, and does not damage the foundation. These places have now become iconic symbols.', 'Over 100 children have participated in this project to decorate bicycle parking spaces and showcase their drawings. The project uses sustainable, environmentally friendly, and recyclable construction materials, drawing inspiration from traditional construction patterns to achieve rapid construction without burdening the environment. The project is creating quality spaces at the entrances of old neighborhoods, aiming to reduce the inequality of environmental decay caused by low income.',
    TRUE,
    'LDP54', 'Sisi Liang, Wei Zhang, Guande Wu, Yue Wang', 123.0, NULL
);

-- Row 60: IFF5
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'MH Architects', 'Mohamed Hendawi', 'info@mharchitects-eg.com', 'Child Development Center',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Cairo', 'Egypt.',
    NULL, NULL,
    'A Biophilic Child Development Center designed by Architect Mohamed Hendawi, P.H. D founder of MH Architects based in Cairo, Egypt. Project Location is MASQUT, Oman. Land Area is 15900 m2. BUA is 7000 m2. The center is G+4.', 'The main objective Is to create a place and spaces that play a vital role in the healing and recovery process based on the scientific proven knowledge and Human’s well-being needs. In this designed Livable Project, Architect Mohamed Hendawi, mainly used the BIOPHILIC Design Concept and its fourteen patterns. Designer created Shaded Cooled Echo Garden full of different activities for the kids and their families to enjoy the direct interaction with the NATURE even in the very hot and humidity period, which is not more than 3 months a year. MH had considered and applied the following design principles in OMAN’s Child Development Center:

•	We brought Nature inside the Built Environment
•	We Reconnected Humans with their Native Nature
•	We used Nature analogs in our structure elements.
•	We used Natural Materials for Façade Cladding
•	We increased the Mount of Vegetation
•	We increased the amount of Water ponds
•	We increased the amount of Living-things
•	Bring vegetation to each level
 •	Creating Green Roofs in different levels.
•	One total floor area “The Shaded ECO GARDEN”
 The design was created based on the following equation

Human + Ecology + Science + culture + Art + Design', 'The Biophilic Child Development Center design is based on integrating Nature with the built environment to create spaces and places that positively impact the human brain and physical condition. The designer used a high level of vegetation, green roofs, and single-loaded building with sun breakers to create a healthy, livable, and low energy consumption built environment. Oman is hot country, thus, designer created an Eco shaded/cooled garden to allow the users to be integrated with NATURE all the year long which fasten the recovery process. Nature has it all.',
    TRUE,
    'IFF5', 'Mohamed Hendawi', NULL, NULL
);

-- Row 61: IFF55
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Conselho de Arquitetura e Urbanismo do Brasil', 'Ananda Oliveira Henklain', 'contato.anandahenklain@gmail.com', 'Among rivers, lagoons and streams: from the Amazon''s self-production to bonding with waters',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Boa Vista/Brazil', 'Unknown',
    NULL, NULL,
    'This project is an Amazon-based arrangement of a housing prototype that adapts to different aquatic contexts by stilts, enabling self-constructive efforts, flexibility, and low-environmental impact assets by a wooden arched geometry, to achieve SDG 11 focusing on societal bonding to waters.', 'Flooding events are urban issues worldwide being intensified by climate change. It threats people by spreading infectious diseases, damaging mobility, buildings and the environment, especially in urban poverty. In this matter, the housing shortage is a structural problem that excludes people from multiple devices and deepens segregation. This project aims to tackle it by valuing Amazon''s social and constructive knowledge presenting a self-constructive response through Da Vinci''s Arch, stilts and bioclimatic studies, gathering technologies and practices easily incorporated and reproduced with local assets and regional heritage to achieve SDG 11.', 'From John Turner''s ideas, who took slums by their potential, this proposal highlights how informal settlements could be a source of transformative practices by turning the lack of urbanization into alternative solutions to the relationship with the environment. Therefore, to build SUSTAINABLE CITIES AND COMMUNITIES, the project enlights the millennial power inscribed in so-called "The Hybrid Men" in the Amazon region, of self-constructing houses and villages over and among waters, adapting and comprehending environmental dynamics and through them managing communities more concerned with carrying capacity and sustainability.',
    TRUE,
    'IFF55', 'Ananda Oliveira Henklain/Rui do Rosário', NULL, NULL
);

-- Row 62: IFF9
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'TecTo Arhitectura', 'Sergiu C. Petrea', 'office@tecto.ro', 'FOREST-LAND MUSEUM (Pădureni Museum)',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_II', 'Plosca village, Teliucu, Hunedoara county', 'Romania',
    NULL, NULL,
    'For project targets the construction of a museum that will gather and represent as faithfully as possible the characteristics of the region, highlighted in the form of a local traditional household. The future Forest-Land Museum (Pădureni Museum) will comprise of two buildings- a larger building conformed to the shape of the local churches’ typology, that contains the museum and a smaller building, following the shape of the local dwellings containing a study center.', 'The design team followed the principles stated by F. Schumacher in the book "Small Is Beautiful". Instead of a major ordering gesture, the museum benefits from the community''s contribution, both as a supplier of labour and materials. Old wood and stone elements, artifacts and personal items are combined with modesty to outline a familiar, yet modern space, open to contemporary experiences. The use of local materials, saving of resources and the close association between what was built, and the natural environment were all important goals established by the community and the partner NGOs.', 'Among the villages threatened with extinction, it was proposed to build a commemorative space, to bring together the elderly people who are still in the area, the young people who return to develop small sustainable businesses and the researchers interested in the cultural, ethnological, and anthropological peculiarities of the place. It aims to build resilient infrastructure, promote inclusive and sustainable building methods and be an example of safe and resilient human settlements.
Faithful to the "cradle to cradle" principle, the project uses elements recovered from abandoned buildings and natural materials, sustainably exploited from local sources ensuring healthy lives and well-being for all at all ages. Reinterpreted traditional elements, arising from the use of local craftsmen shape a natural background for cultural and manufacturing activities that address inclusive and equitable quality education and promote lifelong learning opportunities for all. The project aims to give back to the community a certain territory, a location between familiar limits by using iconic shapes and familiar materials, achieving gender equality, productive employment, and decent work for all. Locally sourced and produced sustainable and reliable energy empowers the building systems ensuring low consumption that tries to combat climate change effects. The built assembly and the surrounding landscape restores to natural environment and promotes sustainable use of terrestrial ecosystems, enhancing local biodiversity.',
    TRUE,
    'IFF9', 'PhD. arch. Sergiu-Cătălin Petrea, arch. Sabrina Ene-Butnariu, arch. Cristina Mototolea, arch. Sebastian-Ștefan Apostol, arch. Dan - Alexandru Roșu, arch. Tania-Victoria Băncilă, arch. Diana-Elena Fusea, arch. Ovidiu-Ion Bălășoiu', NULL, NULL
);

