    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Architectural Society of China', 'Yehao Song', 'sup_atelier@supatelier.com', 'Central Canteen of Tsinghua University',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Beijing', 'China',
    NULL, NULL,
    'To improve the living quality of the campus, a new building is built with multi-functions as canteens for students and professors, lecture hall and exhibition hall for the campus, office and service hall for the Tsinghua Career Center and food storage for all the canteens at the center of the campus of Tsinghua University.', 'The core idea of design is to repair the urban texture in the campus context, to improve the fluency of the site, to make it easy to get in for the public from all directions. The section design takes the full advantage of the terrain of the site, creates a three-dimensional indoor street for the public, through ground floor on east and B1 floor on west. The entrance floor of the building on the one hand is functional and solid and on the other hand is a kind of cluster of open public space.', 'The project transformed the site of former canteen and integrated as a convenient and complete public place for the campus. The terrain of the site is in good use for easy accessibilities in all directions. The trees and vegetation are preserved to keep the continuity and sustainability of the environment. Sustainable strategies, especially passive design strategies are adopted in the project to make the space more comfortable and reduce the cost and energy consumption in operation.',
    TRUE,
    'LDP35', 'Yehao Song, Jingfen Sun, Dan Xie , Xiaojuan Chen, Lina Wang', 21000.0, NULL
);

