) VALUES (
    'Tongji University', 'Philip F. Yuan', 'philipyuan007@tongji.edu.cn', '‘The Light of Internet’ World Conference Center',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Wuzhen', 'China',
    NULL, NULL,
    'In order to meet the functional requirements of the World Internet Conference and future diversified operation requirements; the pavilion is divided into four exhibition halls from south to north. The space can be used separated or merged.', 'The site is located in the northwest corner of the heart of Wuzhen, surrounded by farm houses, tourism projects and the first stage project of the exhibition pavilion area.
The space can be used in series at large exhibitions or it can be opened in parallel to accommodate various activities. Considering the space experience and applicability of the space of the independent exhibition hall, each section of the exhibition halls is high in the center and low along the edge. The string beams are placed in the middle of the exhibition hall to form the big open space for the special function requirement. At the same time, there are openings at the top to introduce the skylight to improve the space quality.
In order to achieve rapid construction of the entire pavilion, the dynamic modular system and the logic of the full prefabrication are applied to the overall skin construction of the entire pavilion project.', 'The space can be used separated or merged, so it is possible to be used in series at large exhibitions or it can be opened in parallel to accommodate various activities. In order to achieve rapid construction of the entire pavilion, the dynamic modular system and the logic of the full prefabrication are applied to the overall skin construction of the entire pavilion project.',
    TRUE,
    'LDP16', 'Philip F. Yuan', 19446.0, NULL
);

