) VALUES (
    'PS_Architetture', 'Pedone Working s.r.l.', 'pedoneworking@gmail.com', 'HEMP REGENERATION_Urban regeneration programme',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Bisceglie', 'Italy',
    NULL, NULL,
    'Natural construction and bioclimatism are the elements of the project. Solar greenhouses and sunshades design the facades of the buildings. Public and private green spaces redesign the neighbourhood.', '“HEMP REGENERATION”, Urban regeneration project, Bisceglie, Puglia.
An abandoned market area with environmental problems is reclaimed with a system of public and private green spaces and new NZeb residences.
The project develops research themes in the Mediterranean area with passive bioclimatic contributions; solar greenhouses and a natural ventilation system mitigate the temperature of the flats made of hemp and lime materials, subtracting -800,000 kg of CO2 and reducing -3,000,000 lt H2O.', 'Houses with natural hemp materials for the healthiness of the occupants. The cultivation of hemp results in a circular economy. Production reduces -3,000,000 litres H2O and -800,000 kg CO2. High insulation, solar greenhouses, natural ventilation, photovoltaic and solar systems for affordable and clean energy. Permeable surfaces and rainwater recovery for water saving and groundwater recharge. Green spaces and Mediterranean scrubland for bee and insect repopulation.',
    TRUE,
    'LDP29', 'Ing. Pietro Pedone, Arch. Pantaleo Pedone, Arch. Massimo Pedone, Arch. Eleonora Pedone', NULL, NULL
);

-- Row 68: LDP32
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
