    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'EFFEKT Architects', 'Liv Elbirk', 'le@effekt.dk', 'Living Places Copenhagen',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Copenhagen', 'Denmark',
    NULL, NULL,
    'Living Places Copenhagen demonstrates a new way of building homes with record low carbon foot print and delivers best in class indoor climate.', 'The vision of Living Places Copenhagen is to lead the way within the building industry and show how rethinking buildings can help solve some of the global climate and health challenges. The concept holds the lowest CO2 emissions in Denmark, demonstrating that we do not have to wait for future technology to build homes that benefit both people and the planet. Designed with a strong focus on creating a healthy indoor climate using daylight and fresh air. SDG: 3, 9, 11, 12, 13, 17', 'Living Places concept holds the lowest CO2 emissions in Denmark and a first-class indoor climate. The concept is based on five key principles: homes should be healthy, affordable, simple, shared over time and scalable. A complete Life Cycle Assessment has been carried out. The green transition is a team sport that requires close cooperation through all phases towards a common goal between all parties of construction projects. Living Places Copenhagen is the result of such a partnership.',
    TRUE,
    'LDP32', 'EFFEKT, The VELUX Group, Artelia and Enemærke & Petersen. Design group: Sinus Lynge, Kasper Reimer, Tina Lund Hansen, Daniel Veenboer, Marco Antonio Ravini, Juan Pablo Herrero Gil, Yulia Kozlova, Evgeny Markachev, Joel Brynielsson', NULL, NULL
);

-- Row 69: LDP53
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Sumito TAKASHINA Architects inc.', 'Sumito TAKASHINA', 'sumito@starchitects.jp', 'URAKUSATSU TOU',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Kusatsu', 'Japan',
    NULL, NULL,
    'A project to upcycle and revitalize a 60-year-old hotel completed in 1961 to provide for the next 60 years. A large amount of CO2 emissions from demolition and new construction were reduced.', 'Rather than scrap-and-build a large reinforced concrete hotel built 60 years ago with an enormous environmental burden, we revitalized it for the next generation in this location that enjoys the benefits of the earth in the form of hot springs. The existing frame was reinforced to withstand earthquakes, and the interior and exterior were finished with an abundance of natural materials that have a low environmental impact. This is an attempt to go carbon neutral for the next 60 years.', 'This project aims to achieve Goal 12 of the SDGs by reducing the amount of material resources, waste, and CO2 emissions by upcycling existing buildings, i.e., reusing existing structures without demolition or new frame work, and also contributes to Goal 15 by protecting hot spring and wood resources. 
 This method is not only effective in significantly reducing construction costs and time, but is also desirable from an ESG investment perspective.',
    TRUE,
    'LDP53', 'Sumito TAKASHINA', NULL, NULL
);

-- Row 70: LDP66
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Studio Cardenas Conscious Design', 'Arch. Mauricio Cardenas Laverde', 'm.cardenas@studiocardenas.it', 'BooTech EcoDome',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Milan', 'Italy',
    NULL, NULL,
    'BooTech Ecodome explores the use of bamboo, recycling one of the natural materials most suitable for construction, with a contemporary language and technique, following the UN 2030 Agenda SDGs.', 'BooTech EcoDome, a geodesical bamboo dome designed for Interni Magazine event at 2009 Milan’s Design Week. Bamboo was reused from a previous pavilion, cut into slats and assembled using mechanical connections using no cement and specialized manpower, unlike mainstream approach. A disrupting construction system in a time of environmental crisis, designed with a precise geometry in harmony with the proportions of the Statale University’s renaissance main courtyard. Tradition vs Innovation.', 'BooTech EcoDome refers to a physical transformation of the built environment asserting that the most viable means to radically reduce embodied carbon in buildings is to use natural materials for construction such as bamboo. Other than combat climate change, using bamboo properly for construction can tackle several SDGs by generating a new value chain, promoting inclusive and sustainable industrialization, foster innovation, protecting ecosystems, bringing near agriculture and architecture.',
    TRUE,
    'LDP66', 'Arch. Mauricio Cardenas Laverde', NULL, NULL
);

-- Row 71: LDP9
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Juri Troy Architects, Caravan Atelier', 'Prof. Arch. Mag. Juri Troy', 'office@juritroy.at', 'Straw flea',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Murstetten', 'Austria',
    NULL, NULL,
    'The project is conceived as a one-room house. It stands as a solitaire self-confidently and naturally in the midst of the historical remains.', 'In the southern, lower part is the living room with large, completely openable glazing to the garden and the small stream crossing the property. The building is entered via the northern part, where there is also a small sanitary unit and a sleeping gallery. The large panorama windows are aligned with the historical and landscape references and offer an unrestricted view towards the church, into the valley or to the remains of historical statues in the park.', 'The project follows a holistic sustainable concept in planning, use and implementation. The house is elevated and only touches the terrain via the eight screw foundations. This means that no ground surface is sealed. Most of the materials used come from the immediate surroundings. The wood, both for the structural elements and for the surfaces, comes from the client''s own forests and was processed in the neighbouring sawmill. Heat and energy are generated by the photovoltaic system on the roof.',
    TRUE,
    'LDP9', 'Prof. Arch. Mag. Juri Troy', NULL, NULL
);

-- Row 72: IFF25
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'ARB (UK)', 'Joshua Bolchover', 'jpbarch@hku.hk', 'Incremental Development Manual for Mongolia',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Ulaanbaatar', 'Mongolia',
    NULL, NULL,
    'The concept is an in-situ upgrading strategy for the ger district residents of Ulaanbaatar, Mongolia that integrates affordable energy efficient housing and key sanitation and sewage infrastructure.', 'Over 840000 people live in the ger districts of Ulaanbaatar, Mongolia without basic infrastructure, and use an average 4.1t of coal for heating as temperatures drop below -30°C. Current plans require residents to exchange their own land for an apartment. We want to allow people to stay on their land via  a mechanism to regenerate plots using infrastructure that promotes densification and value creation for resident landowners, as well as building energy efficient houses that does not use coal.', 'The proposed idea integrates energy efficient housing and in-situ infrastructural provision. Improved insulation, and eliminating use of raw fuels will reduce carbon emissions. Improved air quality, and access to sanitation and sewaging will improve the health and wellbeing of communities by having direct access to drinking water, and reduced sickdays. More people will be living in sustainable, durable homes, whilst site densification reduces unsustainable growth of informal settlements.',
    TRUE,
    'IFF25', 'Joshua Bolchover, Jersey Poon', NULL, NULL
);

-- Row 73: IFF46
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Athabasca University RAIC Centre for Architecture', 'Henry Tsang', 'htsang@athabascau.ca', 'Athabasca Cultural Community Centre',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Town of Athabasca', 'Canada',
    NULL, NULL,
    'The Athabasca Cultural Community Centre is a hypothetical virtual building project designed as a learning tool to explore and demonstrate an integrated approach to a regenerative framework in the context of a rural town in northern Canada.', 'The design for the Athabasca Cultural Community Centre focuses on highlighting an integrated design approach to designing a regenerative project adapted to the northern biome and climate of Athabasca, Canada. The integrated design process takes a three-step approach: Step 1) The programmatic needs are developed through a collaborative engagement of listening and dialogue with the local community; Step 2) Considering its cultural context, climate, and physical characteristics, a deep understanding of the site is formed; Step 3) The program and natural systems are woven together to optimize the passive design opportunities while enhancing the celebration of the environment. 

The final design is highlighted by a holistic understanding and adaptation to the site as an integrated living system. The sculptural building massing & form expresses a strong sense of place and identity informed by indigenous knowledge. The use of sustainable and renewable materials including regional mass timber are able to efficiently sequester carbon. The spatial and experiential design improves the indoor environmental quality, health and wellbeing for its tenants, and is accessible, inclusive and welcoming to all.

Passive Systems: Some design elements that evolved from this process were envelope specific, such as R-values, window wall ratios and shape/size of windows with shading options. The use of the landscape as part of the overall environmental strategy – to moderate solar and stormwater, and to be a purifier of the ventilation air. The landscape design overflowed into a biophilic approach to the architecture with natural materials and systems, such as the solar chimney and extensive green roofs. 
	
Active Systems: The heat is delivered through in-floor – fed via heat pumps connected to the geo-exchange piling system – an integrated engineering structural and environmental strategy. Outside air volumes are doubled with no energy penalty through the use of the earth tube systems, which also provide passive cooling in conjunction with natural ventilation. Renewable energy extends to the roof and parking areas with integrated solar panels.', 'The faculty members of the RAIC Centre for Architecture at Athabasca University collaborated with many interdisciplinary experts in the development of the design, including indigenous knowledge keepers (SDG 17). Together, they have developed this innovative project as a sustainable, accessible, inclusive, safe space and a hub for the residents of the Town of Athabasca. (SDG 10, 11, 16). The Centre is designed with a community-centric planning consideration that focuses on the social and cultural value of space as well as the health and wellbeing of the occupants. (SDG 3) The numerous regenerative design strategies directly advances SDGs that focus on sustainable development and climate action. (SDG 11, 13)',
    TRUE,
    'IFF46', 'Dr. Henry Tsang, Veronica Madonna, Dr. Trevor Butler, Dr. Douglas MacLeod, Jessica Williams', NULL, NULL
);

-- Row 74: IFF49
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Ubuntu Arquitetura', 'Vitor Daher', 'daher.arquitetura@gmail.com', 'Vitor Daher',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Nazaré Paulista', 'Brasil',
    NULL, NULL,
    'The Nazaré Ecosystem transforms a former eucalyptus plantation land into an educational centre meeting the contemporary sustainable demands using a simple and vernacular aesthetic, respecting the client''s desire for an architecture with the atmosphere of "a house that was born old, that has always been there".', 'The Nazare Ecosystem have a complex architectural programme, including: A summer house, small rental units, a cultural space, an industrial kitchen, spa, swimming pool, and an art gallery.
Seeking the best efficiency, a modular structural system made of reforested wood was created using the minimum module of all parts is 300mm with a maximum span of 6m.
All rooms were designed with passive bioclimatic strategies using the sun, the wind and the natural elements in a sustainable approach.', 'From the outset, the project aimed to meet the 17 SDGs.
1- Use of local labor and materials
2- Productive landscaping with native species.
3- Sports infrastructure
4- Educational cultural centre
5- LGBTQI+ lecturers
6.14- Recovery of springs
7- 100% solar energy
8- Attraction of tourism to the city
9,10,11,12- Connection with local producers
15- Discouraging hunting
16- Free educational courses
17- Free cultural agenda with tax incentive.',
    TRUE,
    'IFF49', 'Vitor Daher, Pablo Mauleon', 200000.0, NULL
);

