    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Boldarini Arquitetos Associados', 'Marcos Boldarini', 'contato@boldarini.com.br', 'Cantinho do Céu',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo', 'Brazil',
    NULL, NULL,
    'The Cantinho do Céu project, located in São Paulo, Brazil, comprises the urbanization
of informal settlements and the recovery of a water reservoir´s edges through the
implementation of a linear park', 'The Cantinho do Céu urbanization project was developed based on the understanding
of the importance and urgent need of the territory’s urban qualification. Its main element is
represented by the six phases that make up the linear park, which, in addition to creating
spaces for sports and leisure, seeks to explore possibilities for bringing people closer to the
water and, in an articulated way, respecting social structures and local morphology, resulted
from collective construction.', 'The project brings urban infrastructures and public recreational spaces to a community that lacked access to clean water, sanitation services and public spaces (goals 1, 3, 4, 6, 9, 10 and 11); reforests and preserves the banks of the reservoir and reverses the discharge of sewage into the water body (goals 13, 14, 15); and was developed alongside the community, ensuring community-generated interventions and the continuity and preservation of the project through social engagement (goal 17).',
    TRUE,
    'LDP48', 'General architectural coordinator: Marcos Boldarini, Urban/Landscape coordinator: Marcos Boldarini and Lucas Nobre; Project Management: Elisabete França, Maria Teresa Fedeli, Vanessa Padiá, Letícia Tamisari and Laura Dallabrida Leite.', NULL, NULL
);

-- Row 76: LDP49
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Studio Cardenas Conscious Design', 'Arch.Mauricio Cardenas Laverde', 'm.cardenas@studiocardenas.it', 'BooTech Innovative Bamboo Construction System',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Milan Italy', 'Unknown',
    NULL, NULL,
    'BooTech construction system is a balance between nature and artifice, applicable without cement nor specialized manpower unlike mainstream approach, makes it, when in commerce, the first of its kind.', 'The symbiosis between nature and technology is the original characteristic of BooTech, a disruptive sustainable construction system in a time of environmental crisis. BooTech innovates through the dry-mounted application of bamboo, a natural product of nature, to achieve beautiful, cost-effective, low carbon architectural solutions of different geometrical forms and sizes. The elegant designed system can host bamboo poles of various available species that can vary from 50mm to 140mm diameter.', 'Introducing BooTech into the building chain will promote shaping a circular industry ecosystem, a value network that will challenge the existing construction industry supporting life-cycle thinking. BooTech is a conscious, innovative and strategic choice to radically reduce embodied carbon in buildings supporting the mitigation of climate change in line with the SDGs of the United Nations 2030 Agenda.',
    TRUE,
    'LDP49', 'Arch. Mauricio Cardenas Laverde', NULL, NULL
);

-- Row 77: LDP69
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Brac University', 'Emmat Ara Khanam Ema', 'khanam.ema@bracu.ac.bd', 'Zero Carbon Bamboo Building with Active Participation of Marginalized Community',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Jhenaidah', 'Bangladesh',
    NULL, NULL,
    'A communal space where community members can congregate for various official or informal activities that will promote community building and a sense of unity and connections.', 'The aim was to inspire local people to develop a space on their own, which would create a sense of ownership, and pride in the community while encouraging sustainable living through the eco-friendly structure that produces no carbon emissions. The structure is made of affordable, local materials, with the help of student volunteers, locally-trained artisans, and community members to support and strengthen capacity in the communities ultimately advancing sustainability''s long-term goals.', 'Bamboo Architecture offers a potential solution to the environmental, economic, and social issues that society is currently confronting in Bangladesh. In addition, the involvement of locals enriches practicality and efficiency in the use of community resources, as well as a strengthening strategy for sustainable eco-buildings. Their active involvement in every project phase, from project conception to design to implementation, will also help sustainability''s long-term goals.',
    TRUE,
    'LDP69', 'Zainab Faruqui Ali, Emmat Ara Khanam Ema', 31.22, NULL
);

-- Row 78: IFF11
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'AUTH School of Architecture', 'Angelos Saltidis (Author), Anastasios Tellios (Supervisor)', 'ttellios@arch.auth.gr', '2 km: "Roof" of Agricultural Growth and Innovation in Thessaloniki Plain',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_II', 'Thessaloniki', 'Greece',
    NULL, NULL,
    'The project investigates the redefinition of the Greek countryside, aiming to become a model for the development of a new generation of farms where production, research and recreation are in balance.', 'The proposal transforms 50 hectares of agricultural land into an alternative agricultural typology, offering cultural and community facilities developed around farming and food production. Thus, it makes this new structure an active economic and social center, forming a new model of the relationship between consumer and producer. The resulting program variety reflects the entire food chain, from research, education, cultivation, and harvesting, to storage, sale, and consumption.', 'The project studies new methods of cultivation and food production, suggesting the creation of a new model of farms placed in the Greek countryside, along the main highways. New experimental crops are created around the structure adopting the pixel cropping model. Architecturally, the proposal is based on the typology of the elongated pitched roof allowing for easy future expansion of the structure, or even its transfer to a new plot, leaving the minimum possible footprint on the environment.',
    TRUE,
    'IFF11', 'Angelos Saltidis', NULL, NULL
);

-- Row 79: IFF51
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Colegio de Arquitectos del Peru', 'Carlos Zeballos', 'czeballos@unsa.edu.pe', 'Place Building: Enhancing Urban Resilience in Hazard-Prone Areas’ Public Spaces. The Case of Arequipa, Peru',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_III', 'Arequipa', 'Peru',
    NULL, NULL,
    'This project proposes the concept of Place Building as a tool for integrating fragmented communities near seasonal ravines in Arequipa, Peru through low-cost and easy-to-implement urban elements in public spaces.', 'The main goal of these modular, scalable and flexible urban elements is to enable social exchanges and connections in public spaces, contributing to the consolidation of organized social capital and laying the groundwork for permanent projects that address the needs of an organized community. The design project is based on an intervention model that articulates urban, environmental, social, and institutional aspects to increase the communities'' resilience and mitigates the risk in these areas.', 'Our concept of Place Building proposes creating communal identity by transforming so-called non-places. Unlike Placemaking, which is typically ephemeral, Place Building creates permanent, gradually-developed communal infraestructure based on an initial module developed in collaboration with the community and local authorities. This approach enhances social capital and community reselience. Our proposal is based on the Urban Linkages project and is directly linked to SDGs 11, 15 and 16',
    TRUE,
    'IFF51', 'Carlos Zeballos & Sheyla Chevarria', NULL, NULL
);

-- Row 80: LDP13
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'China Architecture Design & Research Group (CADG)', 'Jiayin Wei', '2019332@cadg.cn', 'The main pavilion of the 11th Jiangsu Horticultural Expo',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Nanjing, Jiangsu province', 'P.R.China',
    NULL, NULL,
    'The main pavilion of the 11th Jiangsu Horticultural Expo is a large-scale public building group with highly complex and diversified functions composed of 43 individual buildings. The original industrial building has a construction area of 12,500 ㎡, and the total construction area after activation and expansion is 52,000 ㎡.

The design takes the site of an abandoned private cement factory as the construction base. Restoring environment, repairing urban functions, creating a new public green space in the city and respect for "ecology" and "heritage" are the primary value orientation during the planning and architectural design process of the main pavilion.', 'The new building adopts the "light intervention" design strategy, in which groups of small architectural groups are placed in the open space between the reserved buildings, creating a strong contrast between the old and the new, and regenerating the ruins into modern horticultural pavilions full of greenery.

Light intervention, reflected in the "light structure" - the use of prefabricated steel structure system to achieve environmental protection and rapid construction process; "Light image" - slender structural components combined with climbing vertical greening to create a light architectural image, contrasting with the roughness and thickness of industrial buildings; "Light attitude" - boundless green gardens permeate the industrial site, allowing the building to dissolve its image and disappear from nature.

From a lime-burning factory to a space that carries new life, the design and construction of the main pavilion is not to erase the past and forget history, but to leave traces and let history speak. Between the old and the new, today''s thinking and creation are also passers-by, and more reverie about beautiful cities and spaces belongs to the future.', 'The main pavilion of the 11th Jiangsu horticultural Expo is built on the site of an abandoned cement factory, focusing on creating a science popularization platform with the theme of industrial heritage protection. The design strategy of light intervention also gives the building greater flexibility to meet the needs of multiple functions and types of spaces, while also taking into account post exhibition renovation and reuse. The design of the main pavilion intends to rely on the diverse industrial architectural relics and rich elevation differences within the site, using a slender steel structure system to achieve a lightweight modern exhibition hall community, making the green art garden diffuse and linger between the rough industrial factories, and using green space to bridge the damage caused by industrial production to the mountains and nature. Using a modular strategy to handle and adapt to complex sites, the prefabricated system enables pre planting of greenery, integrating horticulture and architecture. After the exhibition, the main exhibition hall park will serve as a public education base and a children''s forest experience place, continuously promoting plant and horticultural knowledge to citizens.',
    TRUE,
    'LDP13', 'Cui Kai', NULL, NULL
);

-- Row 81: LDP26
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'SUP Atelier of THAD', 'Yehao Song', 'sup_atelier@supatelier.com', 'Waterfowl Pavilion of Beijing Zoo',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Xicheng District, Beijing', 'China',
    NULL, NULL,
    'Waterfowl Pavilion is a net-zero energy building located on an island with high ecosystem diversity, and serves as a multi-functional building for bird breeding, exhibition and science advocacy.', 'To create a demonstration net-zero energy building under the limit budget is the initial target. Since the pavilion is a habitat for birds, the environmental quality is more complicated. The sustainable strategies need to be refined into specific goals for each engineering discipline.
The design emphasizes being ''invisible'' in the natural environment, which is not only reflected in visual level, but also the minimization of interferences to ecological system and wild environment of the island.', 'The pavilion employs PV, PVT and Solar heating system to produce clean energy onsite. By combining passive design methods and active technologies together, the energy consumption during operation is minimized.(Goal 7)
The original micro-ecosystem is intactly preserved with the site handling strategies. An integrated wetland system is employed through a minimally invasive reform of the site section, which creates an excellent habitat for the waterfowl and the vegetation.(Goal 15)',
    TRUE,
    'LDP26', 'Yehao Song, Lina Wang, Jingfen Sun, Dan Xie, Xiaojuan Chen, Yifan Bai, Zhenghao Lin， Junjie Li', NULL, NULL
);

-- Row 82: LDP41
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'China Architecture Design & Research Group', 'Xinyi Zhao', 'zxy5153@gmail.com', 'The Future Garden of Jiangsu 11th Horticultural Expo',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Nanjing', 'China',
    NULL, NULL,
    'The project is located on Kongshan mountain in Nanjing, where quarrying caused ecological damage. A botanical garden, outdoor theaters and a hotel are built to restore ecosystem and bring life back.', 'Respecting and reusing existing resources, we chose ecological restoration as our strategy. The old transport channel is reconstructed to provide a path to garden and blankets of fog at the pit bottom build a poetic landscape while adjusting temperature and humidity. The roof of botanical garden, a 16000㎡ artificial lake covers the entire secondary mine pit, creating a special "underwater" experience. Then, open-air stages are set up against the cliff to project a huge light show and the hotel is elevated at the east end overlooking the whole park.', 'By light intervening strategy, innovative technology and adaptive vegetation, we avoided new damage to the site and restore degraded forest and ecosystem. The abandoned quarry reshaped into a garden showcased new chances of sustainability, as well as offering a platform for public to look into biodiversity and eco-restoration. Restoring is not only recompensing, but also creating a new nature where human learn to coexist with our planet, and our architecture - when its water turns green with algae and its steel is covered with moss - will eventually be a part of it too.',
    TRUE,
    'LDP41', 'Kai Cui, Fei Guan, Qin Ma, Ling Yang, Xi Chen', 98000.0, NULL
);

-- Row 83: LDP60
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Group of Architects and Thinkers (GOAAT)', 'Md. Rabiul Islam', 'goaatmail@gmail.com', 'Bangabandhu Memorial Ghat',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Gopalganj', 'Bangladesh',
    NULL, NULL,
    'The project''s notion to knit the community while keeping the natural setting, comes from commemorating the visions of ''The father of the nation'' who fought for the liberty of the people of Bangladesh.', 'The Project is situated on the bank of Madhumati River which has been left unutilized without development for decades with mono functional activities like boat docking and river-based transportation of goods which over the years caused the site to decay from extensive flooding and erosion.
The design proposal transforms the entire riverfront with an Indoor information center, an outdoor public space as a contemplation zone that extends towards the river and terminates as a natural slope. The outdoor gathering area around the shallow pond is vegetated with the national flower of Bangladesh “The Lily” enclosed by a curved walkway linking the building mass with the river. 
The main aspect of the project is its adaptability with seasonal changes of water levels and vegetation and inclusivity of nature within a public space. Proposed contours adapt with flooding and inundation of the site during monsoon that brings fertile soil, amplifies native vegetation growth, and attracts numerous shore birds. The safety enclosure of the curved walkway is formed with slender poles made of metal at different height that also acts as a perching zone for shore birds.', 'The project ensures equal accessibility to people of all races, gender, age and religion. It works as a recreational space with well thought out inclusion for the elderly and specially abled and gives everyone the opportunity to connect with nature. Thus, it plays a vital role in maintaining the mental health of the inhabitants. It prevents the site from soil erosion which previously was a major threat to the mono-functions of this area. The proposed contours adapt to the site''s floods and inundation during the monsoon, which delivers fertile soil, amplifies natural flora development, and attracts a large number of shore birds. The circular walkway''s safety perimeter is built by thin metal poles of varying heights that also serve as a perching zone for coastal birds.',
    TRUE,
    'LDP60', 'Md. Rabiul Islam , Nehleen A Chowdhury, Utsha Zaman', NULL, NULL
);

-- Row 84: IFF10
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'NY Hub', 'Manon Vandommele', 'manonvandommele@gmail.com', 'Education Center: new learning opportunities',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'New York City', 'United States of America',
    NULL, NULL,
    'The project aims to rethink architecture as an instrument of inclusion by providing educational facilities that embrace the sensory surprises of New York, offering new learning opportunities in the heart of Manhattan. The proposed architectural interventions aim to create new configurations of spaces for interaction and socialization for schools, and especially for children growing up in a city where everything is tenfold. This new way of thinking about spaces was achieved through the use of sequences and variations that are omnipresent in New York. For the detailed development of the project, the intervention sites are located in a neighborhood in the heart of Manhattan, along 8th Avenue. Both sites offer a strong relationship to the streetscape and represent a great opportunity to provide new educational spaces for New York schools.', 'The new principle of extracurricular spaces forms a new qualitative resilient system that uses the existing qualities of the neighborhood to build complementary spaces to the city’s schools. Through their structural design and their principle of openness to the city, the educational centers express a unique architectural identity in the urban fabric. Human interactions and acquisition of knowledge among children are enhanced by the extracurricular facilities offered, which can also be used by anyone requiring facilities such as those proposed. Schools have complementary spaces for teaching, learning, creating new opportunities for socialization, etc. New learning methods are created by the stimulation between the activity of the streetscape and the extracurricular facilities. The sequences and variations actively present in the city have made it possible to propose new ways of thinking the spatial organization of a classroom, a playground, a cafeteria, etc. The sharing of knowledge and the strong relationship with a city in constant movement are essential elements for the growth of children, allowing them to improve their ability to adapt to unexpected situations. By integrating these functions into the urban fabric of Manhattan’s neighborhoods, a resilient network takes place, optimizing the social and educational integration of children and residents of the city. In this way, the educational centers are an extension of the existing schools of New York, complementing the overcrowded neighborhoods of Manhattan. The architecture of the educational centers creates a strong relationship with the streetscape of the neighborhood and allows children to benefit from school spaces that offer new learning conditions by using the exceptional qualities of the city: sequences, variations and overload of sense. The centers add quality to children’s educational experience and provide new learning opportunities that can be seen as a new vision for New York’s future schools. It is a human-centered approach that addresses the feelings of individuals in a sensory overloaded environment. A new resilient network of schools in Manhattan offering new learning opportunities.', 'Located between Pennsylvania Station and Times Square, the district of the two sites selected for the development of the project is primarily made up of businesses, offices, hotels, theaters and housing. Many of these businesses and offices are empty, hotels are closing one after the other, and the Covid 19 pandemic has only made the situation worse. There is a certain lack of liveliness and authenticity in an area where so much is happening. Thousands of people pass through every day, there is an unmistakable proximity to the city’s points of interest because it is located in the heart of Manhattan. What is missing from these spots and what is the ingredient of a city, of a neighborhood, are schools. Schools in which children have proper spaces for a good education, with outdoor spaces and work areas appropriate to their needs. Most of the schools in the area are located in old buildings where the playgrounds are missing, the interior spaces are too small and not designed for school facilities. Children are somehow cut off from the reality of what is going on in the city. They enter a building and lose the notion of the city. The majority of large New York schools with spacious facilities, outdoor playgrounds and access to natural areas are located in the northern part of Manhattan, where there is very little human activity, where there are no crowds, and where the realities of New York do not show up. However, realities of New York are for me characterized by this constant disorder where many events occur at the same time. There is an overload of sense that sometimes can be too much, but it is part of the reality of the city. Therefore, I will propose to introduce new learning opportunities in these areas through the creation of an educational center offering additional spaces for educational purposes linked to high schools, elementary schools and kindergartens. Those educational centers would be located in several places in the city in order to have a resilient educational system accessible to all. Kindergarten, primary and secondary schools can rent all or part of the spaces offered, for full or half days, and welcome children to offer them traditional and extracurricular activities that are at the level of the neighborhood and not often found in these places. Making the choice to introduce afterschool spaces in areas such as Times Square and Madison Square Garden is a way to connect with the city, with the sensory overload in which children grow up. It is an educational center that learns children to deal with the mess, the real New York, where there are too many people, too many billboards, too many cars, too much noise, too many smells, too many things going on at once.
The principle of the education center aims to expand into multiple areas of Manhattan to provide K-12 schools with multiple access points with different types of activities offered depending on the center and its location. It is a resilient network system that seeks to provide new and complementary learning opportunities in an environment where sensory overload and overcrowding are pervasive. The sequences and variations analyzed above are the main tools for the implementation of these centers. Different centers will be strategically located to connect with both Manhattan schools and direct access to the many activities in the city. The creation of this network of educational centers is the establishment of educational resilience within the different neighborhoods of Manhattan. These out-of-school spaces will offer neighboring schools the opportunity to have different activities not accessible in their schools by providing new kinds of classrooms, play spaces, sports facilities, dining spaces, etc. These spaces can also benefit the city’s occupants when they are not being used by the various schools. These are multi-purpose spaces that provide both new learning opportunities for children and sharing spaces for citizens. This resilient community strategy is spread across several points of interest in Manhattan neighborhoods.
The educational centers are designed in harmony with the liveliness of what happens in the street, with the different levels of intimacy that can be felt, the variations in the facades that have a direct impact on the relationship between the interior environment and the pedestrians, the important variations of our senses that engender all kinds of feelings in our body, as well as the visual sequences offered around the sites. The project is developed on the basis of sequences and variations, meaning that it is a school where hundreds of people pass through a corridor that is in direct relation to the classrooms but also to the playgrounds, where reading and eating complement each other, where hearing the sound of claxons and the yelling of people are part of the many daily events of the children’s education, etc. It is about learning from the harshness of the city, from the simultaneity of these sequences and variations and using them as qualities within educational spaces.
Being in a city like New York, it is also to have a feeling of “too much” very quickly by the important presence of skyscrapers everywhere around us. In these moments, it is important to be able to refocus on ourself and find other ways to experience the city, one of them is to connect with nature. Human beings are genetically predisposed to feel a sense of pleasure when surrounded by natural environments and this can quickly become a need when we are in a dense environment where concrete and asphalt are the main elements around us. We are systematically drawn to nature because it brings a sense of serenity in times of chaos, soothing in times of stress, and simply well-being at any time of the day. Several green spaces are present in Manhattan, including Central Park which is one of the largest parks in New York, allowing residents to escape the city’s crowds and disconnect from the visual and audio chaos while taking a walk. On a more human scale, there are also pocket parks which are generally located in the center of the chaos and which allow to have the feeling of being in a park while being in a dense urban landscape. These are an effective solution when the implementation of a park is not possible due to a lack of space. Furthermore, providing children with green outdoor spaces improves their ability to concentrate and their cognitive skills. It seems essential to incorporate the notion of natural environment within an educational project located in a place overcrowded and overloaded with (unexpected) events. The green spaces will then allow the children to create a balance between the important presence of activities around them and the calm provided by these natural environments.',
    TRUE,
    'IFF10', 'Manon Vandommele - NY Hub - Flanders House - Kris Scheerlinck', NULL, NULL
);

-- Row 85: IFF14
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'CP KUKREJA ARCHITECTS', 'Keshav Tomar', 'keshav.tomar@cpkukreja.com', 'Central Vista Redevelopment',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'New Delhi', 'India',
    NULL, NULL,
    'The Redevelopment of Central Vista, New Delhi, is a historically and culturally significant project proposing the redevelopment over 440 Hectares of prime land. Reimagining New Delhi as a Garden City, the redevelopment proposal offers a possibility of bestowing it with an international iconic stature and creating a state-of-the-art futuristic and livable vision of urban development.', 'The Redevelopment of Central Vista, New Delhi, is a historically and culturally significant project proposing the redevelopment over 440 Hectares of prime land.

Urban Context
Located in the heart of New Delhi, the capital of India, the design concepts are centred on restoration, adaptive re-use, intelligent conservation, upgradation, retrofitting and reconfiguration of the existing edifices to preserve the celebrated historic value of the area, along with creation of some landmark edifices. The site comprises of highly coveted buildings such as the Presidential Residence (Rashtrapati Bhawan), the North and South Blocks, the Indian Parliament, Ministerial Complexes, various Secretariat buildings besides the National Archives, few National Museums and a National Stadium.

Master Planning Concept
The overall master planning integrates elements of harmony, balance and rhythm to ideate a concept which is a comprehensive understanding of the challenges of the present times while leaving ample area for unhindered future expansion. The axis of the Vista extends more than 2 kms in length and is developed as a mixed-use cultural district. A natural stream balances the overall site and is flanked by extensively landscaped avenues and pedestrian spine on either side. By restricting vehicular movement on the outer roads, this street is kept pedestrian-friendly, becoming an eco-conscious zone. The design also proposes a monorail concealed under the terraced landscape which links all buildings in the precinct & integrates with city mass transit significantly reducing vehicles in this district. Technological advancement is utilised to its fullest with features such as high-end security systems, display screens to help guide pedestrians with movement in and around the site, well-regulated parking for vehicles etc.

Vernacular design
The architectural design strives for a responsible concept development through an understanding of conservation, sustainability and holistic approach. The offices are proposed as mixed-use spaces and inspired by the mohallas, chowks and bazaars of Chandni Chowk (one of the oldest area in New Delhi), accommodate retail areas, restaurants, lounging spaces etc. in their central courtyards. Entrance of these buildings use Gopurams and Toranas as inspiration, giving an abstract and magnificent look to the whole Complex. 

Climatologically responsive Design 
The offices would be able to symbolically represent India through use of jaalis, louvres, accommodating semi-shaded central courtyards and creation of double skin façade by extending slabs (chhajjas) supported by colonnaded corridors around the Secretariat edifices. These architectural elements and techniques work well in the Indian landscape and establish a climatologically responsive design. Stone panels with different traditional Indian architectural motifs become the patterns for jaalis which celebrate art and architectural history of India while synchronising with the existing Lutyens’ character. 

Re-defining urban character
The proposal also integrates high-level technology through automation and artificial intelligence systems in the buildings for increased security. North and South Blocks, already existing and highly prominent offices, are proposed to be restored instead of using them as museums. At one end of the axis, a precinct of Museums has been created around India Gate, a national memorial monument, which proposes adaptive reuse of historical Indian princely estates. 

Reimagining New Delhi as a Garden City, the redevelopment proposal offers a possibility of bestowing it with an international iconic stature and creating a state-of-the-art futuristic and livable vision of urban development. 

The Redevelopment of Central Vista, New Delhi, is a historically and culturally significant project proposing the redevelopment over 440 Hectares of prime land. Reimagining New Delhi as a Garden City, the redevelopment proposal offers a possibility of bestowing it with an international iconic stature and creating a state-of-the-art futuristic and livable vision of urban development.', 'Transforming India’s capital for the 21st Century 

Central Vista is the seat of the Government of India and lies at the heart of New Delhi. Inaugurated nearly a century ago, in 1931, this precinct and New Delhi were envisioned by British architects Edwin Lutyens and Herbert Baker as the central administrative zone for the country. The area houses many important legislative, administrative and cultural buildings, including the Rashtrapati Bhawan (Presidential Residence), the Indian Parliament House, the North and South blocks, the secretariat buildings, National Archives, National Museum, and the India Gate. The Central Vista holds immense historical, political and cultural significance for Indians and it is amongst the country’s most well-known precincts.

In 2019, the Government of India initiated the redevelopment of the Central Vista in order to strengthen and modernise the existing governance infrastructure and re-envision Rajpath (now Kartavya Path), the central avenue, which runs from the Rashtrapati Bhawan in the west to the India Gate in the east. Refurbishment of the central avenue, supported by the latest amenities and infrastructure, would also ease distress and overuse of the existing facilities, while opening up an opportunity to rethink the avenue’s connection to people and the environment. 

The redevelopment proposal by CP Kukreja Architects, designed in association with Benoy Ltd., United Kingdom, was selected amongst the top six competition entries and was presented to the Central Public Works Department (CPWD) and the Ministry of Housing and Urban Affairs (MoHUA), Government of India. 

The proposal aims to carve a new identity for the capital by creating an inclusive, ecological and cultural precinct that is rooted in history and yet showcases India’s emergence as a force to be reckoned with in the 21st century. The design creates a people-centred, sustainable development plan supported by technology, that respects and responds to the historical, environmental and architectural contexts.

The site can be divided into three parts. On the west are the Rashtrapati Bhavan and the North and South Blocks that house the Defence and Finance ministries. The central part comprises the Kartavya Path, envisaged as a wide, landscaped public avenue with the new secretariat buildings proposed on its either side. Finally, a cultural hub is envisaged around the India Gate in the east, culminating in the Independence Tower, a new-age observatory, near the National Stadium. Guesthouses of princely states surrounding the lawns of the India Gate, including Jaipur House and Hyderabad House, and other structures of historical significance are proposed to be reused as museums and art galleries.  

A CELEBRATION OF INDIA''S MYRIAD HISTORIES
A significant idea proposed at the Central Vista is to extend the central axis till the banks of the river Yamuna in the east and to the reserved forest at the Delhi Ridge in the West, beyond the Rashtrapati Bhavan. This will revive the historical connection between the neglected river waters and the city by integrating it into the site''s landscape through long canals running along the Kartavya Path.  

Design elements for the new secretariat buildings are inspired by traditional Indian and Lutyens’-era architecture. For example, large monumental gateways punctuating the facade(s) are a contemporary reinterpretation of the Torana (sacred gateway) and the Gopuram (a monumental tower at a temple''s entrance), both of which are prominent features of Indian temple architecture. Other elements include jaalis (traditional perforated screens), chajjas (protruding slabs for shading), and central courts. The courtyards are shaded partly through pergolas, whose members are arranged to form an Ashoka Chakra, a Buddhist symbol that symbolises the Wheel of Time and is a part of the Indian Tricolour. In addition, red and beige sandstones are proposed for the facade to maintain the visual vocabulary of the existing Lutyens’-era architecture. 

CREATING A CITY FOR THE PEOPLE 
The transit plan opens up the central avenue as a completely pedestrian boulevard by diverting traffic through new roads running through the secretariat buildings. These new semi-public roads will be connected to the lateral roads on the avenue, which have been reimagined as underpasses for unobstructed pedestrian movement. 

Roads running in the east-west direction are proposed at the concourse level of the Secretariat buildings and the lateral roads running across the central avenue are reimagined as underpasses. All parking for the secretariat buildings is proposed on the ground and basement levels.  

An underground monorail connects the administrative and cultural buildings to Delhi’s Metro network, thereby easing access and reducing the need for motorised vehicles. Moreover, it increases accessibility to the central avenue for the public without obstructing the flow of the flourishing natural landscape. 

LANDSCAPE FOR URBAN RENEWAL, RECREATION, AND REJUVENATION
At the western end of the site, tree-lined avenues extend from the foot of Raisina Hill and merge into the central avenue where natural landscape reigns supreme. The verdant landscape features ghats (steps that lead to a water body) at the edge of the water canals, with trees densely populated on either side. Terraced levels extend from the central axis onto the front of the Secretariat buildings, adding to the three-dimensionality of the landscape and providing citizens with the opportunity to relax and gaze at the picturesque views.

The landscape on the east, surrounding the India Gate and the National War Museum, is focused on restoring existing parkland, lined with scrubs and meadows and interspersed with zones for social interaction, thereby rejuvenating the region''s biodiversity.    

Further up east, a 194.7 metres tall watchtower, the Independence Tower, is proposed to allow people to view never-before-seen panoramas of the capital city. Its height alludes to India’s independence in the year 1947, and hence bears an emotional significance. The tower''s form is a symbolic representation of folded hands, as the Indian greeting ''Namaste''.

CLIMATE-SENSITIVE DESIGN INTERVENTIONS FOR A SUSTAINABLE FUTURE 
Several active and passive sustainable design strategies are proposed to ensure the buildings have minimal environmental impact. 

At the master planning level, the dense vegetation acts as a heat sink, and the water channels have a cooling effect on the local microclimate. At the building level, the passive design strategies are centred around efficient channelling of air, water, and sunlight to create suitable indoor environments, thus reducing the dependence on artificial HVAC and lighting systems. Compact volumes enable mutual shading at the building level and minimise the solar heat gain. Planned around a series of courtyards, the secretariat buildings receive ample daylight and natural ventilation. The regular misting of courtyards in the summers helps reduce the ambient local temperature by 10-12 degrees celsius. These courtyards are integrated with pergolas for shading, water bodies for evaporative cooling, and roof gardens that act as heat sinks and thermal barriers. Double-skin facades with jaalis enable shading while serving as chutes for natural ventilation. Double-wall construction, insulated roofs and high-performance reflective glass further help in minimising the overall heat gain in the building.

Sunlight is used to generate electricity in the buildings through solar panels on rooftops, parking lots and walkways. Solar thermal energy powers the air conditioning system, and biogas is generated on the site through organic waste treatment. The design also proposes a smart waste management system with automated pneumatic waste collection and provision of waste segregation and collection points at regular intervals. All the rainwater from the site is proposed to be recycled and reused for flushing and irrigation. The design also proposes an integrated high-level automation technology system and artificial intelligence systems that enable efficient energy use and increased security in the secretariat buildings.

The proposal revamps and adds to the administrative and political infrastructure needed for the functioning of a rapidly progressing nation of 1.38 billion people. It takes on the underlying present-day urban planning challenges, from the dominance of car-oriented land use to the forsaken waters of the Yamuna. And finally, the design facilitates the creation of a lively urban public space, respectful of the local context and seamlessly integrated with the natural landscape, setting an example for how to create a city for the people at the very heart of Indian democracy.',
    TRUE,
    'IFF14', 'Dikshu C Kukreja', NULL, NULL
);

