) VALUES (
    'CSCAE', 'Primitivo González', 'noa@primitivogonzalez.com', 'Justice Palace in Burgos',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Burgos', 'Sapin',
    NULL, NULL,
    'An obsolete and old building, presenting an image of being inaccessible, is transformed into a contemporary courthouse, with a sense of closeness to the citizens.', 'There are public buildings that transmit a feeling of being “inaccessible”. This renovation of a 19th century courthouse in a neo-classical style, represents a radical change in the access and layout of the building. The entrance steps have been removed, and the semi-basement floor converted into the ground floor of the building, housing all public services. The result is an accesible building, with enough space for its use, well comunicated as placed in the city centre and giving a modern image of the Justice institucion.The project achived an Honorable Mention in the UIA Award “Friendly Spaces Accesible to All” (2014)', 'Faced with the common alternative of moving the courts from the building to a purpose built campus on the outskirts of the town and making them less convenient to get to,  the Ministry of Justice addressed the possibility of renovating the old building. The project firmly celebrates and supports this option, presenting strategies for adapting the building’s characteristics to current needs. We have managed to secure the survival of a building which is important in itself as a part of the urban landscape. The creation of an accessible, pleasant "new building” is conveyed in the image of the building, that brings closer the institution closer to the citizens',
    TRUE,
    'LDP36', 'Primitivo González', 13.226, NULL
);

