    external_code, authors, size_sqm, year_completed
) VALUES (
    'Sir Syed University Of Engineering & Technology', 'Nihal Ahmed Barry', 'nihalahmed212@gmail.com', 'Redefining Religious Spaces - Mosque as a Social Catalyst',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Uthal - Pakistan', 'Unknown',
    NULL, NULL,
    'The mosque in Baluchistan, Pakistan aims to redefine traditional religious structures by implementing sustainable development goals. The goal is to design a sustainable and communal space that promotes a sense of ownership through place-making strategies..', 'Mosques in Pakistan are now limited to prayer, but in early Islam, they were community centers for social cohesion without discrimination. This project aims to design a sustainable place using a neo-vernacular approach respecting regional materials & construction with an open, nature-connected layout that is inclusive for all ages. The program promotes community programs like community kitchens, bazaars, and safe spaces for play to increase visibility on the street.', 'Goal 2 has been achieved by implementing a program, community kitchen and farming, to address food scarcity. Goal 5 is achieved by designing an inclusive space that discourages discrimination and promotes gender equality. Goals 6 & 13 mitigate climate change by incorporating rainwater harvesting, sanitation practice and use of vernacular materials Additionally, the project provides opportunities for local businesses to thrive, such as a bazaar, to uplift the regional economy in line with Goal 8.',
    TRUE,
    'IFF58', 'Nihal Ahmed Barry, Wajiha Siqqdiqui & Muhammad Mehdi,', NULL, NULL
);

-- Row 93: IFF62
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'School of Architecture, Planning and Design (SAP+D), Mohammed VI Polytechnic University', 'Prof. Hassan Radoine', 'hassan.radoine@um6p.ma', 'Integrated approach  of sustainable territorial development, case of the villages of Nouaji and Tanmirt',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_V', 'Benguerir', 'Morocco',
    NULL, NULL,
    'The integrated project of the villages of Nouaji-Tanmirt is a living laboratory of a territorial development approach. It aims to improve the socio-economic conditions of the local population while carrying out urban regeneration and a community-based approach.', 'The Villages of Nouaji and Tanmirt are located in Benguerir, Morocco, an area that is a model of innovative projects, less than 3 km from the new green city and the Mohammed VI Polytechnic University.
To support this dynamic, the integrated approach consisted of an urban regeneration of these villages and an improvement of the population''s living conditions through the creation of income-generating activities in crafts and agriculture.
This approach is based on territorial integration by connecting the villages to the city, sectoral integration and finally a participatory approach with the skateholders', 'This project addresses the following SDGs:
- SDG 4: quality education
Beyond the program for the promotion of school life, we consider that the educational ecosystem, school and university, are the departure point for territorial transformation
- SDG 8: decent work and economic growth
Through the creation of intra-village and inter-urban economic flows (villages - green city) and through the strengthening of the agricultural and artisanal fabric.
- SDG 11: sustainable city and community
Through social cohesion, the creation of a green grid and the rehabilitation of a heritage of clay houses.
- SDG 17: partnerships to achieve objectives
Through a collective intelligence of several partnerships and capacity building offers between the university, the community and the city''s stakeholders.',
    TRUE,
    'IFF62', '•	Hassan Radoine •	Ismail Hammoumi •	Kaoutare Amini Alaoui •	Mohammed Reda Lazreg •	Fouad Maytoussi', NULL, NULL
);

