    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Studio Cardenas Conscious Design', 'Arch. Mauricio Cardenas Laverde', 'm.cardenas@studiocardenas.it', 'Microclimatic Pavilion',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_I', 'Milan', 'Italy',
    NULL, NULL,
    'Microclimatic Pavilion is a first of its kind sustainable dry mounted bamboo bearing structure designed, unlike mainstream approach, to be easily assembled without the need of specialized manpower.', 'Is in the Fabbrica del Vapore where is possible to experience the Microclimatic Pavilion, built in 2006 in the context of Milan’s Salone del Mobile for DAGAD Association. An exhibition space, a comfort point for people and technology to meet and enjoy the pleasant effects of microclimate control where apparently distant worlds coexist: high tech metallic joints and low tech of bamboo. An urban oasis to protect against the effects of the heat island phenomenon, in line with the 2030 Agenda SDGs.', 'The Microclimatic Pavilion’s objective, other than holding exhibitions, is that of contributing to reduce the urban heat island effect. Studies have found that local warming caused by this phenomenon significantly increases temperatures in addition to global warming. The project, as an urban oasis, promotes sustainable use of bamboo as a construction material, tackling at least 7 SDGs, and takes action to combat climate change ensuring health and well-being for a sustainable development.',
    TRUE,
    'LDP63', 'Arch. Mauricio Cardenas Laverde', NULL, NULL
);

-- Row 96: LDP68
