    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Hoang Thuc Hao and 1+1>2 Architects', '1+1>2 Architects', 'amedia@112.com.vn', 'Village System',
    'IMPLEMENTED', 'APPROVED',
    0.0, 0.0,
    'SECTION_IV', 'Ha Noi', 'Viet Nam',
    NULL, NULL,
    'Globalization has brought the world together but it has obliterated and vanished identities. The purpose of the project is to create a relevant living environment for each specific community.', 'In order to bring happiness to the users and the society, protect the cultural architecture diversity in general and particularly in residential architecture, we advocate research and practices according to the "1+1>2" philosophy, which is vernacular core values incorporate with vanguard academic knowledges. All together towards enhance and acculturate local identity, contribute to shaping lifestyle, inspire people and permeate vernacular culture. Crucially, architects must comprehend which core values and innovations are appropriate for each particular community.', 'Practicing in settlement architecture has help us reveal the beauty of local lifestyles, it also shows us the unlimited ability of architecture to connect and support people, raise happiness for the users, for the buildings and for the architects themselves. Sustainable environment is essential, but more important is to create a sustainable lifestyles respecting history and future. That is the motivation in our creativity.',
    TRUE,
    'LDP68', 'Hoang Thuc Hao and 1+1>2 Architects', NULL, NULL
);

