    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Natureza Urbana', 'Breno Pilot', 'breno@naturezaurbana.net', 'Tourism Masterplan for Sal Island - Cape Verde',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_V', 'Sal Island', 'Cape Verde',
    NULL, NULL,
    'This work included the development of the Sal Island tourism master plan, aiming to identify the particularities, potentialities and needs of the island for a territory coherent tourism development.', 'The Tourism Masterplan for Sal Island, Cape Verde, aimed to identify the particularities, potentialities and needs of the island for a territory coherent tourism development. The initial step consisted in understanding issues related to the dynamics of tourism in the island, analysis of the tourist inventory, attractions and tourist infrastructure and identification of the opportunities and challenges for composition of new routes or strengthening of existing products.', 'The construction of the future vision for the island starts from the intersection of the analyzes, aiming at the definition of strategies and action plans based on the following premises: sustainability, circular economy, and experience tourism, prioritizing opportunities for visitor engagement with the place. In the areas of strategic action, potential tourist segments and products that lead to proposals are identified, divided between actions and projects.',
    TRUE,
    'IFF18', 'Pedro Lira and Manoela Machado (Coordination); Camila Sanches Julia Ximenes (Project Leaders), Carolina Passos, Julia Marini, Laís Pimentel, Laura Figueiredo and Tiago Martinelli (team).', NULL, NULL
);

-- Row 102: IFF19
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Natureza Urbana', 'Breno Pilot', 'breno@naturezaurbana.net', 'Tourism Masterplan for São Nicolau, São Vicente and Santo Antão Island, Cape Verde',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_V', 'São Nicolau, São Vicente and Santi Antão', 'Cape Verde',
    NULL, NULL,
    'This project aimed the development of the tourism Master Plan of the islands in the north consistent with the territory and with its socioeconomic demands considering their cultural and natural particularities.', 'The implementation plan guided the execution of the Master Plan, which indicated the coordination structure responsible for implementing the plans and projects, prioritization, and implementation scenarios. In the initial stage, the project addressed tourism dynamics in the region, tourist demand on the islands, inventory and infrastructure analysis, and identified opportunities and challenges for the composition of new itineraries or strengthening of existing products.', 'The future vision for each island was constructed by intersecting the analyses, aiming to define action plans based on: sustainability, circular economy, and experiential tourism, prioritizing opportunities for visitor engagement with the local area. Additionally, considering the projects'' relationship with the United Nations Sustainable Development Goals (SDG), studies were conducted to assess socio-environmental and socio-cultural impacts, as well as mitigation processes.',
    TRUE,
    'IFF19', 'Pedro Lira and Manoela Machado (Coordination); Camila Sanches (Project Leader), Carolina Passos, Julia Marini, Julia Ximenes, Laís Pimentel, Laura Figueiredo and Tiago Martinelli (team).', NULL, NULL
);

-- Row 103: IFF20
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
