    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'College of Architecture and Urban Planning, Tongji University, Shanghai, P.R.CHINA', 'XIE Shuting', '2243270539@qq.com', 'A Metro Network Stitched Together by Commerce——Responsible Consumption and ProductionA Metro Network Stitched Together by Commerce——Responsible Consumption and Production',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Shanghai', 'China',
    NULL, NULL,
    'Subway stations in the city bring great convenience for people to travel quickly, but also open up underground space, connecting every node in the city into a network.，giving all people access to basic public services and improve the quality of life. The completion of the IAPM Shopping Mall above the Shaanxi South Road subway Station in Shanghai integrates the subway station with large commercial and urban public Spaces. While improving people''s living quality, this construction mode reduces resource consumption, environmental degradation and pollution of the city and increases the net welfare income of economic activities through the highly integration of resources and functions, as well as the increase of urban green space. It is a sustainable pattern of consumption and production.', 'Subway stations in the city bring great convenience for people to travel quickly, but also open up underground space, connecting every node in the city into a network and give all people access to basic public service and improve the quality of life.
Shaanxi South Road belongs to Huangpu District of Shanghai, and is located at the junction of Jing ''an District, Huangpu District and Xuhui District. It is also the intersection of two main traffic arteries, Huaihai Middle Road and Shaanxi South Road. Huaihai Road near it is the second most prosperous commercial street in Shanghai after Nanjing East Road, where many department stores such as Printemps, Parkson, Huating Isetan and 200 Yongxin gather together to form the Huaihai Road business circle.
Shaanxi South Road Hub station is the transfer station of metro lines 1, 10 and 12, all of which are underground transfer stations. There are many bus stations around the station, and the buildings around the station are mainly commercial, as well as some schools and residential communities. From the subway station to Hongqiao and Pudong International Airport instant, the overall traffic is very convenient, gather a huge passenger flow. Shaanxi South Road station has a total of 10 subway entrances. Exit 1 connects to Printemps Paris, exit 2 connects to Parkson Mall, exit 4 connects to Yongxin Building, and Exit 6 to 10 connects to Shanghai World Trade IAPM Mall.
Subway stations in the city bring great convenience for people to travel quickly, but also open up underground space, connecting every node in the city into a network and give all people access to basic public service and improve the quality of life.
Shaanxi South Road belongs to Huangpu District of Shanghai, and is located at the junction of Jing ''an District, Huangpu District and Xuhui District. It is also the intersection of two main traffic arteries, Huaihai Middle Road and Shaanxi South Road. Huaihai Road near it is the second most prosperous commercial street in Shanghai after Nanjing East Road, where many department stores such as Printemps, Parkson, Huating Isetan and 200 Yongxin gather together to form the Huaihai Road business circle.
Shaanxi South Road Hub station is the transfer station of metro lines 1, 10 and 12, all of which are underground transfer stations. There are many bus stations around the station, and the buildings around the station are mainly commercial, as well as some schools and residential communities. From the subway station to Hongqiao and Pudong International Airport instant, the overall traffic is very convenient, gather a huge passenger flow. Shaanxi South Road station has a total of 10 subway entrances. Exit 1 connects to Printemps Paris, exit 2 connects to Parkson Mall, exit 4 connects to Yongxin Building, and Exit 6 to 10 connects to Shanghai World Trade IAPM Mall.', 'In 2015, Shanghai World Trade IAPM Mall above Shaanxi South Road Subway Station was fully completed, integrating the subway station with large-scale commercial and urban public space. While improving people''s living quality, this construction mode reduces resource consumption, environmental degradation and pollution of the city and increases the net welfare income of economic activities through the highly integration of resources and functions, as well as the increase of urban green space. It is a sustainable pattern of consumption and production.',
    TRUE,
    'IFF27', 'Shanghai Lab, Tongji University', NULL, NULL
);

