    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'College of Architecture and Urban Planning, Tongji University, Shanghai, P.R.CHINA', 'WU Xiaoyu', '1807234699@qq.com', 'Shanghai Jing''an Temple Metro Station Analysis',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Shanghai', 'China',
    NULL, NULL,
    'Jing''an Temple Metro Station is one of the most important and densely populated stations in Shanghai''s metro network. It is located in the Jing''an Temple business district, the core of Shanghai, and has not only a high density of urban construction above ground, but also the most dense underground space system within the metro station area.', 'A large number of high-density urban buildings are located in and around the Jing''an Temple Subway Station in Shanghai, and a large number of underground spaces have been developed with the construction of underground rail transit, resulting in a large number of underground interchange channels, underground streets and underground commercial spaces. This study analyzes and evaluates the above-ground and underground station public spaces, analyzes the problems of underground station public spaces, and proposes targeted strategies to improve the quality and vitality of underground station public spaces, to further link the underground space with the life of citizens, and to promote sustainable urban development.', 'The above-ground station area public space of Jing''an Temple metro station well combines the transportation facilities used for daily commuting with people''s daily life through public spaces such as plazas, green areas and pedestrian streets, which provides good protection for the physical and psychological health of urban residents and can be benchmarked against  SDG 3. The reliable underground urban transportation infrastructure construction can be benchmarked against SDG 9, which provides great convenience for people to travel. The integrated development of above- and below-ground space within the station area is an excellent model for promoting urban sustainability in Shanghai, which can be benchmarked against SDG 11. Although the latter two indicators still have obvious flaws and shortcomings in the current study, the strategies proposed in this study will hopefully provide some reference value.',
    TRUE,
    'IFF30', 'Shanghai lab, Tongji University', NULL, NULL
);

