) VALUES (
    'BVO ARQUITECTOS', 'Gustavo Vera Ocampo', 'veraocampo@me.com', 'FIREFLY PROJECT learning about energy efficiency',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Montevideo', 'Uruguay',
    NULL, NULL,
    'Flashforward concept: a firefly project, a maximum of light with a minimum waste of resources. The Firefly Pavilion is an experimental model space, temporary icon and center for learning sustainable architecture.', 'The project is integrated at Montevideo’s waterfront, the city''s balcony towards the sea.
A contemporary architecture able to remix in an ecological way the urban and environmental contexts promoting a wide community consciousness beyond its own ephemeral existence.
Energy efficiency: to prove that is possible to build in a more efficient way if all environmental conditions are considered; topographical, climatic, semantic, functional and technological; to develop an idea that takes advantage of them.', 'RIGHT TO THE CITY
The building is inserted into the public promenade RAMBLA, a place for the expression of all citizens, and a site for the exchange of collective experiences.
The tower intends to continue and reaffirm this dialogue of social, cultural and urban integration, restoring Gasometer 5, part of the industrial heritage of the late 19th-century city. 
An emblematic space within the city, it accommodates a variety of typologies as it takes into account economic and administrative constraints, within a neighborhood that has an identity and a history of its own. The Sur and Palermo neighborhoods are known as the cradle of the Afro-Uruguayan culture. a major contribution to the establishment of a sense of belonging.',
    TRUE,
    'IFF32', 'Gustavo Vera Ocampo, Martín Boga, Pedro Berger, Julia Pereda, César Reisch, Carla Ribas', NULL, NULL
);

-- Row 114: IFF33
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Project: As If', 'Leroy Cheng', 'leroy.cheng@proj-as-if.com', 'Crafted Prosumption – Adopting Doma for Sustainable Urban Strategies in Prosumption Model',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Hong Kong', 'Unknown',
    NULL, NULL,
    'Giving up the old urban strategies, this project proposes Doma as the spatial device to set up a new sustainable linkage between places and people in response to the uptrend of prosumption economy.', 'An abrupt change in living habits and meaning in places is widely observed after the pandemic. Accompanying the increasing prosumption behaviors under the customization fad, the current urban strategies in assigning homogenized programs to places become unfit under both micro- and macro-perspective. After study, Doma, a versatile and adaptable component in Japanese houses, may be the solution for its potential to cultivate sustainability and synergize future development in the built environment.', 'Curating programs for placemaking has been downplayed in urban planning due to the rise of individualized prosumption behaviors and increasing contactless interactions in the post-pandemic era. To encourage physical interactions, an adaptable spatial device down to the household scale being able to constantly transform and cope with the new changes, including the new form of cultural hierarchy, social interactions and economic structures become more important to sustain our future development.',
    TRUE,
    'IFF33', 'Leroy Cheng', NULL, NULL
);

-- Row 115: IFF36
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'International Associate AIA, PhD Candidate University of Calgary, AB, Canada', 'Kulsum Fatima', 'kulsum.fatima@ucalgary.ca', 'Building Better from LEED to Living water systems for SDG6',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Calgary', 'Canada',
    NULL, NULL,
    'Connecting UN SDG6 to other UN SDGs', 'Prepare a narrative using exemplary building examples built in last ten years in North America that emphasize on transition from LEED certified to LBC certified building water systems. This narrative will highlight the role of design interventions in achieving SDG6 and its role in influencing social and physical environments. Additionally, this intend to explore the connections between SDG6 and other SDGs achieved because of SDG6. As a result, it will outline the role of design interventions in establishing these connections and offer a unique perspective for knowledge dissemination around good design practices to achieve SDG6.', 'UN SDG6 is the central theme for this idea. The building design interventions covered are specific to the achievement of UN SDG goal 6, and connects with the achievement of UN SDG 11, 12, and 13,  and shares value with UN SDG 3, 4, 9 and 16.  In doing so, this idea will transform water design elements into opportunities for user engagement, and empowerment, that promotes UN SDG 6 applications and can be replicated as a set of good practice at locations motivated to incorporate similar water sustainability innovations.',
    TRUE,
    'IFF36', 'Kulsum Fatima', NULL, NULL
);

-- Row 116: IFF38
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
