    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Centre for Green Building Materials and Technology', 'Ar. Neelam Manjunath', 'cgbmtblr@gmail.com', 'Let’s Build with Bamboo',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Bengaluru', 'India',
    NULL, NULL,
    'At the COP27, Bamboo has been named as one of future technologies to tackle climate change. Let’s Build with Bamboo is the first comprehensive book on Bamboo Construction curated for a wide audience.', 'A traditional, eco-friendly, & cost-effective construction material, Bamboo offers a sustainable alternative to most manufactured materials. Let’s Build with Bamboo is the world’s first comprehensive guidebook about bamboo construction informed by vernacular knowledge and on site practical application illustrating the modern usage of this material. By sensitising architects, engineers and academicians, the book will instil confidence in readers world over to adopt bamboo as material of choice.', 'SDG 4(4.4 & 4.7): Spread knowledge of bamboo construction at grassroots 
SDG 8(8.2 & 8.3): Bamboo based construction has economic & social benefits, spurring green economy
SDG 9: Support to industry, innovation & infrastructure supporting development 
SDG 11(11.1, 11.3 & 11.b): A beacon for sustainable communities by green construction
SDG 12(12.7, 12.8 & 12a): Responsible construction by use of sustainable materials
SDG 13: Bring awareness about bamboo playing a major role in climate change.',
    TRUE,
    'IFF38', 'BOOK CONCEPT, DESIGN AND AUTHOR: Ar. Neelam Manjunath   COVER PHOTO AND DESIGN: Ar. Neelam Manjunath   BLURB: Ar. Anand D K, Dr. Sanjeev Singh   CURATOR AND CO-EDITORS: Ar. Neelam Manjunath, Ar. Prof Anand D K, Dr. Sanjeev Singh, Dr. Jagadish Vengala   LINE EDITORS: Ar. Neelam Manjunath, Ar. Rajesh Advani   TEXT REFERENCING: Ar. Radhika Gopinath, Ar. Sagar Jayaram, Veronica, Nayana Badiger     PRINTED BY Judge press Grafi print private limited W.Q. Judge Press, 97,Residency Rd, Bengaluru. Karnataka 560025   FORWORD BY N. Sivasailam , IAS (R) Arun Kr Bansal. IFS( R)   DESIGN CREDITS Concept and Layout by Ar. Neelam Manjunath   Graphic Design by Karthik Burra   PICTURE RESEARCH: Ar. Sagar Jayaram, Vivek Cheekoti, Shreya Gaikwad, Veronica   IMAGE/PHOTO REFERENCING: Vivek Cheekoti, Shreya Gaikwad, Veronica   COMPILATION: Ar. Sagar Jayaram, Ar. Sowmya, Ar. Sonali Srivastava   FORMATTING: Ar. Mogilisetty, Nikhil Prasanth , Vivek Cheekoti,  Nayana Badiger', NULL, NULL
);

-- Row 117: IFF40
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'College of Architecture and Urban Planning, Tongji University, Shanghai, P.R.CHINA', 'Xiong Yixuan', 'dnjchz@gmail.com', 'Hanzhong Road Metro Station',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Shanghai', 'China',
    NULL, NULL,
    'Hanzhong Road Station, located in Jing''an District, Shanghai, China, is the interchange station of Shanghai Metro Line 1, Line 12 and Line 13, put into use on April 10, 1995 with the opening of Line 1; Passed Line 12 and Line 13 on December 19, 2015.', 'In the 1990s, there were large areas of low-rise residential buildings and little high-rise apartments and office buildings near Hanzhong Road Station. Along with the construction of the subway, the old residential buildings were gradually replaced by high-rise commercial complexes, office buildings and new residential communities.
Circumstance:Hanzhong Road Station is a five-story island-platform. For the platforms of Line 12 and 13 are arranged upward-and-downward counterpoint, there is no need to transfer through the station hall; The station hall of Line 12 and 13 connects to the hall of Line 1 through an underground passage. As an interchange station, the station has multiple floors with high pedestrian flow during peak hours, but clear flow lines ensure its traffic efficiency.  
The station has ten entrances distributed in three street blocks. Entrance 1-4 are located above the station hall of Line 1 and Entrance 5-10 above the station hall of Lines 12 and 13. Entrance 5 and 10 lead to underground commercial space and the accessible elevator is located near Entrance 10. The entrances lead to five roads. Among them, Hengfeng Road and Hengtong Road are traffic arteries. 
Buildings around the station are mainly high-rise commercial and office buildings. Residential areas are further on the north and southeast sides. The station hall area of Line 12 and 13 is now covered by a Shopping Center whose underground part is directly connected with the station.   
The station is relatively close to Suzhou River and adjacent to Hengfeng Road Bridge on the west side. Entrances 3, 7, 8, and 9 are only one block from the Suzhou River along which is waterfront landscape green space.
Questions and Optimization:Entrance 1-4 are located above the hall of Line 1. Due to its early construction period, the vertical transportation facilities are crude. Heat map shows the north side (commercial-office area) of Hanzhong Road Station has a higher pedestrian flow compared to the south side (residential area). Entrance 1 in this area has a dense flow of people during rush hours with a narrow stairs and no two-way escalator; The barrier-free elevator near entrance 10 is hidden behind the street greening whose accessibility and visibility need improving.
Passengers entering and exiting the station are mainly office staff and residents nearby with a high demand for small restaurants, fresh food, convenience stores, etc. However, except for entrance 5 and 10 leading to the shopping mall. There is only one bakery next to entrance 1 and no small commercial service facilities near the other entrances. A temporary building near Suzhou River at Entrance 2 and 3 currently serve as a food market, indicating a lack of community oriented commercial support. 
The station is near Suzhou River. However, along Hengfeng Road and Meiyuan Road which connect the station and landscape area are warehouses and parking lots. Sight is squeezed by Hengfeng Road Bridge, lacking direct visual connection and prompts. The pedestrian experience can be optimized by renovating local streets, connecting subway stations with landscape spaces.', 'According to existing studies, Hanzhong Road Station is seen as an interchange station whose traffic efficiency and the experience of underground space are mainly concerned. But it is located in a mixed-functional area in the central city of Shanghai. Which means the circumstance is complex and the station serves a large quantity of passengers getting out and in every day. Therefore it should not only transfer but also be an infrastructure connecting to the city or the community and more accessible to the citizens. 
Based on data collection and field research, this study analyses the relation between the station and its circumstance, including roads, buildings, city landscape as well as urban activities around it, and  proposes ideas-from the aspects of convenient facilities and spatial experience-to help make it a more positive and active part of the city in which it deeply roots. The goal is to improve transportation efficiency, enhance the convenience of city lives and increase the vitality of urban public space，creating a sustainable city and community.',
    TRUE,
    'IFF40', 'Shanghai Lab, Tongji University', NULL, NULL
);

-- Row 118: IFF41
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
