    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Prefeitura Municipal de Sobral', 'Yvo Gabriel Sousa Galvão', 'yvogalvao@sobral.ce.gov.br', 'Jordão Occupation Pilot Project',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Sobral', 'Brazil',
    NULL, NULL,
    'Located in Jordão, district of Sobral, in Brazil, the project provides housing adaptation for 5 families in social vulnerability occupying an abandoned property, once attached to a municipal school.', 'As a forerunner of a housing policy based on the reform and adaptation of abandoned buildings for purposes of social interest at local and national level, the pilot project seeks to adapt the public building for social housing, so that the building can adequately receive its residents by promoting better living conditions at low cost.', 'Guided by the conversion of empty buildings into sustainable popular housing, as it uses idle properties for the Pilot Occupation Project in Jordão, which promotes their renovation and adaptation to social housing, at low cost, not keeping residents away from their place of origin, influencing the development of a more compact, inclusive and, consequently, more sustainable city.',
    TRUE,
    'IFF41', 'Janaina Carneiro Americano de Brito; Lucas Golignac Lessa; Anderson Mateus Santos da Silva; Marília Gouveia Ferreira Lima.', NULL, NULL
);

-- Row 119: IFF47
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'IAB, Institute of Architects Bangladesh', 'Sarita Rahman', 'saritaanusha@yahoo.com', 'Bagaan, a vertical community farming',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Dhaka', 'Bangladesh',
    NULL, NULL,
    'Vertical farming in urban areas can be a great solution for both senior citizens and job-seeking young people.

For senior citizens, vertical farming can provide them with a new and exciting hobby that can keep them active and engaged in their community. It can also provide them with a source of fresh, healthy produce, which is particularly important for older individuals who may have limited mobility or access to transportation.

For job-seeking young people, vertical farming can offer a range of opportunities. They can work in urban farms as growers, caretakers, or even in marketing and sales. As urban farming continues to grow in popularity, there will be more job opportunities for people with a range of skills and interests.

In addition to job opportunities, vertical farming can also offer young people the chance to learn about sustainable agriculture and urban food systems. They can gain valuable experience and knowledge that they can use to pursue careers in related fields or even start their own businesses.

Overall, vertical farming has the potential to benefit both senior citizens and job-seeking young people in urban areas. It can provide fresh produce, employment opportunities, and a sense of community and purpose.', 'With the climate change, Bangladesh, a deltaic plain, is expected to experience frequent flooding and other ecological hazards which can lead to extensive pressure in agricultural production and biodiversity. As a result, the food security will be at risk. This paper discusses in details the elements related to farming such as land, water, pesticides, seeds, food supply, food safety, etc. and its impacts on those components in Bangladesh. As for instance, it is discussed how agriculture promotes the land loss and an estimated total area of the tropical forest in Bangladesh was reduced to 900 km2 in 2019, from 966 km2 in 2001. Also, a discussion takes place regarding the food supply and the idea of food miles is briefly mentioned and how it is impacting the supply of food and is adding to the woes of the farmers in Bangladesh, particularly in light of pandemics like Covid-19.

The paper further discusses the potential of multi-disciplinary intervention, including architecture, to address the concerns related to agriculture and climate change. The concept of vertical farming from an architectural point-of-view is discussed in this paper. Case studies from the projects of renowned architects like Dr. Ken Yeang are studied to fully the principles of this kind of farming along with studies of successful implementations from countries like Japan, South Korea, Netherlands etc. 

Lastly, the paper introduces the project Bagaan- a new visionary model for the climate adaptation of off-grid, integrated and resilient urban farming that can power and feed self-reliant families around a neighborhood. The proposed project is expected to reduce carbon emission and also the land use by 98% and grow the percentage of 100% organic while creating job opportunities and self-reliance within a community, mostly amongst the elderly adults. The paper shows a positive correlation in the ageing population getting involved in farming and green works. Hence, the target group of Bagaan is mostly the elderly citizens, who will be comprising of bigger portion of the demography of Bangladesh by the year 2050. Bagaan aims to explore the production of diverse range of agricultural products within a climatically controlled containers, with provision of machine learning technologies with easy-to-use UXP (user experience) platform, while reducing the food mile mentioned before, but the enhancing the quality of food. The paper also briefly mentions how Bagaan satisfies the Sustainable Development Goals 2030, by directly sufficing the Goal-1, 2, 3, 5, 8, 9, 10, 11, 12, and 13.', 'Smart agriculture and next-gen farmers are important concepts for achieving the SDGs related to agriculture and food security.

Smart agriculture involves using modern technologies such as precision agriculture, drones, sensors, and artificial intelligence to optimize crop yields, reduce waste, and increase efficiency. It also involves using data and analytics to make informed decisions about planting, fertilizing, irrigation, and pest management, among other things.

Next-gen farmers, on the other hand, refer to the younger generation of farmers who are more educated, tech-savvy, and diverse than their predecessors. These farmers bring new ideas, skills, and perspectives to the agricultural sector, which can help drive innovation, improve productivity, and enhance sustainability. Next-gen farmers can also play an important role in promoting sustainable and regenerative farming practices that protect the environment and support local communities.

Together, smart agriculture and next-gen farmers can help address some of the major challenges facing the agricultural sector, including climate change, resource scarcity, and food insecurity. By adopting innovative technologies and practices, and by promoting diversity and inclusivity in the agricultural workforce, we can create a more sustainable, equitable, and resilient food system for the future.',
    TRUE,
    'IFF47', 'Sarita Rahman, Minami Islam Khan', NULL, NULL
);

