    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'euZen Architecture / Theodora Kyriafini - Fotini Lymperiadou & Co L.P. / Architects: T. KYRIAFINI, F. LYMPERIADOU, K. DESPOTIDIS, A. EFTHIMIADOU / Associates: I. DESPOTIDIS, C. SAXONI, E. MALEZI, A. IOSIFIDOU, P. GALANIS, I. KEFALONITI, A. LYMPERIADOU, M.', 'Theodora Kyriafini - Fotini Lymperiadou & Co L.P.', 'info@euzenarchitecture.com', 'Innovative Bioclimatic European School in Crete',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_II', 'Heraklion, Crete', 'Greece',
    NULL, NULL,
    '1st prize of the 2012 International Architectural Competition organized by UIA & School Buildings Organization. European School is addressed to 780 pupils aged 5 to 18 years old. Construction is planned to start in 2024.', 'Bringing nature to the heart of the school is the catalyst for users to experience joy and freedom, promoting health.
Courtyards surrounded by small scaled buildings and their arcades embrace pupils and foster the feeling of community while improving the microclimate.
Passive heating and cooling methods are adopted incorporating design principles of ancient and vernacular local architecture.
Local, low embodied energy clean materials achieve a high-quality indoor air, resulting in the well-being for the users.', 'The school through education acts as a prototype for experiential lifelong learning in environmental awareness, involves local community and nearby university, promoting good health & the well-being of its users.
Small scaled buildings and inner courtyards surrounded by arcades are formed as natural environments, adjacent to south facing classrooms. Nature’s rhythms are observed and respected.
Achieving almost zero energy consumption, it presents an affordable and clean energy example of bioclimatic design.',
    TRUE,
    'IFF50', 'Theodora Kyriafini, Fotini Lymperiadou', NULL, NULL
);

-- Row 121: IFF53
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
