    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Estúdio Lava - Paisagem, Arquitetura e Arte and Ensamble de Arquitectura Integral', 'Julia de Andrade Reis', 'julia@estudiolava.com.br', 'Cerros Orientales Biocultural Park',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Bogotá', 'Colômbia',
    NULL, NULL,
    'The Park is a nature-based infrastructure that articulates the peri-urban edge through environment, agricultural production and culture, consolidating resilient landscapes and sustainable communities', 'The project works as a system of articulation networks between park, countryside, and city. The integration of collective spaces, equipments (nodes), and zones, promotes the appropriation and perception of the landscape through its natural, productive, aesthetic, historical, social, and symbolic values, consolidating an infrastructure from the local communities aimed at environmental conservation and recovery, agro-ecology, urban and rural culture, and the very identity and memory of Bogota.', '. Agro-ecological practices and environmental recovery through agroforestry (SDG 2);
. Recovery of waterways that supply the city, through phytoremediation gardens and the consolidation of riparian forests for their protection (SDG 6);
. Resilient design for the management of risks associated with floods, landslides, and other climatic events aggravated by Climate Crisis (SDG 11 and 13);
. Recovery of native flora and fauna by replacing exotic species with endogenous ones (SDG 15)',
    TRUE,
    'IFF53', 'Julia Reis; Lucas Bueno; Simón Fique; Juan Pablo Pardo; David Moreno; Daniella Gerbasi; Aline Gaspar; Juliana Sáenz', NULL, NULL
);

-- Row 122: IFF54
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Casa Cidade Arquitetura e Urbanismo', 'Renata Fragoso Coradin', 'renata.coradin@casacidade.com.br', 'Guaicuri: Social Urbanism',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo / Brazil', 'Unknown',
    NULL, NULL,
    'The Guaicuri Project implies on the requalification of public areas into a new, green, front with leisure and preservation cores along the Guaicuri canal, articulating mixed-use social housing complexes', 'Access to qualified housing, education, health, sanitary conditions, and quality leisure spaces are premises of the Guaicuri social urbanism project, proposed for an area approximately of 87.000m² in the extreme south of the city of São Paulo. It proposes a linear park along the canal where new and existing dwellings compose open leisure spaces, in addition of institutional uses with a new nursery and new health unit, as well as commercial spaces on the ground floor of the buildings.', 'The urbanization and provision of new social housing units in the Guaicuri area is one of the solutions to a social vulnerability context, where residents now live in precarious houses above a polluted stream. The main goal of the project is to combine public green areas, adequate and accessible housing, commercial and institutional spaces to promote coexistence, equity and well-being. It mainly contributes to the first objective of sustainable development goals, “no poverty”.',
    TRUE,
    'IFF54', 'Renata Fragoso Coradin; Amanda Ramos Silva Santos; Ana Paula Coelho; Caroline de Souza Moura; Felipe Maike Lima de Souza Oliveira; Giovanna Sambugaro; Gustavo Bento Silva; Ian dos Santos Araújo; Juliana Bizzi Radi de Ponti; Juliana Nunes Watanabe; Letícia Ferreira; Matheus de Vasconcelos Casimiro; Soraya Mayumi Tamate Palmeira de Paula; Suellen Cristina Pivato; Alexandre Horiye Ferreira; Daniela Arduino Dezidera Horiye; Joice Lopes; Elisabete França; Ana Clara Gurgel; Fernanda Souza Silva; Maria Teresa Cardoso Fedeli; Mayra Rodrigues; Vanessa Padiá de Souza', NULL, NULL
);

-- Row 123: IFF57
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Faculty of Public Health at USP', 'Isabel Ammann Saad', 'isabelsaad8@gmail.com', 'Bioremediation and waste management combined with the recovery of canalized urban streams: Project proposal in the Jaguaré stream',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Sao Paulo', 'SP',
    NULL, NULL,
    'Return the curves and the margins of the channeled urban river with a floating structure where macrophyte plants are trapped that help in cleaning the water via Bioremediation, combined with the management of floating waste.', 'This project aims at the sustainable treatment of water from channeled rivers and the removal of surface residues from the Jaguaré stream in Sao Paulo. Aiming to increase the quality of life in the surroundings and the environmental quality of the floodplains that were reduced for the implementation of roads. It is a design proposal for floating structures on the Jaguaré Stream that simulate the meandering floodplains characteristic of the rivers of the Alto Tietê Basin, in an allusion to the curves that no longer exist.', 'From the point of view of sustainability and resilience, the project is an action to clean polluted water and minimize the waste that reaches the oceans. The project also elaborates forms of explanatory awareness for the local communities. The actions contemplated here are in line with Sustainable Development Goals number 3, as it encourages the cleaning of water that may contain disease vectors. SDG 4 with regard to environmental education actions for the population. SDG number 6 as it is a water treatment that contains sewage and diffuse pollution. And SDG 15 that indicates resilience and sustainability within the city and its channeled rivers.',
    TRUE,
    'IFF57', 'Isabel Ammann Saad', NULL, NULL
);

-- Row 124: IFF6
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'HOV', 'David Raponi', 'hov@hov.it', 'FLOLONY (Float-On/Float-Off/Colony)',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_I', 'Everywhere', 'Unknown',
    NULL, NULL,
    'FLOLONY is a changeable buoyancy floating housing unit, made up of a mobile naval architecture equipped with autonomous energy and developed on a geometry which enables the vessel to adapt to any marine conditions, even the extreme ones. The structure has a large surface in contact with the open space and the upper part, always out of water, is controlled by systems that can guarantee the maximum supply of vital elements (light and water), useful for the residential/productive metabolism of the colony.', 'FLOLONY conceives a housing unit in a marine environment, where a community of individuals chooses to live a short or long part of their lives on the open sea. As for the essential services for life the unit is autonomous and, according to its potential configurations and equipments, it can be independent (therefore with no need of external supplies) for periods varying from a few months to several years. Moving along marine routes within the temperate/equatorial zones and following the direction of the main streams, the colony maintains its energy balance using Ocean Thermal Energy Conversion – OTEC, sun energy, wave power and the methods of collection and use of high temperature waters originating from deep thermal sources.
FLOLONY is a structure made of double and triple steel layers and aluminum. Its changeable buoyancy is regulated by compensation basins that permit a float-on/float-off range of about 120ft (36.5m). This allows it to face extreme marine conditions and, in the same way, to keep its buoyancy on the surface level when there are optimum marine conditions.
The unit is divided into 19 main decks and 10 secondary (or partial) decks, for a total amount of 29 levels. In the immersed section, besides the compensation basins, there are fish farming basins, habitats for farming products, systems for the collection and treatment of precipitations, a desalination plant, storages of  potable water and fuel, emergency diesel/electric engine-generators, an electric propulsive system, a stock area for the converters of wave power, technical special areas, etc.
Accommodation units, cultural and entertaining spaces, schools, scientific and medical laboratories, pilot house areas, bridges, technical and navigation instruments, mechanical plants for air change/treatment, production workshops and laboratories, green areas, play and sport areas, etc. are situated in the changeable buoyancy section and in the emerging section.

Technical Sheet

Length: 395.33 m (1,297 ft)
Beam: 269.65 m (885 ft)
Height: 180.75 m (593 ft)
Volume: 6,107,742.00 m3
Estimated construction cost: $ 2.97 billion
Draft: 98.45 (323 ft) to 134.72 m (442 ft)
Decks: 29
Installed power:
2 diesel generators × 15,200 kW = 30.4 MW
2 diesel generators × 11,400 kW = 22.8 MW
4 strips (with 7 oscillating sensors each) x 6,700 kW = 26.8 MW
High Concentration Photovoltaics Panels x 2,600 kW  = 2.6 MW
2 OTEC Systems (Ocean Thermal Energy Conversion) x 10,500 kW = 21 MW
Total power: 103.6 MW on-board electricity supply', 'In this project simulation a realistic social model is applied to the structure: the building cost of the colony is divided into shares per person according to the number of inhabitants, as well as the costs for maintenance, services, crew, etc. Nevertheless, the structure of the colony does not exclude the implementation of more supportive social models, in which the participation to livelihood activities and services is equally distributed among the occupants, if a crew is not present, and the professional activities are carried out by the inhabitants themselves (doctors, pilots, engineers, on board and production technicians, teachers, instructors, operators, etc.)
In both cases the colony represents a complex organism and activates a system of relationships among the inhabitants that is typical of small and tightly connected groups, and it also represents an alternative to the social models characterized by collective intelligence. Both models, which are antithetical ones according to the bifurcation theory, could be the ongoing result of the IT era.',
    TRUE,
    'IFF6', 'David Raponi_HOV', NULL, NULL
);

