    'Prefeitura Municipal de Sobral; Grupo Certare.', 'Yvo Gabriel Sousa Galvão', 'yvogalvao@sobral.ce.gov.br', 'Sobral Urban Routes Plan (PRUS)',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'Sobral', 'Brazil',
    NULL, NULL,
    'The plan presents guidelines and projects to promote sustainable and safe mobility, with the objective of reducing the spread of Covid-19 and expanding the network of active and safe trips in the city of Sobral.', 'Developed with the aim of expanding the cycling network in order to connect peripheral neighborhoods to the city center, mitigating agglomerations in mass public transport, the Sobral Urban Routes Plan (PRUS) was part of the actions developed during the COVID-19 pandemic by the municipality of Sobral in order to promote safe paths, expand stretches of roads to facilitate pedestrian traffic and implement bicycle racks to support and encourage the safe movement of cyclists.', 'Aiming on consolidate actions planned by the Sobral Municipal Management with the objective of reducing the spread of the coronavirus and expanding the network of active and safe displacements in the city of Sobral, the PRUS, in addition to promoting sustainability through active mobility, encourages new, safe and healthy habits while it fosters a sense of belonging in people and gives a new meaning to the city public spaces, through their use and occupation.',
    TRUE,
    'IFF63', 'Marília Gouveia Ferreira Lima; José Otávio Santos de Almeida Braga; Úrsula Priscyla Santana Nóbrega; Bruno Ary Ferreira; Igor Fernandes Nóbrega; Raquel Pessoa Morano; Isabela Ribeiro de Castro; Germana Nunes de Oliveira Melo;', NULL, NULL
);

-- Row 127: IFF64
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'categoria impossível', 'lucas radatz', 'email@categoriaimpossivel.site', 'spatial sublimation as an alternative to fragmentary drives',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo', 'Brasil',
    NULL, NULL,
    'The urban-regional of the future lies in the understanding of the counterposition of anthropic and natural dispersion and fragmentation, based on new ways of dealing with the urban in the 21st century. An alternative experimentation merging superpositions and transversalities to the scope of planning projects and urban-architectural design.', 'According to Walter Benjamin''s reflections about the cities of modernity, the urban space makes the human psyche tangible, reverberating in its social organization, compositional structure, and mode of occupation. The urban-regional project understands as problematic the counterposition of dispersion and fragmentation, anthropic and natural, basing itself on new forms in the 21st century. In an alternative experimentation to the highly complex issues brought by such debate, this project merges superpositions and transversalities to the projects'' scope.', 'It is proposed to deal with the spatial construction crossing scales, from plan to project, in which the multiscale fragmentation of nature, the collective and individuals may result in an urban and contemporary totality and simultaneity. While the condition of heterogeneous elements no longer exists in isolation, composing spaces in which the limitations and normalities are dissolved, joining the systemic elements that configure the mosaic of the landscape.',
    TRUE,
    'IFF64', 'Lucas Radatz', NULL, NULL
);

-- Row 128: IFF8
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Arlind Dervishaj architecture & innovation workshop', 'Arlind Dervishaj', 'arlindd@kth.se', 'Grattacortina – a concept accounting for growing density in Cities',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_I', 'Turin', 'Italy',
    NULL, NULL,
    'Grattacortina is a sustainable urban regeneration model that addresses the increasing density in cities. Its organic design integrates public spaces and repurposes unused plots without demolition.', 'Grattacortina is a concept designed to address the growing density in cities, specifically in Turin, Italy. Unlike traditional high-rises that require the demolition of existing structures, this concept uses plots that would otherwise remain unused while combining real needs of cities into a new urban model that includes public spaces, and adaptable and flexible structures. It incorporates sustainable principles including daylighting strategies at the urban scale and in the design of facades.', 'It contributes to SDG 11 as a new urban model to address densification, supports SDG 12 through the reuse of empty plots instead of outward city expansion, SDG 13 through design for adaptability reduces lifecycle GHGs, SDG 3 with optimal access to daylight for all buildings, SDG 7 by integrating renewable energy sources, and SDG 8 to create new jobs and investments. Lastly, the creation of new public spaces from urban regeneration aligns with multiple SDGs including SDG 11, SDG 3, and SDG 8.',
    TRUE,
    'IFF8', 'Arlind Dervishaj', NULL, NULL
);

-- Row 129: LDP10
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'TecTo Arhitectura', 'Sergiu C. Petrea', 'office@tecto.ro', 'DSBU (Deutsche Schule Bukarest) - New School Campus',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_II', 'Bucharest', 'Romania',
    NULL, NULL,
    'A new school campus containing educational spaces for children of all ages, focused on pupils’ integration, belonging and well-being. The general concept follows principles from all aspects of sustainability and represents EU principles: democracy, equality, unity, diversity, and mutual learning.', 'As a European school, DSBU gathers pupils from many European countries in a new place where the European principles such as democracy, education, equality, learning together from each other are brought together. The buildings are placed around a central square, accessible from all directions, that connects every empty space between buildings, creating a coherent urban composition that responds to functional connectivity and aesthetic purposes. The functional layout helps children to guide themselves easily inside the school, facilitating education through art, space, light and emotion.', 'All spaces ensure healthy activity and promote well-being for all at all ages. The colorful architecture and common spaces support the indoor and outdoor activities and ensure inclusive and equitable quality education and promote lifelong learning opportunities for all. The school has many secure places of different kinds, that encourage movement and social interaction, gender equality, productive employment, and decent work for all. The project uses sustainable materials and affordable and reliable energy efficient systems in a compact shape that proves that it is possible to imagine an architectural vocabulary that is both aesthetically harmonious and capable to give valuable answers to economic and sustainable constraints (environmental, social, economic). The general architecture image establishes a significant link with nature based on a resilient infrastructure as part of an inclusive, resilient, and sustainable new part of the city. Overall, the project strives to become a manifesto for contemporary sustainable architecture, designed to meet educational, cultural, and economic needs, with emphasis on energy efficiency and responsible use of natural resources, protecting biodiversity and taking urgent action to combat climate change. The campus has been pre-certified with the grade Excellent for the Green Schools category by ROGBC - Romania Green Building Council, thus confirming the care for the environment and the commitment for a sustainable and green future.',
    TRUE,
    'LDP10', 'PhD. arch. Sergiu-Cătălin Petrea, arch. Sabrina Ene-Butnariu, arch. Cristina Mototolea, arch. Sebastian-Ștefan Apostol, arch. Dan - Alexandru Roșu, arch. Tania-Victoria Băncilă, arch. Diana-Elena Fusea, arch. Ovidiu-Ion Bălășoiu', NULL, NULL
);

-- Row 130: LDP33
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'CSCAE', 'Primitivo González', 'noa@primitivogonzalez.com', 'Art School in Valladolid',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_I', 'Valladolid. Spain', 'Unknown',
    NULL, NULL,
    'The new Art School of Valladolid, respectful of its historical context, is built as an architecture of patios, where education and creativity can meet.', 'The new Art School of Valladolid is adjacent to the convent of Las Carmelitas Descalzas. The plot used to be part of the convent''s orchards, this condition has characterised the project. Towards the city, the buildings shows itself as an architecture of walls; towards the inside, an architecture of patios. The project strives to be respectful of its historical context. However, it houses a space for creativity, youth and dreams. The essence of the project is the materialization of this duality.', 'The Art School, placed in the former orchards of the adjacent convent, shows a brick façade, respectful to the historical context. However the internal structure is designed to promote a better education, allowing teachers and students to appropriate the space. It also intends to create an environment that provokes the interaction between different disciplines and students, an to encourage them to be active part of their education.',
    TRUE,
    'LDP33', 'Primitivo, Noa and Ara González', NULL, NULL
);

-- Row 131: LDP4
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Oriental Group Architects (Hamdy EL-Setouhy)', 'Hamdy EL-Setouhy', 'INFO@OG-ARCHITECTS.COM', 'Reviving AL-Nazlah',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_V', 'Fayoum', 'Egypt',
    NULL, NULL,
    'Reviving the Al-Nazlah area in Fayoum aims to create a pilot project in contexts of specificity. The valuable district incubates pottery workshops which have been producing special pots used for construction since Ancient Egyptian Civilization. Thus, the upgraded construction technique which enhanced the bonding material gluing the pots together via the help of lab experiments maintained the traditional technique. Also, new forms have been introduced for the roofing construction, which enabled the local community to explore a wider range of spans through introducing domes & vaults constructed by pots. The project was initiated by Arch. El-Setouhy with an aim to indulge the local community in a participatory process which enables the locals to learn, appreciate, create and govern their cultural product. Thus, enabling them to achieve the three pillars of sustainability for the project, social, economic and environmental sustenance.  The project has been awarded the second prize of the Baku Award in 2019, Category A, with the support of UIA for creating a sustainable environmental development nucleus that has many positive impacts on the whole region. The project was nominated to receive the Aga-Khan Award cycle 2022. Also, shortlisted in the Arab Association Award for the last cycle 2022.', 'Concept: Develop the Nazlah area by reviving its cultural heritage and returning it to become a cultural product again that the local people can be proud of it. 
Goals:
Pilot project, give a model about improving performance and maximize benefits for areas which has different kinds of arts of their local culture over hundreds of years, that Egypt has many of it. 
Create a sustain environmental development nucleus that has many positive impacts on the whole region.
Reviving the traditional crafts that characterize the region, to protect it from extinction.
Seeking to restore the place to its former value that brought happiness to the local people, while restoring confidence in their cultural heritage.

The interlocking of the pots forms a continuous arch, which creates a load-bearing mechanism. The variations and repetition of the load-bearing elements create a variety of spaces and roof treatments. The climatic sustainability stems from the zero-waste process adopted in the construction technique. The Visitor witness a powerful environmentally friendly climatic nature in terms of adequacy of internal temperatures and also as to its coherence with the surrounding nature. The geometrical iterations in the construction of the roof, which created diffused sunlight radiations on the building added an important layer in the lower temperatures inside the buildings.  This manipulation of the roof results in less heat transfer into the internal spaces than the conventional R.C. and mud bricks construction modes. The project created a process of discovery of a heritage asset, the capitalization of the architect through a participatory methodology of a familiar practice of construction that was about to go extinct, in a contemporary mode which explores architectural aesthetical values and adventurous journeys in the spatial experiences of the Visitor center. 
Program:
-Visitor center:
Introduces the historical value of this site, which facilitates marketing issue.
Contains a number of halls. The first, displays samples and information on the various pottery products produced by the people of the region, attached to it is a hall on the tools they use in making pottery, next to a hall documenting artwork (movies and songs) that were filmed in the region.
Attached to the visitor center is a space used to sit and enjoy the beautiful scenery of the waterway.
-An exhibition for displaying and selling pottery products, consisting of three rooms attached to an open space next to the current pergola to be an extension of the products display.
-Development of workshops:
The development of new workshops that were built soon, of white limestone blocks, which are not commensurate with the nature of the place and its cultural heritage.
-Services – Landscape:
Provide a multipurpose space for different cultural and related activities.
Facilitate a secured passing way for visitors that do not interrupt that of workers.
The project is closely linked to the SDGs, and sought to achieve a set of its goals, whether in the stages of implementation or after implementation, especially the goals numbers (1-3-7-13)', 'The project is closely linked to the SDGs, and sought to achieve a set of its goals, whether in the stages of implementation or after implementation, especially the goals numbers (1-7-3-13)
Goal 01:
The Al-Nazlah area is characterized by many potentials, however, the poverty rate is very high in a way that makes us have to act responsibly, and the projects have a positive impact on this point, and this is what the project sought.
Pottery is made in the region in a way that dates back to the ancient Egyptian civilization and there is no analogue in the world, besides it is an attractive area that attracted many creators to evaluate their artworks there.
1- He relied on the local population to implement the project, which added economic value to them.
2- After the establishment of the project, many scholars and media professionals were attracted to it, which helped the people of the region market their products and added to them an appropriate financial return.
Which achieved Goal No. (1) NO POVERTY
Goal (03):
After its implementation, the project turned into a recreational area for all ages, providing a healthy life and promoting well-being for all ages. It has become a recreation area for everyone and a pride for them. Suffice it to say that it has become the main park in all holidays and a major shrine for all guests of the region. Besides, it connected the people of the region with their cultural heritage.
Which seriously sought to achieve goal number (03) GOOD HEALTH & WELL-BEING
Goal (07):
Access to clean and affordable energy starts primarily with our use of building materials themselves, as we have tended in the recent period to use materials that are not environmentally friendly and do not suit the climatic conditions.
One of the goals of the project is to draw attention to our ability to use local raw materials that are compatible with the environment, and achieve good results. The use of pottery in construction achieved a decrease in the temperature inside the buildings 10-12 degrees lower than outside, which attributed the local residents to their confidence in the local raw materials. Which helped achieve Goal No. (7) AFORDABLE & CLEAN ENERGY
Goal (13):
The project aimed to revive our cultural heritage, and to point out in an effective practical way that we have within our cultural heritage solutions to the problem of climate change, not only to protect our heritage, but also to protect our current lives and our future heritage. Which achieved effective results in the pursuit of goal (13) CLIAMTE ACTION',
    TRUE,
    'LDP4', 'Hamdy EL-Setouhy', NULL, NULL
);

-- Row 132: LDP40
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Stcuhi&Leite', 'Fabiana Stuchi', 'fabiana@stuchileite.com', 'Boulevard da Paz',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_III', 'São Paulo', 'Brazil',
    NULL, NULL,
    'Integrated plan to implement social housing, urban infrastructure and environmental qualification, with 3 housing complexes for 750 families removed from a risk area, public parks and other services.', 'In the outskirts of São Paulo, Boulevard da Paz has a recurrent issue in the Brazilian context: precarious settlements on the verge of landslides. The public authorities’ removed families that will be welcomed in 3 housing complexes under construction, with 750 units. The project is a direct consequence of the site’s environmental and social characteristics, delimited by the channeled stream and the slope embankments, which requires a building design that is verticalized, linear and articulated.', 'The families at Boulevard da Paz are living in extreme poverty, affected by all sorts of vulnerability. The building complexes will offer proper homes, small retail spaces and public services of health care and professional qualification. Between a water course and a slope, the siting results from a land scarcity and the housing demand. Its impact addresses environmental improvement in a dam zone and disaster risk prevention: avoids precarious settlements, offers sewer networks and public parks.',
    TRUE,
    'LDP40', 'Fabiana Stuchi, Danilo Bocchini, Fernanda Moreira, Thayse Portugal, Fabiana Granusso, Guilherme Seror, João Pedro Manccini, Elisabete França, Maria Teresa Fedeli, Raphaela Rodrigues, Carlos Leite', NULL, NULL
);

-- Row 133: LDP42
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Architectural Society of China', 'Wei ZHANG', 'zw1998@vip.163.com', 'Yuanbo Building',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Zhuhai', 'China',
    NULL, NULL,
    'Yuanbo Building is the teaching building for School of Design in Zhuhai Campus of Beijing Normal University. It is a renovation project. The design encourages communication and experiencing nature.', 'Yuanbo Building is attempting to bring design education back to humanity and nature. The building has been transformed into the most popular and dynamic space on the campus. Different design teaching activities such as exhibitions, performances, and even fashion shows were set in motion. A newly built continuous loop of stairs and corridors connects the roofs, courtyards and indoor spaces tightly together, creating opportunities for exchanging ideas and engendering social interactions.', 'In the era of virtual reality, the project attempts to bring design education back to humanity and nature. The continuous roof loop offers spaces for feeling nature and exchanging ideas. The atrium with big stairs is the exhibition and show space for students. The square courtyard with the original tree can be used as outdoor exhibition space. The round courtyard offers a stage with lights where students can hold small concerts. Students find inspiration from the building in the design studios.',
    TRUE,
    'LDP42', 'Architect In Charge: Wei ZHANG, Jingxian ZHAO Design Team: Haiyang HUANG, Xiangyi LI, Yue WANG, Xiaoqian ZHANG, Mingcheng CAI, Sisi LIANG, Yuben ZHANG, Ruoxing LI, Shiqi LI', NULL, NULL
);

-- Row 134: LDP46
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Chocarro y Urmeneta S.L.P. / Arquitectos', 'Patxi Chocarro', 'arquitectos@chyurm.com', 'REUSED BOTTLE CHRISTMAS TREE',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_I', 'Pamplona', 'Spain',
    NULL, NULL,
    'Simple, austere, contemporary, reusable and low energy consumption were the premises for the Christmas tree promoted by the “Mancomunidad de la Comarca de Pamplona”. (Pamplona’s Common Region is an entity which manages urban waste collection and recycling thereof, among other competences, for 355.000 inhabitants)

Due to Christmas celebrations and with the aim of sensitizing the citizens about recycling, a tree with reused and reusable glass bottles was projected and has been installed continuously since 2012. The structure of the tree consists of a cone-shape steel structure. This cone has four quadrants, screwed to each other. This fact allows a comfortable assembly and dismantling of the structure, as well as its transportation and storage. This means that the reusability of the structure and of the bottles is guaranteed throughout the years.', 'Simple, austere, contemporary, reusable and low energy consumption were the premises for the Christmas tree promoted by the “Mancomunidad de la Comarca de Pamplona”. (Pamplona’s Common Region is an entity which manages urban waste collection and recycling thereof, among other competences, for 355.000 inhabitants)

Due to Christmas celebrations and with the aim of sensitizing the citizens about recycling, a tree with reused and reusable glass bottles was projected and has been installed continuously since 2012. The structure of the tree consists of a cone-shape steel structure. This cone has four quadrants, screwed to each other. This fact allows a comfortable assembly and dismantling of the structure, as well as its transportation and storage. This means that the reusability of the structure and of the bottles is guaranteed throughout the years.

A 3.300 kg counterweight has been projected to support wind’s push and suction which can also be dismantled.

The tree is 6m high and has 4,80m diameter on the base.
Since 2012 it has been located in “Baluarte’s Auditorium” Square during Christmastime.

The number of the bottles used is of 2.328. The 90% of them are green glass, and the 10% transparent glass.

The illumination has been carried out by Waterproof LED luminaire.

The lights are arranged radially into three circular rings in parallel planes to the base. The light is projected towards the cone’s vertex illuminating the bottles.

An explanatory panel was located next to the tree with a message about the responsible attitude of the citizens in terms of recycling. The 2.328 bottles involved the glass recovery of 13 families of Pamplona’s region along a year.', 'Since 2012, without interruption, the reused bottle tree has been installed during the Christmas period. The public entity organizes educational activities with children to raise awareness about the reuse of glass bottles. It is a reference event in the city of Pamplona.

The tree was awarded in 2013 at the awards organized by the Basque-Navarre Official College of Architects and won first prize at the WAN AWARDS 12, LIGHTING INSTALLATION OF THE YEAR.',
    TRUE,
    'LDP46', 'Patxi Chocarro and María Urmeneta', NULL, NULL
);

-- Row 135: LDP5
INSERT INTO projects (
    organization_name, contact_person, contact_email, project_name,
    project_status, workflow_status,
    funding_needed, funding_spent,
    uia_region, city, country,
    latitude, longitude,
    brief_description, detailed_description, success_factors,
    gdpr_consent,
    external_code, authors, size_sqm, year_completed
) VALUES (
    'Zuby Design Collective', 'Zohaib Zuby', 'zohaib.zuby@ivs.edu.pk', 'Wallah''s House',
    'IMPLEMENTED', 'SUBMITTED',
    0.0, 0.0,
    'SECTION_IV', 'Karachi', 'Pakistan',
    NULL, NULL,
    'Wallah’s House is an experiment in Affordable Housing in an urban slum in Karachi. The project was co-financed (home-owners and donors), and co-designed (home-owners, contracting team), while sourcing technical design expertise on a pro-bono basis.', 'Wallah’s House is a precedent for Affordable Housing in the Urban Slum context. Financing was through Zakat donations, which prove to be a sustainable source for financing construction. Reinforced Cement Concrete is employed offering labour ease and cost efficiency, while giving structural integrity and sense of dignity for homeowners in slums. Vernacular elements (courtyards & screens) were employed offering culturally appropriate user-experience and passive cooling. The family had an empowered role in the entire layout of spaces, making it a thoroughly participatory design process.', 'Wallah’s project worked with SDG 11.1 “Affordable Housing”. The project was co-financed (homeowners and donors), and co-designed (home-owners, contracting team). The construction makes use of local materials, technology and skill. The project is sensitive to its wider cultural ethos and immediate context, in terms of architectural devices and aesthetic. It works on a small footprint, with ample semi-open flexible spaces. The project is also an incremental housing project, where the metaphor of making “half a good house” has been achieved, and additional levels can be made in the future.',
    TRUE,
    'LDP5', 'Zohaib Zuby', NULL, NULL
);

